function _syncThemePicker() {
  const current = localStorage.getItem('icu_theme') || 'dark';
  _buildThemeCarousel();
  _buildMapThemeCarousel();
  document.querySelectorAll('#appThemePicker .theme-card').forEach(c =>
    c.classList.toggle('active', c.dataset.themeVal === current)
  );
  const mapCurrent = localStorage.getItem('icu_map_theme') || 'liberty';
  document.querySelectorAll('#mapThemePicker .theme-card').forEach(c =>
    c.classList.toggle('active', c.dataset.theme === mapCurrent)
  );
}

// Lazy subpage cache — DocumentFragment approach
// Moves DOM nodes to a fragment (preserves event listeners, dropdown state, scrubber positions)
// Restore is instant — no HTML parsing, just move nodes back
const _subpageCache = {};
let _subpageCacheReady = false;

function _initSubpageCache() {
  if (_subpageCacheReady) return;
  let count = 0;
  document.querySelectorAll('.ios-subpage').forEach(sub => {
    const key = sub.id.replace('iosSubpage-', '');
    if (sub.childNodes.length) {
      const frag = document.createDocumentFragment();
      while (sub.firstChild) frag.appendChild(sub.firstChild);
      _subpageCache[key] = frag;
      count++;
    }
  });
  _subpageCacheReady = true;
  console.info('Lazy subpages: cached ' + count + ' subpages (DocumentFragment)');
}

// Restore subpage content from fragment cache (instant, no HTML parse)
function _restoreSubpage(id) {
  const sub = document.getElementById('iosSubpage-' + id);
  if (!sub) return;
  if (!sub.childNodes.length && _subpageCache[id]) {
    sub.appendChild(_subpageCache[id]);
    // Fragment is now empty (nodes moved to sub) — recreate for next strip
    _subpageCache[id] = null;
  }
}

// Strip subpage content back to fragment cache
function _stripSubpage(id) {
  const sub = document.getElementById('iosSubpage-' + id);
  if (!sub || !sub.childNodes.length) return;
  const frag = document.createDocumentFragment();
  while (sub.firstChild) frag.appendChild(sub.firstChild);
  _subpageCache[id] = frag;
}

function _isDesktopSettings() { return window.innerWidth >= 900; }

function openSettingsSubpage(id) {
  if (_iosNavLocked) return;
  const main = document.getElementById('iosSettingsMain');
  const sub  = document.getElementById('iosSubpage-' + id);
  if (!main || !sub) return;

  // Restore subpage content from cache
  _restoreSubpage(id);
  _iosNavLocked = true;
  setTimeout(() => { _iosNavLocked = false; }, _isDesktopSettings() ? 50 : 400);

  // Push current subpage onto stack so back returns here
  if (_iosActiveSubpage) {
    _iosSubpageStack.push(_iosActiveSubpage);
  }
  _iosActiveSubpage = id;
  const headline = document.querySelector('.page-headline');

  // Highlight the source row we're navigating from
  const evt = window.event;
  const row = evt?.target?.closest?.('.ios-row, .ios-profile-card');
  _iosSourceRow = row;

  const isDesktop = _isDesktopSettings();

  // Desktop: persistent active row highlight
  if (isDesktop) {
    main.querySelectorAll('.stt-active-row').forEach(r => r.classList.remove('stt-active-row'));
    if (row) row.classList.add('stt-active-row');
  } else if (row) {
    row.style.transition = 'background 0.3s ease';
    row.style.background = 'var(--accent-dim)';
  }

  // Close any other active subpage instantly and strip its DOM
  document.querySelectorAll('.ios-subpage.active').forEach(s => {
    s.classList.remove('active');
    s.style.display = 'none';
    const prevId = s.id.replace('iosSubpage-', '');
    if (prevId !== id) _stripSubpage(prevId);
  });

  // Desktop: don't hide main list, no slide animation
  if (!isDesktop) {
    main.classList.add('ios-nav-out');
    if (headline) headline.classList.add('ios-nav-out');
  }

  // Prepare subpage: show it (desktop: instantly, mobile: slide in)
  sub.style.display = 'block';
  if (!isDesktop) sub.offsetHeight; // force reflow for mobile animation
  sub.classList.add('active');

  // Render dynamic subpage content
  if (id === 'navigation' && typeof renderNavSettings === 'function') renderNavSettings();
  if (id === 'accentcolor') setTimeout(() => openAccentColorPicker(), 350);
  if (id === 'sync') {
    // Restore P2P toggle state
    const p2pOn = localStorage.getItem('icu_p2p_enabled') === 'true';
    const p2pCb = document.getElementById('syncP2pToggle');
    if (p2pCb) p2pCb.checked = p2pOn;
    const content = document.getElementById('syncP2pContent');
    if (content) content.style.display = p2pOn ? '' : 'none';
    _peerRenderDevices((_peerConn && _peerConn.open) ? _peerRemoteName : null);
    // Restore sync category toggles
    const toggles = _syncGetToggles();
    document.querySelectorAll('#iosSubpage-sync [data-sync-key]').forEach(cb => {
      cb.checked = toggles[cb.dataset.syncKey] !== false;
    });
  }
  if (id === 'apptheme' || id === 'maptheme') { _syncThemePicker(); _syncSquircleToggle(); if (window._syncCardStyleControls) window._syncCardStyleControls(); }
  if (id === 'notifications') {
    // Sync toggle states from localStorage
    const g = document.getElementById('notifGearToggle');
    const t = document.getElementById('notifTrainingToggle');
    const s = document.getElementById('notifStreaksToggle');
    const gl = document.getElementById('notifGoalsToggle');
    if (g) g.checked = localStorage.getItem('icu_notif_gear') !== 'false';
    if (t) t.checked = localStorage.getItem('icu_notif_training') !== 'false';
    if (s) s.checked = localStorage.getItem('icu_notif_streaks') !== 'false';
    if (gl) gl.checked = localStorage.getItem('icu_notif_goals') !== 'false';
    const p = document.getElementById('notifPushToggle');
    if (p) p.checked = localStorage.getItem('icu_notif_push') === 'true';
  }

  // Inject hero intro if not already present
  if (!sub.querySelector('.stt-hero') && _STT_HERO_DATA[id]) {
    const h = _STT_HERO_DATA[id];
    const hero = document.createElement('div');
    hero.className = 'stt-hero';
    const title = _iosSubpageNames[id] || id;
    hero.innerHTML = `<div class="stt-hero-icon" style="background:${h.bg}">${h.icon}</div><div class="stt-hero-title">${title}</div><div class="stt-hero-desc">${h.desc}</div>`;
    sub.insertBefore(hero, sub.firstChild);
  }

  // Hide main after transition (mobile only — desktop keeps both visible)
  if (!isDesktop) setTimeout(() => { main.style.display = 'none'; }, 380);

  // Update page headline to subpage name after slide-out starts
  if (!isDesktop) {
    setTimeout(() => {
      const title = document.getElementById('pageTitle');
      const subtitle = document.getElementById('pageSubtitle');
      const hasHero = !!_STT_HERO_DATA[id];
      if (title) title.textContent = hasHero ? '' : (_iosSubpageNames[id] || id);
      if (subtitle) subtitle.textContent = '';
      const _st = document.getElementById('stickyPageTitleText');
      if (_st) _st.textContent = hasHero ? '' : (_iosSubpageNames[id] || id);
      const backBtn = document.getElementById('settingsBackBtn');
      if (backBtn) backBtn.style.display = '';
      if (headline) {
        headline.classList.add('page-headline--subpage');
        headline.classList.remove('ios-nav-out');
        headline.classList.add('ios-nav-in');
        headline.offsetHeight;
        headline.classList.remove('ios-nav-in');
        if (hasHero) headline.style.display = 'none';
      }
    }, 180);
    _iosSettingsScrollY = window.scrollY;
    window.scrollTo(0, 0);
  }

  // Subpage-specific init
  if (id === 'leveling') {
    const dateInput = document.getElementById('xpStartDate');
    if (dateInput) dateInput.value = localStorage.getItem('icu_xp_start_date') || '';
  }
}

function closeSettingsSubpage() {
  if (_iosNavLocked) return;
  const main = document.getElementById('iosSettingsMain');
  if (!main) return;
  const isDesktop = _isDesktopSettings();
  _iosNavLocked = true;
  setTimeout(() => { _iosNavLocked = false; }, isDesktop ? 50 : 400);

  // Desktop: clear active row highlight
  if (isDesktop) {
    main.querySelectorAll('.stt-active-row').forEach(r => r.classList.remove('stt-active-row'));
  }
  const activeSub = document.querySelector('.ios-subpage.active, .ios-subpage.ios-nav-back');
  const headline = document.querySelector('.page-headline');

  // Also find subpage by _iosActiveSubpage if class-based query missed it
  const sub = activeSub || (_iosActiveSubpage ? document.getElementById('iosSubpage-' + _iosActiveSubpage) : null);

  // Slide headline out to the right with subpage
  if (headline) headline.classList.add('ios-nav-out-right');

  // Slide subpage out to the right, then strip DOM
  const closingId = _iosActiveSubpage;
  if (sub) {
    sub.style.display = 'block';
    sub.classList.remove('active');
    sub.classList.add('ios-nav-back');
    setTimeout(() => {
      sub.classList.remove('ios-nav-back');
      sub.style.display = 'none';
      // Strip subpage DOM to save nodes
      if (closingId) _stripSubpage(closingId);
    }, 380);
  }

  // Show main: clear inline display, remove transition class, force reflow
  main.style.display = '';
  main.classList.remove('ios-nav-out');
  main.offsetHeight; // force reflow so browser sees the state change

  // Update headline mid-transition, then slide it back in from the left
  setTimeout(() => {
    const title = document.getElementById('pageTitle');
    const subtitle = document.getElementById('pageSubtitle');
    if (title) title.textContent = 'Settings';
    if (subtitle) subtitle.textContent = 'Account & connection';
    const _st2 = document.getElementById('stickyPageTitleText');
    if (_st2) _st2.textContent = 'Settings';
    const backBtn = document.getElementById('settingsBackBtn');
    if (backBtn) backBtn.style.display = 'none';
    if (headline) {
      headline.style.display = '';
      headline.classList.remove('page-headline--subpage', 'ios-nav-out-right');
      headline.classList.add('ios-nav-in-left');
      headline.offsetHeight;
      headline.classList.remove('ios-nav-in-left');
    }
  }, 180);

  _iosActiveSubpage = null;
  _iosSubpageStack = [];
  window.scrollTo({ top: _iosSettingsScrollY, behavior: 'instant' });

  // Fade out ALL source row highlights (covers deep navigation)
  setTimeout(() => {
    document.querySelectorAll('.ios-row, .ios-profile-card').forEach(r => {
      if (r.style.background) {
        r.style.transition = 'background 0.45s ease';
        r.style.background = '';
      }
    });
  }, 300);
  _iosSourceRow = null;
}

function setHrZoneSource(val) {
  try { localStorage.setItem('icu_hr_zone_source', val); } catch {}
  document.querySelectorAll('#hrZoneSourcePills .theme-toggle-btn').forEach(b => b.classList.toggle('active', b.dataset.val === val));
  const slider = document.querySelector('#hrZoneSourcePills .theme-toggle-slider');
  if (slider) slider.style.transform = val === 'manual' ? 'translateX(100%)' : '';
  document.getElementById('hrZoneSourcePills')?.setAttribute('data-active', val);
}
function setPwrZoneSource(val) {
  try { localStorage.setItem('icu_pwr_zone_source', val); } catch {}
  document.querySelectorAll('#pwrZoneSourcePills .theme-toggle-btn').forEach(b => b.classList.toggle('active', b.dataset.val === val));
  const slider = document.querySelector('#pwrZoneSourcePills .theme-toggle-slider');
  if (slider) slider.style.transform = val === 'custom' ? 'translateX(100%)' : '';
  document.getElementById('pwrZoneSourcePills')?.setAttribute('data-active', val);
}
function setTssModel(val) {
  try { localStorage.setItem('icu_tss_model', val); } catch {}
  document.querySelectorAll('#tssModelPills .theme-toggle-btn').forEach(b => b.classList.toggle('active', b.dataset.val === val));
  const slider = document.querySelector('#tssModelPills .theme-toggle-slider');
  if (slider) slider.style.transform = val === 'hr' ? 'translateX(100%)' : '';
  document.getElementById('tssModelPills')?.setAttribute('data-active', val);
}


function settingsBack() {
  if (_iosNavLocked) return;
  if (_iosActiveSubpage && _iosSubpageStack.length > 0) {
    // Go back to parent subpage
    const parent = _iosSubpageStack.pop();
    _iosActiveSubpage = null;
    // Clear any lingering source row highlight
    if (_iosSourceRow) {
      _iosSourceRow.style.transition = 'background 0.45s ease';
      _iosSourceRow.style.background = '';
      _iosSourceRow = null;
    }
    // Close current subpage
    document.querySelectorAll('.ios-subpage.active').forEach(s => {
      s.classList.remove('active');
      s.style.display = 'none';
    });
    // Open parent subpage (suppress highlight by temporarily blocking event)
    const savedEvent = window.event;
    openSettingsSubpage(parent);
    _iosSourceRow = null; // don't highlight on back navigation
  } else if (_iosActiveSubpage) {
    closeSettingsSubpage();
  } else {
    navigate(state.previousPage || 'dashboard');
  }
}

function saveLogodevKey() {
  const input = document.getElementById('logodevKeyMain') || document.getElementById('logodevKeyInput');
  const key = input?.value.trim();
  if (key) { localStorage.setItem('icu_logodev_key', key); showToast('Logo.dev key saved', 'success'); }
  else { localStorage.removeItem('icu_logodev_key'); showToast('Logo.dev key removed', 'info'); }
  _updateLogodevStatus();
}
function _updateLogodevStatus() {
  const el = document.getElementById('logodevKeyStatus');
  if (el) {
    const hasKey = !!localStorage.getItem('icu_logodev_key');
    el.textContent = hasKey ? 'Connected' : 'Not set';
    el.style.color = hasKey ? 'var(--accent)' : 'var(--text-muted)';
  }
}

function iosSettingsInit() {
  // Close any open subpage when entering settings
  closeSettingsSubpage();

  // Profile card
  const connected = !!(state.athleteId && state.apiKey);
  const profileName = document.getElementById('iosProfileName');
  const profileSub  = document.getElementById('iosProfileSub');
  const profileAv   = document.getElementById('iosProfileAvatar');
  if (connected && state.athlete) {
    const a = state.athlete;
    const aName = a.name || a.firstname || 'Athlete';
    if (profileName) profileName.textContent = aName;
    if (profileSub)  profileSub.textContent = 'Profile, Photo & Account';
    if (profileAv) {
      const customAvatar = localStorage.getItem('icu_avatar');
      const src = customAvatar || _getIntervalsAvatarUrl();
      if (src) profileAv.innerHTML = `<img src="${src}" alt="" style="width:100%;height:100%;object-fit:cover;border-radius:50%">`;
      else profileAv.textContent = aName[0].toUpperCase();
    }
  } else {
    if (profileName) profileName.textContent = 'Not Connected';
    if (profileSub)  profileSub.textContent = 'Tap to set up your account';
    if (profileAv)   profileAv.textContent = '?';
  }

  // Connection badges
  const icuBadge    = document.getElementById('iosIcuBadge');
  const icuBadgeOff = document.getElementById('iosIcuBadgeOff');
  if (icuBadge && icuBadgeOff) {
    icuBadge.style.display    = connected ? '' : 'none';
    icuBadgeOff.style.display = connected ? 'none' : '';
  }
  const stravaConnected = !!localStorage.getItem('strava_access_token');
  const stBadge    = document.getElementById('iosStravaBadge');
  const stBadgeOff = document.getElementById('iosStravaBadgeOff');
  if (stBadge && stBadgeOff) {
    stBadge.style.display    = stravaConnected ? '' : 'none';
    stBadgeOff.style.display = stravaConnected ? 'none' : '';
  }

  // Inline values
  const fontEl = document.getElementById('iosCurrentFont');
  if (fontEl) {
    const fontMap = { 'inter': 'Inter', 'dm-sans': 'DM Sans', 'outfit': 'Outfit', 'space-grotesk': 'Space Grotesk' };
    fontEl.textContent = fontMap[localStorage.getItem('icu_font') || 'inter'] || 'Inter';
  }
  const mapEl = document.getElementById('iosCurrentMapTheme');
  if (mapEl) {
    const themeMap = { 'liberty': 'Liberty', 'positron': 'Positron', 'dark': 'Dark', 'strava': 'Strava' };
    mapEl.textContent = themeMap[localStorage.getItem('icu_map_theme') || 'dark'] || 'Dark';
  }
  const wxEl = document.getElementById('iosWeatherCount');
  if (wxEl) {
    try {
      const locs = JSON.parse(localStorage.getItem('icu_wx_locations') || '[]');
      wxEl.textContent = locs.length ? String(locs.length) : 'None';
    } catch { wxEl.textContent = 'None'; }
  }
  // Default range value
  const defRangeEl = document.getElementById('iosDefRangeVal');
  if (defRangeEl) defRangeEl.textContent = (state.rangeDays || 30) + ' days';
  // Sync checkmarks
  document.querySelectorAll('.ios-row--check[data-defrange]').forEach(r =>
    r.classList.toggle('active', parseInt(r.dataset.defrange) === (state.rangeDays || 30))
  );
  // Training toggles
  setHrZoneSource(localStorage.getItem('icu_hr_zone_source') || 'auto');
  setPwrZoneSource(localStorage.getItem('icu_pwr_zone_source') || 'auto');
  setTssModel(localStorage.getItem('icu_tss_model') || 'power');
  // Theme label
  const themeEl = document.getElementById('iosCurrentTheme');
  if (themeEl) {
    const labels = { dark: 'Dark', light: 'Light', tdf: 'Tour de France', auto: 'Auto' };
    themeEl.textContent = labels[localStorage.getItem('icu_theme') || 'dark'] || 'Dark';
  }
  // 3D card quality select
  const q3dSel = document.getElementById('quality3dSelect');
  if (q3dSel) q3dSel.value = localStorage.getItem('icu_3d_quality') || 'auto';
}

/* ====================================================
   CONNECTION UI
==================================================== */
function updateConnectionUI(connected) {
  const dot   = document.getElementById('connectionDot');
  const name  = document.getElementById('athleteName');
  const sub   = document.getElementById('athleteSub');
  const av    = document.getElementById('athleteAvatar');

  if (connected && state.athlete) {
    const a = state.athlete;
    const aName = a.name || a.firstname || 'Athlete';
    dot.className    = 'connection-dot connected';
    name.textContent = aName;
    sub.textContent  = a.city || 'intervals.icu';
    av.textContent   = aName[0].toUpperCase();
    // Custom avatar takes priority, then intervals.icu profile pic
    const customAvatar = localStorage.getItem('icu_avatar');
    applyAvatar(customAvatar || _getIntervalsAvatarUrl());
    // Update settings profile card name
    const sttName = document.getElementById('settingsAthleteName');
    if (sttName) sttName.textContent = aName;
    // iOS settings profile card
    const iosName = document.getElementById('iosProfileName');
    if (iosName) iosName.textContent = aName;
    // Sidebar level badge
    const lvlBadge = document.getElementById('sidebarLvlBadge');
    if (lvlBadge && state.activities?.length) {
      const lvlInfo = getLevel(getTotalXP());
      const lvl = lvlInfo?.level || '';
      lvlBadge.textContent = lvl || '';
      lvlBadge.style.display = lvl ? '' : 'none';
    }
  } else {
    dot.className   = 'connection-dot disconnected';
    name.textContent = 'Not connected';
    sub.textContent  = 'Click to connect';
    av.textContent   = '?';
    const iosName = document.getElementById('iosProfileName');
    if (iosName) iosName.textContent = 'Not Connected';
  }

  // Update floating profile level badge
  const floatingLvl = document.getElementById('floatingProfileLvl');
  if (floatingLvl && state.activities?.length) {
    const lvlInfo = getLevel(getTotalXP());
    floatingLvl.textContent = lvlInfo.level;
  }

  // Update Import → ICU tab if panel exists
  icuRenderSyncUI();

  // Notification toggles
  const _nt = (id, key) => { const el = document.getElementById(id); if (el) el.checked = _notifSetting(key); };
  _nt('notifPushToggle', 'push');
  _nt('notifGearToggle', 'gear');
  _nt('notifTrainingToggle', 'training');
  _nt('notifStreaksToggle', 'streaks');
  _nt('notifGoalsToggle', 'goals');

  // Logo.dev key (both inputs — subpage + main)
  const lk = localStorage.getItem('icu_logodev_key') || '';
  const logodevInput = document.getElementById('logodevKeyInput');
  if (logodevInput) logodevInput.value = lk;
  const logodevMain = document.getElementById('logodevKeyMain');
  if (logodevMain) logodevMain.value = lk;
  _updateLogodevStatus();
}

function updateLifetimeCacheUI() {
  const countEl = document.getElementById('icuLifetimeCount');
  const sizeEl  = document.getElementById('icuLifetimeSize');
  const syncEl  = document.getElementById('icuLifetimeSync');
  const acts    = state.lifetimeActivities;

  const stravaOnly = acts ? acts.filter(a => a.source === 'STRAVA' && a._note).length : 0;
  const available  = acts ? acts.length - stravaOnly : 0;
  if (countEl) countEl.textContent = acts ? available.toLocaleString() + ' activities' : '—';
  const stravaRow = document.getElementById('icuStravaOnlyRow');
  const stravaEl  = document.getElementById('icuStravaOnlyCount');
  if (stravaRow && stravaEl) {
    if (stravaOnly > 0) {
      stravaRow.style.display = '';
      stravaEl.innerHTML = `${stravaOnly} <span style="font-size:.75rem;color:var(--text-muted)">(not available via API)</span>`;
    } else {
      stravaRow.style.display = 'none';
    }
  }
  if (sizeEl)  sizeEl.textContent  = (() => {
    const bytes = getLifetimeCacheSize();
    if (!bytes) return '—';
    return bytes > 1048576 ? (bytes / 1048576).toFixed(1) + ' MB' : (bytes / 1024).toFixed(0) + ' KB';
  })();
  if (syncEl) {
    const ls = localStorage.getItem('icu_lifetime_sync');
    if (ls) {
      const diff = Math.round((Date.now() - new Date(ls).getTime()) / 60000);
      syncEl.textContent = diff < 1 ? 'Just now'
        : diff < 60 ? `${diff} min ago`
        : diff < 1440 ? `${Math.round(diff / 60)} hr ago`
        : new Date(ls).toLocaleDateString();
    } else {
      syncEl.textContent = 'Never';
    }
  }
}

function clearAllCaches() {
  showConfirmDialog(
    'Clear All Caches',
    'This will remove all cached data including activities, fitness, and heat map routes. The app will need to re-download everything.',
    () => {
      clearActivityCache();
      clearFitnessCache();
      clearLifetimeCache();
      for (let i = localStorage.length - 1; i >= 0; i--) {
        const key = localStorage.key(i);
        if (key && key.startsWith('icu_gps_pts_')) localStorage.removeItem(key);
      }
      _hmClearCache();
      // Clear offline activity IDB cache
      try { _actCacheDB().then(db => { const tx = db.transaction('items', 'readwrite'); tx.objectStore('items').clear(); }); } catch (_) {}
      _hm.allRoutes = [];
      _hm.loaded = false;
      state.lifetimeActivities = null;
      state._lifetimeSyncDone  = false;
      updateStorageBar();
      showToast('All caches cleared', 'success');
      if (state.currentPage === 'settings') navigate('settings');
    }
  );
}

function resyncLifetimeData() {
  showConfirmDialog(
    'Re-sync Lifetime Data',
    'This will clear your cached lifetime data and re-download all activities from Intervals.icu. This may take a moment.',
    () => {
      clearLifetimeCache();
      state.lifetimeActivities = null;
      state.lifetimeLastSync   = null;
      state._lifetimeSyncDone  = false;
      showToast('Syncing lifetime data…', 'success');
      runLifetimeSync();
    }
  );
}

function runLifetimeSync() {
  if (state._lifetimeSyncDone) return;
  state._lifetimeSyncDone = true;
  (async () => {
    try {
      const pageSize = 200;
      const seen = new Set();
      const all = [];
      const existing = state.lifetimeActivities || [];
      const lastSync = state.lifetimeLastSync;

      const hardOldest = lastSync ? toDateStr(new Date(lastSync.getTime() - 7 * 86400000)) : '2010-01-01';
      let ceiling = toDateStr(new Date());

      for (let guard = 0; guard < 60; guard++) {
        if (guard > 0) await new Promise(r => setTimeout(r, 300));

        let data;
        for (let retry = 0; retry < 3; retry++) {
          try {
            data = await icuFetch(
              `/athlete/${state.athleteId}/activities?oldest=${hardOldest}&newest=${ceiling}&limit=${pageSize}`
            );
            break;
          } catch (fetchErr) {
            const status = parseInt(fetchErr.message);
            if (status === 429 || status === 503) {
              await new Promise(r => setTimeout(r, (retry + 1) * 2000));
            } else {
              throw fetchErr;
            }
          }
        }
        if (!data) throw new Error('API rate limit — try again in a minute');

        const chunk = Array.isArray(data) ? data : (data.activities || []);
        if (!chunk.length) break;
        let added = 0;
        for (const a of chunk) {
          if (!seen.has(a.id)) { seen.add(a.id); all.push(a); added++; }
        }
        if (added === 0 || chunk.length < pageSize) break;
        const dates = chunk.map(a => a.start_date_local || a.start_date).filter(Boolean).sort();
        if (!dates.length) break;
        const oldest = dates[0].slice(0, 10);
        if (oldest <= hardOldest) break;
        ceiling = oldest;
      }

      if (lastSync && existing.length) {
        const freshIds = new Set(all.map(a => a.id));
        const kept = existing.filter(a => !freshIds.has(a.id));
        state.lifetimeActivities = [...kept, ...all].sort(
          (a, b) => new Date(b.start_date_local || b.start_date) - new Date(a.start_date_local || a.start_date)
        );
      } else {
        state.lifetimeActivities = all.sort(
          (a, b) => new Date(b.start_date_local || b.start_date) - new Date(a.start_date_local || a.start_date)
        );
      }

      state.lifetimeLastSync = new Date();
      saveLifetimeCache(state.lifetimeActivities);
      updateLifetimeCacheUI();
      showToast(`Synced ${state.lifetimeActivities.length} lifetime activities`, 'success');

      if (state.currentPage === 'goals') { renderStreaksPage(); renderGoalsPage(); _rIC(() => { if (window.refreshGlow) refreshGlow(); if (window.refreshBadgeTilt) refreshBadgeTilt(); }); }
      if (state.currentPage === 'activities') renderAllActivitiesList();
      if (state.currentPage === 'settings') navigate('settings');
    } catch (e) {
      console.error('Lifetime sync failed:', e);
      showToast('Lifetime sync failed: ' + (e.message || 'unknown error'), 'error');
      if (!state.lifetimeActivities) state.lifetimeActivities = state.activities || [];
      if (state.currentPage === 'goals') { renderStreaksPage(); renderGoalsPage(); _rIC(() => { if (window.refreshGlow) refreshGlow(); if (window.refreshBadgeTilt) refreshBadgeTilt(); }); }
    }
  })();
}

function exportLifetimeJSON() {
  const acts = state.lifetimeActivities;
  if (!acts || !acts.length) { showToast('No lifetime data to export', 'error'); return; }
  const blob = new Blob([JSON.stringify(acts, null, 2)], { type: 'application/json' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href     = url;
  a.download = `cycleiq-activities-${new Date().toISOString().slice(0, 10)}.json`;
  a.click();
  URL.revokeObjectURL(url);
  showToast(`Exported ${acts.length} activities`, 'success');
}

function importLifetimeJSON() {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = '.json';
  input.onchange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const acts = JSON.parse(ev.target.result);
        if (!Array.isArray(acts) || !acts.length) {
          showToast('Invalid file — expected a JSON array of activities', 'error');
          return;
        }
        // Merge with existing: imported data fills gaps, existing data takes priority
        const map = new Map();
        acts.forEach(a => { const id = a.id || a.icu_id; if (id) map.set(id, a); });
        (state.lifetimeActivities || []).forEach(a => { const id = a.id || a.icu_id; if (id) map.set(id, a); });
        state.lifetimeActivities = Array.from(map.values()).sort(
          (a, b) => new Date(b.start_date_local || b.start_date) - new Date(a.start_date_local || a.start_date)
        );
        state.lifetimeLastSync = new Date();
        saveLifetimeCache(state.lifetimeActivities);
        updateLifetimeCacheUI();
        updateStorageBar();
        showToast(`Imported — ${state.lifetimeActivities.length} activities total`, 'success');
        if (state.currentPage === 'activities') renderAllActivitiesList();
      } catch (err) {
        showToast('Failed to parse JSON file', 'error');
      }
    };
    reader.readAsText(file);
  };
  input.click();
}

/* ── Full Backup helpers (IDB read/write) ── */
async function _idbReadAll(openFn, storeName) {
  try {
    const db = await openFn();
    const tx = db.transaction(storeName, 'readonly');
    const store = tx.objectStore(storeName);
    return await new Promise(res => {
      const entries = [];
      const req = store.openCursor();
      req.onsuccess = e => {
        const c = e.target.result;
        if (c) { entries.push({ k: c.key, v: c.value }); c.continue(); }
        else res(entries);
      };
      req.onerror = () => res([]);
    });
  } catch (_) { return []; }
}
async function _idbWriteAll(openFn, storeName, entries, outOfLineKeys) {
  try {
    const db = await openFn();
    const tx = db.transaction(storeName, 'readwrite');
    const store = tx.objectStore(storeName);
    store.clear();
    for (const e of entries) {
      if (outOfLineKeys) store.put(e.v, e.k);
      else store.put(e.v);
    }
    await new Promise(r => { tx.oncomplete = r; tx.onerror = r; });
  } catch (_) {}
}

/* ══════════════════════════════════════════════════════════════════════════════
   PEERJS P2P DEVICE SYNC
   ══════════════════════════════════════════════════════════════════════════════ */

let _peerInstance = null;
let _peerConn = null;
let _peerMyId = '';
let _peerRemoteId = '';
let _peerReconnecting = false;
let _peerManualDisconnect = false;
let _peerAutoStarting = false;
let _peerReconnectTimer = null;
let _peerRemoteName = '';
let _peerDiscoverTimer = null;
let _peerDiscoveredDevices = {};
let _peerGeneration = 0; // incremented on every toggle/disconnect — stale handlers check this

// Smart discovery timer — stops when connected, pauses when hidden, backs off over time
function _peerStartDiscoveryTimer() {
  if (_peerDiscoverTimer) clearInterval(_peerDiscoverTimer);
  let interval = 15000; // start at 15s
  _peerDiscoverTimer = setInterval(() => {
    // Skip if tab hidden, already connected, or peer destroyed
    if (document.hidden || !_peerInstance || _peerConn) {
      if (_peerConn) { clearInterval(_peerDiscoverTimer); _peerDiscoverTimer = null; }
      return;
    }
    window._peerFailedIds?.clear();
    _peerDiscoverDevices();
    // Back off: 15s → 30s → 60s
    if (interval < 60000) {
      interval = Math.min(60000, interval * 2);
      clearInterval(_peerDiscoverTimer);
      _peerDiscoverTimer = setInterval(arguments.callee, interval);
    }
  }, interval);
}
let _peerDiscovering = false; // guards against overlapping discovery scans
let _peerToggling = false; // guards against overlapping toggle calls

function _peerLog(msg, level) {
  const ts = new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  const prefix = level === 'error' ? '✗' : level === 'warn' ? '!' : '›';
  const color = level === 'error' ? '#ff453a' : level === 'warn' ? '#f0c429' : 'rgba(255,255,255,0.55)';
  const el = document.getElementById('syncLogContent');
  if (el) {
    const line = document.createElement('div');
    line.style.color = color;
    line.textContent = `${ts} ${prefix} ${msg}`;
    el.appendChild(line);
    el.parentElement.scrollTop = el.parentElement.scrollHeight;
  }
  if (level === 'error' || level === 'warn') console.warn('[PEER]', msg);
  else console.log('[PEER]', msg);
}
function _peerDestroyInstance() {
  if (_peerConn) { try { _peerConn.close(); } catch {} _peerConn = null; }
  if (_peerInstance) { try { _peerInstance.destroy(); } catch {} _peerInstance = null; }
  if (_peerReconnectTimer) { clearTimeout(_peerReconnectTimer); _peerReconnectTimer = null; }
}

const _peerOpts = {
  debug: 1,
  host: '0.peerjs.com',
  port: 443,
  secure: true,
  path: '/',
  config: {
    iceServers: [
      { urls: 'stun:stun.l.google.com:19302' },
      { urls: 'stun:stun1.l.google.com:19302' },
      { urls: 'turn:openrelay.metered.ca:80', username: 'openrelayproject', credential: 'openrelayproject' },
      { urls: 'turn:openrelay.metered.ca:443', username: 'openrelayproject', credential: 'openrelayproject' },
      { urls: 'turn:openrelay.metered.ca:443?transport=tcp', username: 'openrelayproject', credential: 'openrelayproject' }
    ]
  }
};

function _peerDeviceName() {
  const ua = navigator.userAgent;
  if (/iPhone/.test(ua)) return 'iPhone';
  if (/iPad/.test(ua)) return 'iPad';
  if (/Android/.test(ua)) return 'Android';
  if (/Mac/.test(ua)) return 'Mac';
  if (/Windows/.test(ua)) return 'Windows';
  if (/Linux/.test(ua)) return 'Linux';
  return 'Browser';
}

// Per-device unique suffix — persisted so the ID is stable across sessions
function _peerDeviceSuffix() {
  let suffix = localStorage.getItem('icu_peer_device_suffix');
  if (!suffix) {
    suffix = Math.random().toString(36).slice(2, 5); // 3-char random e.g. "k7f"
    localStorage.setItem('icu_peer_device_suffix', suffix);
  }
  return suffix;
}

function _peerMakeId() {
  const aid = (state.athleteId || '').replace(/[^a-zA-Z0-9]/g, '').slice(0, 8);
  if (!aid) return null;
  const device = _peerDeviceName();
  const suffix = _peerDeviceSuffix();
  return `CIQ-${aid}-${device}-${suffix}`;
}

function _peerCandidateIds() {
  const aid = (state.athleteId || '').replace(/[^a-zA-Z0-9]/g, '').slice(0, 8);
  if (!aid) return [];
  const myId = _peerMakeId();
  const devices = ['iPhone', 'iPad', 'Android', 'Mac', 'Windows', 'Linux', 'Browser'];
  const candidates = new Set();
  for (const d of devices) {
    // Try base ID (no suffix) — first device of each type claims this
    const baseId = `CIQ-${aid}-${d}`;
    if (baseId !== myId && !myId.startsWith(baseId)) candidates.add(baseId);
    // Try known suffixes from previous discoveries
    const knownSuffixes = _peerGetKnownSuffixes(d);
    for (const s of knownSuffixes) {
      const id = `CIQ-${aid}-${d}-${s}`;
      if (id !== myId) candidates.add(id);
    }
  }
  return [...candidates];
}

// Store discovered device suffixes so we can find them again
function _peerGetKnownSuffixes(deviceType) {
  try {
    const stored = JSON.parse(localStorage.getItem('icu_peer_known_suffixes') || '{}');
    return stored[deviceType] || [];
  } catch { return []; }
}

function _peerRememberSuffix(deviceType, suffix) {
  try {
    const stored = JSON.parse(localStorage.getItem('icu_peer_known_suffixes') || '{}');
    if (!stored[deviceType]) stored[deviceType] = [];
    if (!stored[deviceType].includes(suffix)) {
      stored[deviceType].push(suffix);
      // Keep max 5 per type
      if (stored[deviceType].length > 5) stored[deviceType].shift();
      localStorage.setItem('icu_peer_known_suffixes', JSON.stringify(stored));
    }
  } catch {}
}

/* ── Lazy-load PeerJS on demand ── */
let _peerJsLoading = false;
function _loadPeerJS() {
  return new Promise((resolve, reject) => {
    if (typeof Peer !== 'undefined') { resolve(); return; }
    if (_peerJsLoading) { const w = setInterval(() => { if (typeof Peer !== 'undefined') { clearInterval(w); resolve(); } }, 100); return; }
    _peerJsLoading = true;
    const s = document.createElement('script');
    s.src = 'https://unpkg.com/peerjs@1.5.5/dist/peerjs.min.js';
    s.onload = () => resolve();
    s.onerror = () => reject(new Error('Failed to load PeerJS'));
    document.head.appendChild(s);
  });
}
function _loadJsQR() {
  return new Promise((resolve, reject) => {
    if (typeof jsQR !== 'undefined') { resolve(); return; }
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/jsqr@1.4.0/dist/jsQR.min.js';
    s.onload = () => resolve();
    s.onerror = () => reject(new Error('Failed to load jsQR'));
    document.head.appendChild(s);
  });
}

/* ── P2P Toggle: ON/OFF ── */
async function _peerToggle(on) {
  if (_peerToggling) return; // guard against overlapping calls
  _peerToggling = true;
  _peerGeneration++; // invalidate all stale handlers
  const gen = _peerGeneration;

  localStorage.setItem('icu_p2p_enabled', on ? 'true' : 'false');
  const content = document.getElementById('syncP2pContent');
  if (content) content.style.display = on ? '' : 'none';

  // Always fully tear down first
  if (_peerDiscoverTimer) { clearInterval(_peerDiscoverTimer); _peerDiscoverTimer = null; }
  _peerDiscovering = false;
  _peerManualDisconnect = true;
  _peerReconnecting = false;
  if (_peerReconnectTimer) { clearTimeout(_peerReconnectTimer); _peerReconnectTimer = null; }
  if (_peerConn) { try { _peerConn.close(); } catch {} _peerConn = null; }
  if (_peerInstance) { try { _peerInstance.destroy(); } catch {} _peerInstance = null; }
  _peerMyId = '';
  _peerRemoteId = '';
  _peerRemoteName = '';
  _peerDiscoveredDevices = {};
  localStorage.removeItem('icu_peer_remote');
  localStorage.removeItem('icu_peer_my_id');

  if (!on) {
    _peerUpdateUI('off');
    _peerRenderDevices(null);
    _peerToggling = false;
    return;
  }

  // Turn ON
  if (!state.athleteId) { showToast('Log in first to use P2P sync', 'error'); _peerToggling = false; return; }
  const myId = _peerMakeId();
  if (!myId) { showToast('No athlete ID', 'error'); _peerToggling = false; return; }
  try { await _loadPeerJS(); } catch { showToast('Failed to load P2P library', 'error'); _peerToggling = false; return; }

  _peerManualDisconnect = false;
  _peerMyId = myId;
  // Try base ID first (without suffix) — if taken, fall back to suffixed ID
  const aid = (state.athleteId || '').replace(/[^a-zA-Z0-9]/g, '').slice(0, 8);
  const baseId = `CIQ-${aid}-${_peerDeviceName()}`;
  const tryId = baseId; // try without suffix first
  _peerInstance = new Peer(tryId, _peerOpts);

  _peerInstance.on('open', id => {
    if (gen !== _peerGeneration) return; // stale — a newer toggle happened
    _peerMyId = id;
    _peerLog('Registered as: ' + id);
    _peerUpdateUI('ready', id);
    _peerRenderDevices(null);
    _peerToggling = false;
    _peerDiscoverDevices();
    _peerStartDiscoveryTimer();
  });

  _peerInstance.on('connection', conn => {
    if (gen !== _peerGeneration) { try { conn.close(); } catch {} return; }
    _peerLog('Incoming connection from: ' + conn.peer);
    _peerHandleDiscovery(conn, gen);
  });

  _peerInstance.on('error', e => {
    if (gen !== _peerGeneration) return;
    if (e.type === 'peer-unavailable') return;
    if (e.type === 'network') { _peerLog('Network error', 'warn'); return; }
    if (e.type === 'unavailable-id') {
      if (_peerInstance) { try { _peerInstance.destroy(); } catch {} _peerInstance = null; }
      const suffixedId = _peerMakeId();
      _peerLog('ID taken, using ' + suffixedId, 'warn');
      _peerMyId = suffixedId;
      _peerInstance = new Peer(suffixedId, _peerOpts);
      _peerInstance.on('open', id => {
        if (gen !== _peerGeneration) return;
        _peerMyId = id;
        _peerLog('Registered as: ' + id);
        _peerUpdateUI('ready', id);
        _peerToggling = false;
        _peerDiscoverDevices();
        _peerStartDiscoveryTimer();
      });
      _peerInstance.on('connection', conn => _peerHandleDiscovery(conn, gen));
      _peerInstance.on('error', e2 => {
        if (gen !== _peerGeneration) return;
        if (e2.type === 'peer-unavailable') return;
        _peerLog('Peer error: ' + (e2.type || e2.message), 'error');
        _peerToggling = false;
      });
      return;
    }
    _peerLog('Peer error: ' + (e.type || e.message), 'error');
    _peerToggling = false;
  });

  // Timeout: if open doesn't fire in 10s, release the toggle guard
  setTimeout(() => { _peerToggling = false; }, 10000);
}
window._peerToggle = _peerToggle;

/* ── Discovery: scan for other devices on same account ── */
function _peerDiscoverDevices() {
  if (_peerDiscovering) return; // re-entrance guard
  if (!_peerInstance || _peerInstance.destroyed || !_peerInstance.open) return;
  if (_peerConn && _peerConn.open) return; // already paired
  const gen = _peerGeneration;
  if (!window._peerFailedIds) window._peerFailedIds = new Set();
  const candidates = _peerCandidateIds().filter(c => !_peerDiscoveredDevices[c] && !window._peerFailedIds.has(c));
  if (!candidates.length) return;
  _peerDiscovering = true;
  _peerLog('Scanning: ' + candidates.join(', '));

  let idx = 0;
  const _batch = () => {
    if (gen !== _peerGeneration) { _peerDiscovering = false; return; } // stale
    if (!_peerInstance || _peerInstance.destroyed || (_peerConn && _peerConn.open)) { _peerDiscovering = false; return; }
    const batch = candidates.slice(idx, idx + 3);
    if (!batch.length) { _peerDiscovering = false; return; }
    idx += 3;
    for (const cid of batch) {
      if (_peerDiscoveredDevices[cid] || gen !== _peerGeneration) continue;
      try {
        const conn = _peerInstance.connect(cid, { ordered: true });
        const timeout = setTimeout(() => { window._peerFailedIds?.add(cid); try { conn.close(); } catch {} }, 5000);
        conn.on('error', () => { window._peerFailedIds?.add(cid); });
        conn.on('open', () => {
          clearTimeout(timeout);
          if (gen !== _peerGeneration) { try { conn.close(); } catch {} return; }
          _peerLog('Probe connected: ' + cid);
          conn.send({ type: 'discover', name: _peerDeviceName(), suffix: _peerDeviceSuffix() });
          conn.on('data', data => {
            if (gen !== _peerGeneration) return;
            if (data?.type === 'discover_ack') {
              if (!_peerDiscoveredDevices[cid]) {
                _peerDiscoveredDevices[cid] = { name: data.name, conn };
                // Remember suffix for future scans
                if (data.suffix) {
                  const parts = cid.split('-');
                  if (parts.length >= 3) _peerRememberSuffix(parts[2], data.suffix);
                }
                _peerLog('Found: ' + data.name);
                _peerRenderDevices(null);
              }
            } else if (data?.type === 'pair_request') {
              // Remote tapped Pair on a connection we initiated — handle it
              const name = data.name || _peerDiscoveredDevices[cid]?.name || cid;
              _peerShowSyncConfirm({
                title: 'Pair Request', pairDevice: name,
                desc: '', btnText: 'Accept', btnColor: 'var(--accent)',
                onApprove: () => { conn.send({ type: 'pair_accept', name: _peerDeviceName() }); _peerPromoteToPaired(conn, name); },
                onDecline: () => { conn.send({ type: 'pair_decline', name: _peerDeviceName() }); },
              });
            } else if (data?.type === 'pair_accept') {
              _peerHandlePairAccept(conn, data);
            } else if (data?.type === 'pair_decline') {
              showToast((data.name || 'Peer') + ' declined', 'info');
            }
          });
          conn.on('close', () => {
            if (gen !== _peerGeneration) return;
            delete _peerDiscoveredDevices[cid];
            _peerRenderDevices(null);
          });
        });
        conn.on('error', () => clearTimeout(timeout));
      } catch {}
    }
    if (idx < candidates.length) setTimeout(_batch, 800);
    else _peerDiscovering = false;
  };
  _batch();
}

/* ── Handle incoming discovery connections ── */
function _peerHandleDiscovery(conn, gen) {
  let _remoteName = '';
  conn._peerGen = gen; // tag connection with its generation
  conn.on('data', data => {
    if (gen !== _peerGeneration) return; // stale
    if (!data?.type) return;
    if (data.type === 'discover') {
      _remoteName = data.name || conn.peer;
      conn.send({ type: 'discover_ack', name: _peerDeviceName(), suffix: _peerDeviceSuffix() });
      // Always prefer incoming connection — both sides listen on it
      _peerDiscoveredDevices[conn.peer] = { name: _remoteName, conn };
      // Remember this device's suffix for future discovery
      const parts = conn.peer.split('-');
      if (parts.length >= 4) _peerRememberSuffix(parts[2], parts[3]);
      _peerLog('Discovered by: ' + _remoteName);
      _peerRenderDevices(null);
    } else if (data.type === 'pair_request') {
      _peerShowSyncConfirm({
        title: 'Pair Request', pairDevice: data.name || _remoteName,
        desc: '', btnText: 'Accept', btnColor: 'var(--accent)',
        onApprove: () => {
          conn.send({ type: 'pair_accept', name: _peerDeviceName() });
          _peerPromoteToPaired(conn, data.name || _remoteName);
        },
        onDecline: () => {
          conn.send({ type: 'pair_decline', name: _peerDeviceName() });
          _peerLog('Declined pair from ' + _remoteName);
        },
      });
    } else if (data.type === 'pair_accept') {
      _peerHandlePairAccept(conn, data);
    } else if (data.type === 'pair_decline') {
      showToast((data.name || _remoteName) + ' declined', 'info');
    }
  });
  conn.on('close', () => {
    if (gen !== _peerGeneration) return;
    delete _peerDiscoveredDevices[conn.peer];
    _peerRenderDevices(null);
  });
}

/* ── Pair request (initiated by tapping Pair button) ── */
function _peerRequestPair(peerId) {
  const device = _peerDiscoveredDevices[peerId];
  if (!device || !device.conn || !device.conn.open) {
    showToast('Device no longer available', 'error');
    return;
  }
  device.conn.send({ type: 'pair_request', name: _peerDeviceName() });
  _peerLog('Sent pair request to ' + device.name);
  showToast('Pair request sent to ' + device.name + '...', 'info');
}
window._peerRequestPair = _peerRequestPair;

/* ── Accept pairing: promote discovery conn to full paired conn ── */
function _peerHandlePairAccept(conn, data) {
  _peerPromoteToPaired(conn, data.name || 'Peer');
  showToast('Paired with ' + (data.name || 'Peer') + '!', 'success');
}

function _peerPromoteToPaired(conn, name) {
  // Stop discovery
  if (_peerDiscoverTimer) { clearInterval(_peerDiscoverTimer); _peerDiscoverTimer = null; }
  _peerDiscovering = false;
  _peerDiscoveredDevices = {};

  // Remove all existing listeners from discovery phase to prevent duplicates
  conn.removeAllListeners('data');
  conn.removeAllListeners('close');
  conn.removeAllListeners('error');

  // Set as main connection
  _peerConn = conn;
  _peerRemoteId = conn.peer;
  _peerRemoteName = name;
  _peerReconnecting = false;
  localStorage.setItem('icu_peer_remote', _peerRemoteId);
  localStorage.setItem('icu_peer_my_id', _peerMyId);

  // Attach full paired data handler (clean — no duplicate listeners)
  _peerHandleConn(conn);
  _peerUpdateUI('connected');
  _peerRenderDevices(name);
  _peerLog('Paired with ' + name);
}

/* ── Sync category toggles ── */
const _SYNC_CATEGORIES = {
  gear:        k => k.includes('gear') || k.includes('component') || k.includes('bike_photo'),
  batteries:   k => k.includes('batter'),
  services:    k => k.includes('service') || k.includes('shop'),
  settings:    k => k.includes('theme') || k.includes('widget') || k.includes('range') || k.includes('notif') || k.includes('font') || k.includes('unit') || k.includes('week_start') || k.includes('dash_section') || k.includes('goal'),
  credentials: k => k.includes('athlete') || k.includes('api_key') || k.includes('strava'),
};
function _syncGetToggles() {
  try { return JSON.parse(localStorage.getItem('icu_sync_toggles') || '{}'); } catch { return {}; }
}
function _syncToggleCategory(el) {
  const key = el.dataset.syncKey;
  const toggles = _syncGetToggles();
  toggles[key] = el.checked;
  localStorage.setItem('icu_sync_toggles', JSON.stringify(toggles));
}
window._syncToggleCategory = _syncToggleCategory;

function _peerBuildSnapshot() {
  const toggles = _syncGetToggles();
  const ls = {};
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (!k.startsWith('icu_') && !k.startsWith('strava_')) continue;
    // Check if any disabled category matches this key
    let excluded = false;
    for (const [cat, matcher] of Object.entries(_SYNC_CATEGORIES)) {
      if (toggles[cat] === false && matcher(k)) { excluded = true; break; }
    }
    if (!excluded) ls[k] = localStorage.getItem(k);
  }
  return ls;
}

function _peerRestoreSnapshot(snapshot) {
  if (!snapshot || typeof snapshot !== 'object') return;
  for (const [k, v] of Object.entries(snapshot)) {
    if (k.startsWith('icu_') || k.startsWith('strava_')) localStorage.setItem(k, v);
  }
}

function _peerUpdateUI(status, peerId) {
  const dot = document.querySelector('#syncStatusDot .sync-dot');
  const text = document.getElementById('syncStatusText');
  const label = document.getElementById('syncStatusLabel');

  const isPeerConnected = status === 'connected';
  const isOn = status === 'ready' || isPeerConnected || status === 'connecting';

  // Hero status dot + text
  if (dot) {
    dot.className = 'sync-dot ' + (isPeerConnected ? 'sync-dot--on' : isOn ? 'sync-dot--waiting' : 'sync-dot--off');
  }
  if (text) {
    text.textContent = isPeerConnected ? 'Connected'
      : isOn ? 'Scanning...'
      : 'Off';
  }

  // Settings row label
  if (label) label.textContent = isPeerConnected ? 'Connected' : isOn ? 'On' : '';

  // Transfer zone visibility
  const zoneActive = document.getElementById('syncZoneActive');
  if (zoneActive) zoneActive.style.display = isPeerConnected ? '' : 'none';

  // Floating P2P status icon
  const p2pBtn = document.getElementById('p2pStatusBtn');
  const p2pDot = document.getElementById('p2pStatusDot');
  if (p2pBtn) {
    const onDash = state.currentPage === 'dashboard';
    p2pBtn.style.display = (isOn && onDash) ? 'flex' : 'none';
    p2pBtn.style.color = isPeerConnected ? 'var(--accent)' : 'var(--text-muted)';
  }
  if (p2pDot) {
    p2pDot.className = 'p2p-status-dot ' + (isPeerConnected ? 'p2p-dot--on' : isOn ? 'p2p-dot--scanning' : 'p2p-dot--off');
  }

  _peerUpdateLastSync();
}

function _peerUpdateLastSync() {
  const el = document.getElementById('syncLastTime');
  if (!el) return;
  const ts = localStorage.getItem('icu_peer_last_sync');
  if (ts) {
    const d = new Date(ts);
    el.textContent = d.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
  } else {
    el.textContent = 'Never';
  }
}

function _peerRenderDevices(peerName) {
  const el = document.getElementById('syncDeviceList');
  if (!el) return;
  const _icon = n => (['iPhone','iPad','Android'].includes(n)
    ? '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="1.8"><rect x="5" y="2" width="14" height="20" rx="2"/><line x1="12" y1="18" x2="12.01" y2="18"/></svg>'
    : '<svg class="icon" width="18" height="18"><use href="icons.svg#icon-monitor"/></svg>');
  const myName = _peerDeviceName();
  let html = `<div class="sync-device sync-device--me">
    <div class="sync-device-icon">${_icon(myName)}</div>
    <div class="sync-device-info"><div class="sync-device-name">${myName}</div><div class="sync-device-time">This device</div></div>
    <div class="sync-device-dot"></div>
  </div>`;

  // Connected peer
  if (peerName && _peerConn?.open) {
    html += `<div class="sync-device">
      <div class="sync-device-icon">${_icon(peerName)}</div>
      <div class="sync-device-info"><div class="sync-device-name">${peerName}</div><div class="sync-device-time" style="color:var(--accent)">Connected</div></div>
      <div class="sync-device-dot sync-device-dot--peer"></div>
    </div>`;
  }

  // Discovered (not yet paired) devices
  for (const [pid, dev] of Object.entries(_peerDiscoveredDevices)) {
    if (_peerConn?.open && pid === _peerRemoteId) continue; // already shown as connected
    html += `<div class="sync-device">
      <div class="sync-device-icon">${_icon(dev.name)}</div>
      <div class="sync-device-info"><div class="sync-device-name">${dev.name}</div><div class="sync-device-time">Discovered</div></div>
      <button class="sync-pair-btn" onclick="_peerRequestPair('${pid}')">Pair</button>
    </div>`;
  }

  el.innerHTML = html;
}

/* ── QR Code generation (minimal, no library needed for short strings) ── */
function _peerShowQR() {
  const canvas = document.getElementById('syncQrCanvas');
  if (!canvas || !_peerMyId) return;
  const btn = document.getElementById('syncQrBtn');
  const isVisible = canvas.style.display !== 'none';
  if (isVisible) {
    canvas.style.display = 'none';
    if (btn) btn.innerHTML = '<svg class="icon" width="14" height="14"><use href="icons.svg#icon-grid"/></svg> Show QR';
    return;
  }
  // Use QR code API as image
  const img = new Image();
  img.crossOrigin = 'anonymous';
  const _qrShownLabel = '<svg class="icon" width="14" height="14"><use href="icons.svg#icon-x"/></svg> Hide QR';
  const _qrSize = 400;
  img.onload = () => {
    canvas.style.display = 'block';
    canvas.width = _qrSize;
    canvas.height = _qrSize;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, _qrSize, _qrSize);
    ctx.drawImage(img, 0, 0, _qrSize, _qrSize);
    if (btn) btn.innerHTML = _qrShownLabel;
  };
  img.onerror = () => {
    canvas.style.display = 'block';
    canvas.width = _qrSize;
    canvas.height = _qrSize;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, _qrSize, _qrSize);
    ctx.fillStyle = '#000000';
    ctx.font = 'bold 48px monospace';
    ctx.textAlign = 'center';
    ctx.fillText(_peerMyId, _qrSize / 2, _qrSize / 2 + 16);
    if (btn) btn.innerHTML = _qrShownLabel;
  };
  img.src = `https://api.qrserver.com/v1/create-qr-code/?size=${_qrSize}x${_qrSize}&data=${encodeURIComponent(_peerMyId)}&bgcolor=ffffff&color=000000&margin=0`;
}
window._peerShowQR = _peerShowQR;

/* ── QR Code scanning via camera (jsQR — works on iOS Safari) ── */
function _peerScanQR() {
  // Ensure jsQR is loaded
  if (typeof jsQR === 'undefined') {
    showToast('Loading scanner...', 'info');
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/jsqr@1.4.0/dist/jsQR.min.js';
    s.onload = () => _peerScanQR();
    s.onerror = () => showToast('QR scanner failed to load — enter the ID manually', 'error');
    document.head.appendChild(s);
    return;
  }
  const overlay = document.createElement('div');
  overlay.id = 'qrScanOverlay';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:99999;background:#000;display:flex;flex-direction:column;align-items:center;justify-content:center;';
  overlay.innerHTML = `
    <div style="position:absolute;top:env(safe-area-inset-top,16px);left:16px;right:16px;padding-top:16px;display:flex;justify-content:space-between;align-items:center;z-index:2">
      <span style="color:#fff;font-size:17px;font-weight:600">Scan Peer QR Code</span>
      <button id="qrScanClose" style="width:36px;height:36px;border-radius:50%;background:rgba(255,255,255,0.2);border:none;color:#fff;font-size:20px;cursor:pointer">×</button>
    </div>
    <video id="qrScanVideo" autoplay playsinline muted style="width:100%;height:100%;object-fit:cover"></video>
    <canvas id="qrScanCanvas" style="display:none"></canvas>
    <div style="position:absolute;width:200px;height:200px;border:2px solid var(--accent);border-radius:12px;pointer-events:none"></div>
  `;
  document.body.appendChild(overlay);

  const video = document.getElementById('qrScanVideo');
  const canvas = document.getElementById('qrScanCanvas');
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  let scanning = true;

  document.getElementById('qrScanClose').onclick = () => {
    scanning = false;
    if (window._qrScanStream) window._qrScanStream.getTracks().forEach(t => t.stop());
    overlay.remove();
  };

  navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
    .then(stream => {
      window._qrScanStream = stream;
      video.srcObject = stream;
      video.play();

      const scan = () => {
        if (!scanning || !document.getElementById('qrScanOverlay')) return;
        if (video.readyState >= video.HAVE_ENOUGH_DATA) {
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

          // Use jsQR if available, fallback to BarcodeDetector
          if (typeof jsQR !== 'undefined') {
            const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'dontInvert' });
            if (code && code.data) {
              const val = code.data.trim().toUpperCase();
              if (val.startsWith('CIQ-')) {
                scanning = false;
                stream.getTracks().forEach(t => t.stop());
                overlay.remove();
                const input = document.getElementById('syncJoinInput');
                if (input) input.value = val;
                _peerConnect(val);
                showToast('QR scanned: ' + val, 'success');
                return;
              }
            }
          }
        }
        requestAnimationFrame(scan);
      };
      video.onloadedmetadata = () => { video.play(); requestAnimationFrame(scan); };
    })
    .catch(e => {
      scanning = false;
      overlay.remove();
      console.warn('[QR] Camera error:', e);
      showToast('Camera access denied — enter the ID manually', 'error');
    });
}
window._peerScanQR = _peerScanQR;

function _peerShowProgress(current, total, sizeBytes) {
  let bar = document.getElementById('syncProgressBar');
  if (!bar) {
    bar = document.createElement('div');
    bar.id = 'syncProgressBar';
    bar.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:99999;background:var(--surface-2);height:40px;display:flex;align-items:center;padding:0 16px;gap:10px;';
    bar.innerHTML = `<div style="flex:1;height:6px;background:var(--surface-3);border-radius:3px;overflow:hidden"><div id="syncProgressFill" style="height:100%;background:var(--accent);border-radius:3px;transition:width 0.15s;width:0%"></div></div><span id="syncProgressText" style="font-size:12px;font-family:var(--font-num);color:var(--text-secondary);white-space:nowrap">0%</span>`;
    document.body.appendChild(bar);
  }
  const pct = total > 0 ? Math.round((current / total) * 100) : 0;
  const fill = document.getElementById('syncProgressFill');
  const text = document.getElementById('syncProgressText');
  if (fill) fill.style.width = pct + '%';
  if (text) {
    if (sizeBytes) {
      text.textContent = `Receiving ${Math.round(sizeBytes / 1024)} KB...`;
    } else {
      text.textContent = pct + '%';
    }
  }
}

function _peerHideProgress() {
  const bar = document.getElementById('syncProgressBar');
  if (bar) {
    const fill = document.getElementById('syncProgressFill');
    if (fill) fill.style.width = '100%';
    const text = document.getElementById('syncProgressText');
    if (text) text.textContent = '✓ Complete';
    setTimeout(() => bar.remove(), 1500);
  }
}

function _peerHandleConn(conn) {
  const gen = _peerGeneration;
  // Close previous connection if still open
  if (_peerConn && _peerConn !== conn) { try { _peerConn.close(); } catch {} }
  _peerConn = conn;
  _peerManualDisconnect = false;
  let _chunks = [];
  let _chunkTotal = 0;
  conn._receiveApproved = false;
  conn.on('open', () => {
    _peerRemoteId = conn.peer;
    const wasReconnecting = _peerReconnecting;
    _peerReconnecting = false;
    if (_peerReconnectTimer) { clearTimeout(_peerReconnectTimer); _peerReconnectTimer = null; }
    _peerUpdateUI('connected');
    conn.send({ type: 'hello', name: _peerDeviceName() });
    _peerRenderDevices(null);
    localStorage.setItem('icu_peer_remote', _peerRemoteId);
    localStorage.setItem('icu_peer_my_id', _peerMyId);
    _peerLog('Data channel open with: ' + conn.peer);
    showToast(wasReconnecting ? 'Reconnected!' : 'Peer connected!', 'success');
    // Attach ICE listeners AFTER open (peerConnection now available)
    try {
      const _pc = conn.peerConnection;
      if (_pc) {
        _pc.oniceconnectionstatechange = () => _peerLog('ICE: ' + _pc.iceConnectionState);
        _pc.onconnectionstatechange = () => _peerLog('Conn state: ' + _pc.connectionState);
      }
    } catch {}
  });
  conn.on('data', data => {
    if (!data || !data.type) return;
    if (data.type === 'hello') {
      _peerRemoteName = data.name || '';
      _peerRenderDevices(_peerRemoteName);
    } else if (data.type === 'snapshot_start') {
      if (!conn._receiveApproved) { _peerLog('Blocked unapproved snapshot_start', 'warn'); return; }
      _chunks = new Array(data.total);
      _chunkTotal = data.total;
      _peerShowProgress(0, data.total, data.size);
    } else if (data.type === 'snapshot_chunk') {
      if (!conn._receiveApproved) return;
      _chunks[data.index] = data.data;
      _peerShowProgress(data.index + 1, _chunkTotal);
    } else if (data.type === 'snapshot_end') {
      if (!conn._receiveApproved) { _peerLog('Blocked unapproved snapshot_end', 'warn'); return; }
      _peerHideProgress();
      try {
        const json = _chunks.join('');
        const snapshot = JSON.parse(json);
        const keys = Object.keys(snapshot).length;
        _peerRestoreSnapshot(snapshot);
        localStorage.setItem('icu_peer_last_sync', new Date().toISOString());
        _peerUpdateLastSync();
        conn.send({ type: 'snapshot_ack', keys, device: _peerDeviceName() });
        conn._receiveApproved = false; // reset guard after successful receive
        _peerLog('Received ' + keys + ' keys from peer');
        showToast(`Received ${keys} keys ✓`, 'success');
      } catch (e) {
        _peerLog('Snapshot parse error: ' + e.message, 'error');
        conn.send({ type: 'snapshot_ack', error: true });
        showToast('Failed to parse received data', 'error');
      }
      _chunks = [];
    } else if (data.type === 'snapshot') {
      if (!conn._receiveApproved) { _peerLog('Blocked unapproved snapshot', 'warn'); return; }
      const keys = Object.keys(data.payload || {}).length;
      _peerRestoreSnapshot(data.payload);
      localStorage.setItem('icu_peer_last_sync', new Date().toISOString());
      _peerUpdateLastSync();
      _peerLog('Received ' + keys + ' keys from peer');
      showToast(`Received ${keys} keys ✓`, 'success');
    } else if (data.type === 'snapshot_ack') {
      if (data.error) {
        showToast('Peer failed to restore data', 'error');
      } else {
        showToast(`${data.device || 'Peer'} received ${data.keys} keys ✓`, 'success');
      }
    } else if (data.type === 'request') {
      // Peer wants our data — ask user to approve
      _peerLog('Data request from: ' + (data.device || conn.peer));
      _peerShowIncomingRequest(data.device || conn.peer, conn);
    } else if (data.type === 'request_declined') {
      _peerLog('Request declined by peer', 'warn');
      showToast((data.device || 'Peer') + ' declined the request', 'info');
    } else if (data.type === 'send_offer') {
      // Peer wants to send us data — ask user to accept
      _peerLog('Incoming data offer from: ' + (data.device || conn.peer) + ' (' + data.keys + ' keys, ' + Math.round((data.size || 0) / 1024) + ' KB)');
      _peerShowIncomingSendOffer(data.device || conn.peer, data.size, data.keys, conn);
    } else if (data.type === 'send_accepted') {
      // Peer accepted our send — now actually send the data
      _peerLog('Peer accepted — sending data...');
      showToast('Peer accepted — sending...', 'success');
      _peerSendSnapshot(conn);
      localStorage.setItem('icu_peer_last_sync', new Date().toISOString());
      _peerUpdateLastSync();
    } else if (data.type === 'send_declined') {
      _peerLog('Send declined by peer', 'warn');
      showToast((data.device || 'Peer') + ' declined the transfer', 'info');
    }
  });
  conn.on('close', () => {
    if (gen !== _peerGeneration) return; // stale — a newer toggle/disconnect happened
    if (_peerConn === conn) _peerConn = null;
    if (_peerManualDisconnect) return;
    if (_peerReconnecting) return;
    const remoteId = _peerRemoteId || conn.peer;
    if (remoteId && _peerInstance && !_peerInstance.destroyed) {
      _peerReconnecting = true;
      _peerUpdateUI('connecting');
      _peerLog('Connection lost — reconnecting in 2s...', 'warn');
      showToast('Connection lost — reconnecting...', 'info');
      // Debounce: wait 2s before first reconnect attempt (both sides may close simultaneously)
      _peerReconnectTimer = setTimeout(() => _peerAutoReconnect(remoteId, 0), 2000);
    } else {
      _peerUpdateUI('off');
      _peerRenderDevices(null);
      showToast('Peer disconnected', 'info');
    }
  });
  conn.on('error', e => {
    _peerLog('Connection error: ' + (e.type || e.message || e), 'error');
    if (!_peerManualDisconnect) {
      showToast('Connection error — will retry...', 'error');
    }
  });
}

function _peerAutoReconnect(remoteId, attempt) {
  if (_peerManualDisconnect || !_peerInstance || _peerInstance.destroyed) return;
  if (_peerConn && _peerConn.open) { _peerReconnecting = false; return; } // already connected
  if (attempt >= 5) {
    _peerReconnecting = false;
    _peerReconnectTimer = null;
    _peerUpdateUI('off');
    _peerLog('Gave up after 5 reconnect attempts', 'error');
    showToast('Could not reconnect — peer may be offline', 'error');
    return;
  }
  const delay = Math.min(3000 * Math.pow(1.5, attempt), 20000); // 3s, 4.5s, 6.75s... max 20s
  // Add jitter (0-1s) to avoid both peers reconnecting at the exact same time
  const jitter = Math.random() * 1000;
  _peerLog(`Reconnect attempt ${attempt + 1} in ${Math.round((delay + jitter) / 1000)}s...`);
  _peerReconnectTimer = setTimeout(() => {
    if (_peerManualDisconnect || !_peerInstance || _peerInstance.destroyed) return;
    if (_peerConn && _peerConn.open) { _peerReconnecting = false; return; }
    // Close any lingering old connection
    if (_peerConn) { try { _peerConn.close(); } catch {} _peerConn = null; }
    const conn = _peerInstance.connect(remoteId, { ordered: true });
    _peerHandleConn(conn);
    // If doesn't open in 10s, try next attempt
    const timeout = setTimeout(() => {
      if (!conn.open && !_peerManualDisconnect) {
        try { conn.close(); } catch {} // clean up failed attempt
        _peerAutoReconnect(remoteId, attempt + 1);
      }
    }, 10000);
    conn.on('open', () => { clearTimeout(timeout); _peerReconnectTimer = null; });
  }, delay + jitter);
}

async function _peerStart() {
  try { await _loadPeerJS(); } catch {
    showToast('Failed to load P2P library', 'error');
    _peerUpdateUI('error');
    return;
  }
  _peerAutoStarting = false; // cancel auto-start if running
  _peerDestroyInstance();
  _peerManualDisconnect = false;

  // Reuse saved host ID, or generate a new one
  const savedHostId = localStorage.getItem('icu_peer_host_id');
  const shortId = savedHostId || ('CIQ-' + Array.from(crypto.getRandomValues(new Uint8Array(3)))
    .map(b => b.toString(36)).join('').toUpperCase().slice(0, 6));
  localStorage.setItem('icu_peer_host_id', shortId);
  _peerMyId = shortId;

  _peerInstance = new Peer(shortId, _peerOpts);
  _peerInstance.on('open', id => {
    _peerMyId = id;
    _peerLog('Host registered: ' + id);
    _peerUpdateUI('ready', id);
    _peerRenderDevices(null);
    const codeEl = document.getElementById('syncRoomCode');
    if (codeEl) codeEl.textContent = id;
  });
  _peerInstance.on('connection', conn => {
    _peerLog('Incoming connection from: ' + conn.peer);
    _peerHandleConn(conn);
  });
  _peerInstance.on('error', e => {
    _peerLog('Peer error: ' + e.type + ' — ' + (e.message || ''), 'error');
    if (e.type === 'unavailable-id') {
      _peerInstance.destroy();
      // Clear saved ID so _peerStart generates a fresh one
      localStorage.removeItem('icu_peer_host_id');
      _peerLog('ID taken, generating new one...');
      setTimeout(_peerStart, 500);
    } else if (e.type === 'peer-unavailable') {
      showToast('Peer not found — check the ID and try again', 'error');
      _peerUpdateUI('off');
    } else {
      showToast('Connection error: ' + (e.type || ''), 'error');
      _peerUpdateUI('off');
    }
  });
}

async function _peerConnect(peerId) {
  if (!peerId || peerId.length < 4) { showToast('Enter a valid peer ID', 'error'); return; }
  _peerAutoStarting = false; // cancel auto-start
  const clean = peerId.trim().toUpperCase();
  _peerUpdateUI('connecting');
  _peerLog('Connecting to ' + clean + '...');
  showToast('Connecting to ' + clean + '...', 'info');

  const _doConnect = () => {
    const conn = _peerInstance.connect(clean, { ordered: true });
    _peerHandleConn(conn);
    // Timeout: if conn doesn't open in 15s, show error
    const timeout = setTimeout(() => {
      if (!conn.open) {
        _peerLog('Connection timeout — peer may be offline', 'warn');
        showToast('Connection timed out — peer may be offline', 'error');
        _peerUpdateUI('off');
      }
    }, 15000);
    conn.on('open', () => clearTimeout(timeout));
    conn.on('error', () => clearTimeout(timeout));
  };

  // If no instance, destroyed, or stuck — create a fresh one
  if (!_peerInstance || _peerInstance.destroyed || !_peerInstance.open) {
    _peerDestroyInstance();
    try { await _loadPeerJS(); } catch { showToast('Failed to load P2P library', 'error'); return; }
    const myId = 'CIQ-' + Array.from(crypto.getRandomValues(new Uint8Array(3)))
      .map(b => b.toString(36)).join('').toUpperCase().slice(0, 6);
    _peerInstance = new Peer(myId, _peerOpts);
    _peerInstance.on('open', () => {
      _peerMyId = myId;
      _peerLog('Joiner registered: ' + myId);
      _doConnect();
    });
    _peerInstance.on('connection', conn => _peerHandleConn(conn));
    _peerInstance.on('error', e => {
      _peerLog('Connect error: ' + e.type + ' — ' + (e.message || ''), 'error');
      if (e.type === 'peer-unavailable') {
        showToast('Peer not found — check the ID and try again', 'error');
        _peerUpdateUI('off');
      } else {
        showToast('Could not connect: ' + (e.type || e.message), 'error');
        _peerUpdateUI('off');
      }
    });
  } else {
    // Instance exists and is open — connect directly
    _doConnect();
  }
}
window._peerConnect = _peerConnect;

function _peerSendSnapshot(conn) {
  const snapshot = _peerBuildSnapshot();
  const json = JSON.stringify(snapshot);
  const CHUNK = 100000;
  const total = Math.ceil(json.length / CHUNK);
  _peerShowProgress(0, total, json.length);
  conn.send({ type: 'snapshot_start', total, size: json.length });
  // Send chunks with small delays to avoid overwhelming the buffer
  let i = 0;
  function sendNext() {
    if (i < total) {
      conn.send({ type: 'snapshot_chunk', index: i, data: json.slice(i * CHUNK, (i + 1) * CHUNK) });
      _peerShowProgress(i + 1, total);
      i++;
      setTimeout(sendNext, 20);
    } else {
      conn.send({ type: 'snapshot_end' });
      _peerHideProgress();
    }
  }
  sendNext();
}

function _peerSendData() {
  if (!_peerConn || !_peerConn.open) {
    showToast('No peer connected', 'error');
    return;
  }
  // Send offer — wait for peer to accept before sending actual data
  const snapshot = _peerBuildSnapshot();
  const sizeBytes = JSON.stringify(snapshot).length;
  _peerConn.send({ type: 'send_offer', device: _peerDeviceName(), size: sizeBytes, keys: Object.keys(snapshot).length });
  _peerLog('Sent data offer to peer — waiting for approval...');
  showToast('Waiting for peer to accept...', 'info');
}
window._peerSendData = _peerSendData;

function _peerRequestData() {
  if (!_peerConn || !_peerConn.open) {
    showToast('No peer connected', 'error');
    return;
  }
  _peerConn._receiveApproved = true; // we initiated the request, so we approve incoming data
  _peerConn.send({ type: 'request', device: _peerDeviceName() });
  _peerLog('Requesting data from peer...');
  showToast('Requesting data from peer — waiting for approval...', 'info');
}
window._peerRequestData = _peerRequestData;

function _peerCancelConnect() {
  _peerLog('Connection cancelled');
  _peerManualDisconnect = true;
  _peerReconnecting = false;
  if (_peerReconnectTimer) { clearTimeout(_peerReconnectTimer); _peerReconnectTimer = null; }
  if (_peerConn) { try { _peerConn.close(); } catch {} _peerConn = null; }
  if (_peerInstance) { try { _peerInstance.destroy(); } catch {} _peerInstance = null; }
  _peerMyId = '';
  _peerUpdateUI('off');
  _peerRenderDevices(null);
  showToast('Connection cancelled', 'info');
}
window._peerCancelConnect = _peerCancelConnect;

function _peerDisconnect() {
  _peerLog('Disconnected — restarting discovery');
  showToast('Disconnected', 'success');
  // Full clean re-toggle: _peerToggle handles all teardown + re-init
  _peerToggle(true);
}
window._peerDisconnect = _peerDisconnect;

// Aliases for HTML onclick compatibility
window._gunGenRoom = _peerStart;
window._peerResetId = function() {
  _peerDestroyInstance();
  localStorage.removeItem('icu_peer_host_id');
  _peerMyId = '';
  _peerStart();
};
window._gunCopyRoom = function() {
  if (!_peerMyId) return;
  navigator.clipboard?.writeText(_peerMyId).then(() => showToast('Peer ID copied', 'success'))
    .catch(() => { prompt('Copy this ID:', _peerMyId); });
};
window._gunJoinRoom = _peerConnect;
window._gunDisconnect = _peerDisconnect;

// Auto-reconnect on app startup if we have a saved pairing
// Auto-enable P2P if it was on in previous session
(function _peerAutoEnable() {
  if (localStorage.getItem('icu_p2p_enabled') !== 'true') return;
  const _wait = () => {
    if (!state.athleteId) { setTimeout(_wait, 1000); return; }
    _peerToggle(true); // _peerToggle now lazy-loads PeerJS itself
    const cb = document.getElementById('syncP2pToggle');
    if (cb) cb.checked = true;
  };
  setTimeout(_wait, 3000);
})();

/* ── Sync transfer confirmation sheet ── */
function _peerConfirmTransfer(mode) {
  if (mode === 'send' && (!_peerConn || !_peerConn.open)) {
    showToast('No peer connected', 'error'); return;
  }
  if (mode === 'receive' && (!_peerConn || !_peerConn.open)) {
    showToast('No peer connected', 'error'); return;
  }

  const titleEl = document.getElementById('syncConfirmTitle');
  const descEl = document.getElementById('syncConfirmDesc');
  const itemsEl = document.getElementById('syncConfirmItems');
  const sizeEl = document.getElementById('syncConfirmSize');
  const btnEl = document.getElementById('syncConfirmBtn');
  if (!titleEl || !btnEl) return;

  const isSend = mode === 'send';
  titleEl.textContent = isSend ? 'Send Data' : 'Receive Data';
  descEl.textContent = isSend
    ? 'This will send your local data to the connected peer. Their data will be overwritten.'
    : 'This will request data from the connected peer. Your local data will be overwritten.';

  // Build data summary
  const snapshot = _peerBuildSnapshot();
  const keys = Object.keys(snapshot);
  const sizeBytes = JSON.stringify(snapshot).length;
  const sizeMB = (sizeBytes / 1048576).toFixed(1);
  const sizeKB = Math.round(sizeBytes / 1024);
  sizeEl.textContent = sizeBytes > 1048576 ? `${sizeMB} MB` : `${sizeKB} KB`;

  // Categorize keys for summary
  const cats = { gear: 0, batteries: 0, services: 0, goals: 0, settings: 0, strava: 0, other: 0 };
  for (const k of keys) {
    if (k.includes('gear') || k.includes('component') || k.includes('bike')) cats.gear++;
    else if (k.includes('batter')) cats.batteries++;
    else if (k.includes('service') || k.includes('shop')) cats.services++;
    else if (k.includes('goal')) cats.goals++;
    else if (k.startsWith('strava_')) cats.strava++;
    else if (k.includes('setting') || k.includes('range') || k.includes('widget') || k.includes('theme') || k.includes('notif')) cats.settings++;
    else cats.other++;
  }

  let itemsHtml = '';
  const catList = [
    ['Gear & Components', cats.gear, 'var(--accent)'],
    ['Batteries', cats.batteries, '#f0c429'],
    ['Services & Shops', cats.services, '#5ac8fa'],
    ['Goals', cats.goals, '#ff9500'],
    ['Settings & Preferences', cats.settings, '#af52de'],
    ['Strava Data', cats.strava, '#fc4c02'],
    ['Other Data', cats.other, 'var(--text-muted)'],
  ];
  for (const [label, count, color] of catList) {
    if (count === 0) continue;
    itemsHtml += `<div class="ios-row" style="min-height:36px"><span class="ios-row-label">${label}</span><span class="ios-row-detail" style="color:${color};font-weight:600">${count} keys</span></div>`;
  }
  if (itemsEl) itemsEl.innerHTML = itemsHtml;

  // Confirm button
  btnEl.textContent = isSend ? 'Send Now' : 'Request Now';
  btnEl.style.background = isSend ? 'var(--accent)' : '#5ac8fa';
  btnEl.style.color = '#000';
  btnEl.onclick = () => {
    _closeOverlaySheet('syncConfirmSheet');
    if (isSend) _peerSendData();
    else _peerRequestData();
  };

  _openOverlaySheet('syncConfirmSheet');
}
window._peerConfirmTransfer = _peerConfirmTransfer;

/* ── Incoming data request approval ── */
/* ── Unified sync confirmation sheet (request + send offer) ── */
function _peerShowSyncConfirm(cfg) {
  // cfg: { title, desc, btnText, btnColor, onApprove, onDecline, sizeBytes?, keyCount?, showItemBreakdown? }
  const titleEl = document.getElementById('syncConfirmTitle');
  const descEl = document.getElementById('syncConfirmDesc');
  const itemsEl = document.getElementById('syncConfirmItems');
  const sizeEl = document.getElementById('syncConfirmSize');
  const btnEl = document.getElementById('syncConfirmBtn');
  if (!titleEl || !btnEl) return;

  titleEl.textContent = cfg.title;
  descEl.textContent = cfg.desc;
  const closeBtn = document.querySelector('#syncConfirmSheet .modal-close');
  if (closeBtn) closeBtn.style.display = cfg.pairDevice ? 'none' : '';
  titleEl.style.display = '';
  titleEl.style.textAlign = cfg.pairDevice ? 'center' : '';
  titleEl.style.width = cfg.pairDevice ? '100%' : '';

  // Pair request: show device graphic instead of data keys/size
  const sizeRow = sizeEl?.closest('div');
  if (cfg.pairDevice) {
    const _devImages = { iPhone: 'img/devices/iphone.png' };
    const deviceImg = _devImages[cfg.pairDevice];
    const isMobile = ['iPhone','iPad','Android'].includes(cfg.pairDevice);
    const deviceVisual = deviceImg
      ? `<img src="${deviceImg}" alt="${cfg.pairDevice}" style="width:140px;height:auto;object-fit:contain">`
      : (isMobile
        ? `<svg viewBox="0 0 24 24" width="64" height="64" fill="none" stroke="var(--accent)" stroke-width="1.2"><rect x="5" y="2" width="14" height="20" rx="3"/><line x1="12" y1="18" x2="12.01" y2="18"/></svg>`
        : `<svg class="icon" width="64" height="64" style="stroke:var(--accent)"><use href="icons.svg#icon-monitor"/></svg>`);
    if (itemsEl) itemsEl.innerHTML = `
      <div style="display:flex;flex-direction:column;align-items:center;padding:4px 0 8px;gap:8px">
        <div style="width:160px;height:160px;border-radius:32px;background:${deviceImg ? 'none' : 'var(--surface-1)'};display:flex;align-items:center;justify-content:center;overflow:hidden">${deviceVisual}</div>
        <div style="text-align:center">
          <div style="font-size:18px;font-weight:700;color:var(--text-primary)">${cfg.pairDevice}</div>
          <div style="font-size:13px;color:var(--text-muted);margin-top:2px">Wants to pair with this device</div>
        </div>
      </div>`;
    if (sizeRow) sizeRow.style.display = 'none';
    descEl.style.display = 'none';
  } else {
    if (sizeRow) sizeRow.style.display = '';
    descEl.style.display = '';

    // Size display
    const bytes = cfg.sizeBytes || 0;
    sizeEl.textContent = bytes > 1048576 ? (bytes / 1048576).toFixed(1) + ' MB' : Math.round(bytes / 1024) + ' KB';
  }

  // Items breakdown (only for non-pair confirms)
  if (!cfg.pairDevice && cfg.showItemBreakdown) {
    const snapshot = _peerBuildSnapshot();
    const keys = Object.keys(snapshot);
    const cats = { gear: 0, batteries: 0, services: 0, goals: 0, settings: 0, strava: 0, other: 0 };
    for (const k of keys) {
      if (k.includes('gear') || k.includes('component') || k.includes('bike')) cats.gear++;
      else if (k.includes('batter')) cats.batteries++;
      else if (k.includes('service') || k.includes('shop')) cats.services++;
      else if (k.includes('goal')) cats.goals++;
      else if (k.startsWith('strava_')) cats.strava++;
      else if (k.includes('setting') || k.includes('range') || k.includes('widget') || k.includes('theme') || k.includes('notif')) cats.settings++;
      else cats.other++;
    }
    const catList = [
      ['Gear & Components', cats.gear, 'var(--accent)'], ['Batteries', cats.batteries, '#f0c429'],
      ['Services & Shops', cats.services, '#5ac8fa'], ['Goals', cats.goals, '#ff9500'],
      ['Settings & Preferences', cats.settings, '#af52de'], ['Strava Data', cats.strava, '#fc4c02'],
      ['Other Data', cats.other, 'var(--text-muted)'],
    ];
    if (itemsEl) itemsEl.innerHTML = catList.filter(([,c]) => c > 0)
      .map(([l, c, col]) => `<div class="ios-row" style="min-height:36px"><span class="ios-row-label">${l}</span><span class="ios-row-detail" style="color:${col};font-weight:600">${c} keys</span></div>`).join('');
  } else if (!cfg.pairDevice) {
    if (itemsEl) itemsEl.innerHTML = `<div class="ios-row" style="min-height:36px"><span class="ios-row-label">Data keys</span><span class="ios-row-detail" style="color:var(--accent);font-weight:600">${cfg.keyCount || '?'}</span></div>`;
  }

  // Approve button
  btnEl.textContent = cfg.btnText;
  btnEl.style.background = cfg.btnColor || 'var(--accent)';
  btnEl.style.color = '#000';
  btnEl.onclick = () => { _closeOverlaySheet('syncConfirmSheet'); cfg.onApprove(); };

  // Decline button (visible for pair requests)
  const declineBtn = document.getElementById('syncDeclineBtn');
  if (declineBtn) {
    declineBtn.style.display = cfg.pairDevice ? '' : 'none';
    declineBtn.onclick = () => { _closeOverlaySheet('syncConfirmSheet'); cfg.onDecline?.(); };
  }

  // Decline on backdrop dismiss
  const overlay = document.getElementById('syncConfirmSheet');
  const backdrop = overlay?.querySelector('.wxd-backdrop');
  const _onClose = () => { cfg.onDecline?.(); backdrop?.removeEventListener('click', _onClose); };
  backdrop?.addEventListener('click', _onClose, { once: true });

  _openOverlaySheet('syncConfirmSheet');
}

function _peerShowIncomingRequest(deviceName, conn) {
  const snapshot = _peerBuildSnapshot();
  _peerShowSyncConfirm({
    title: 'Data Request',
    desc: `${deviceName || 'A device'} is requesting your data. This will send your local data to them.`,
    btnText: 'Approve & Send', btnColor: 'var(--accent)',
    sizeBytes: JSON.stringify(snapshot).length, showItemBreakdown: true,
    onApprove: () => { _peerSendSnapshot(conn); _peerLog('Approved request — sending data'); showToast('Sending data...', 'info'); },
    onDecline: () => { conn.send({ type: 'request_declined', device: _peerDeviceName() }); _peerLog('Declined data request'); },
  });
}

function _peerShowIncomingSendOffer(deviceName, sizeBytes, keyCount, conn) {
  _peerShowSyncConfirm({
    title: 'Incoming Data',
    desc: `${deviceName || 'A device'} wants to send you their data. Your local data will be overwritten.`,
    btnText: 'Accept & Receive', btnColor: '#5ac8fa',
    sizeBytes, keyCount,
    onApprove: () => { conn._receiveApproved = true; conn.send({ type: 'send_accepted', device: _peerDeviceName() }); _peerLog('Accepted incoming data'); showToast('Accepted — waiting for data...', 'info'); },
    onDecline: () => { conn.send({ type: 'send_declined', device: _peerDeviceName() }); _peerLog('Declined incoming data'); },
  });
}

/* ── Clipboard-based transfer (reliable fallback) ── */
async function _clipboardExport() {
  try {
    const snapshot = _peerBuildSnapshot();
    const json = JSON.stringify(snapshot);
    await navigator.clipboard.writeText(json);
    const keys = Object.keys(snapshot).length;
    const sizeKB = Math.round(json.length / 1024);
    showToast(`Copied ${keys} keys (${sizeKB} KB) — paste on other device`, 'success');
  } catch (e) {
    const snapshot = _peerBuildSnapshot();
    const json = JSON.stringify(snapshot);
    const ta = document.createElement('textarea');
    ta.value = json;
    ta.style.cssText = 'position:fixed;left:-9999px';
    document.body.appendChild(ta);
    ta.select();
    document.execCommand('copy');
    document.body.removeChild(ta);
    showToast('Copied to clipboard — paste on other device', 'success');
  }
}
window._clipboardExport = _clipboardExport;

async function _clipboardImport() {
  try {
    const text = await navigator.clipboard.readText();
    if (!text || text.length < 10) { showToast('Clipboard is empty', 'error'); return; }
    let snapshot;
    try { snapshot = JSON.parse(text); } catch { showToast('Clipboard does not contain valid backup data', 'error'); return; }
    if (typeof snapshot !== 'object' || !Object.keys(snapshot).some(k => k.startsWith('icu_'))) {
      showToast('Not a valid CycleIQ backup', 'error');
      return;
    }
    const keys = Object.keys(snapshot).length;
    if (!confirm(`Restore ${keys} settings from clipboard? This will overwrite your current data.`)) return;
    _peerRestoreSnapshot(snapshot);
    showToast(`Restored ${keys} keys — reloading...`, 'success');
    setTimeout(() => location.reload(), 1500);
  } catch (e) {
    const text = prompt('Paste the backup data here:');
    if (!text) return;
    let snapshot;
    try { snapshot = JSON.parse(text); } catch { showToast('Invalid backup data', 'error'); return; }
    if (typeof snapshot !== 'object') { showToast('Not a valid backup', 'error'); return; }
    const keys = Object.keys(snapshot).length;
    _peerRestoreSnapshot(snapshot);
    showToast(`Restored ${keys} keys — reloading...`, 'success');
    setTimeout(() => location.reload(), 1500);
  }
}
window._clipboardImport = _clipboardImport;

/* ── Full Backup Export ── */
// ── Storage info ──
async function _showStorageInfo() {
  const el = document.getElementById('iosStorageSize');

  // localStorage size
  let lsSize = 0;
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    lsSize += (k.length + (localStorage.getItem(k) || '').length) * 2; // UTF-16
  }

  // IndexedDB sizes
  const idbSizes = {};
  const dbNames = ['cycleiq_fit_cache', 'cycleiq_routes', 'cycleiq_workouts', 'icu_activity_cache', 'icu_heatmap_cache', 'icu_strava_cache'];
  for (const name of dbNames) {
    try {
      const db = await new Promise((res, rej) => {
        const req = indexedDB.open(name);
        req.onsuccess = () => res(req.result);
        req.onerror = () => rej();
      });
      let total = 0;
      const storeNames = [...db.objectStoreNames];
      for (const sn of storeNames) {
        try {
          const tx = db.transaction(sn, 'readonly');
          const store = tx.objectStore(sn);
          const count = await new Promise(r => { const req = store.count(); req.onsuccess = () => r(req.result); req.onerror = () => r(0); });
          total += count;
        } catch {}
      }
      idbSizes[name] = { stores: storeNames.length, entries: total };
      db.close();
    } catch {}
  }

  // Storage estimate (if available)
  let estimate = null;
  if (navigator.storage && navigator.storage.estimate) {
    try { estimate = await navigator.storage.estimate(); } catch {}
  }

  const fmt = (bytes) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  // Update the settings row value
  if (el && estimate) {
    el.textContent = fmt(estimate.usage || 0);
  }

  // Build detail toast
  let msg = `localStorage: ${fmt(lsSize)}\n`;
  for (const [name, info] of Object.entries(idbSizes)) {
    const short = name.replace('cycleiq_', '').replace('icu_', '');
    msg += `${short}: ${info.entries} entries\n`;
  }
  if (estimate) {
    msg += `\nTotal used: ${fmt(estimate.usage)}\nQuota: ${fmt(estimate.quota)}`;
  }
  showToast(msg.trim(), 'info', 6000);
}
window._showStorageInfo = _showStorageInfo;

// Update storage size label when settings page loads
function _updateStorageSizeLabel() {
  const el = document.getElementById('iosStorageSize');
  if (!el) return;
  if (navigator.storage && navigator.storage.estimate) {
    navigator.storage.estimate().then(est => {
      const mb = est.usage ? (est.usage / (1024 * 1024)).toFixed(1) : '0';
      el.textContent = mb + ' MB';
    }).catch(() => {});
  }
}

async function exportFullBackup() {
  showToast('Building full backup…', 'info');
  try {
    // 1. localStorage
    const ls = {};
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k.startsWith('icu_') || k.startsWith('strava_')) ls[k] = localStorage.getItem(k);
    }
    // 2. IndexedDB stores
    const [actcache, hmRoutes, hmMeta, strava, routes] = await Promise.all([
      _idbReadAll(_actCacheDB, 'items'),
      _idbReadAll(_hmOpenDB,   'routes'),
      _idbReadAll(_hmOpenDB,   'meta'),
      _idbReadAll(_stravaOpenDB, 'streams'),
      _idbReadAll(_rbOpenDB,   'routes'),
    ]);
    const backup = {
      version: 1,
      exported: new Date().toISOString(),
      localStorage: ls,
      indexedDB: { actcache, heatmap_routes: hmRoutes, heatmap_meta: hmMeta, strava, routes }
    };
    const json = JSON.stringify(backup);
    const blob = new Blob([json], { type: 'application/json' });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href     = url;
    a.download = `cycleiq-backup-${new Date().toISOString().slice(0, 10)}.json`;
    a.click();
    URL.revokeObjectURL(url);
    const sizeMB = (blob.size / (1024 * 1024)).toFixed(1);
    showToast(`Full backup exported (${sizeMB} MB)`, 'success');
  } catch (e) {
    console.error('Full backup export failed:', e);
    showToast('Backup export failed: ' + (e.message || 'unknown error'), 'error');
  }
}

/* ── Full Backup Import ── */
function importFullBackup() {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = '.json';
  input.onchange = e => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async ev => {
      try {
        showToast('Restoring backup…', 'info');
        const backup = JSON.parse(ev.target.result);
        if (!backup.version || !backup.localStorage) {
          showToast('Invalid backup file', 'error'); return;
        }
        // 1. Restore localStorage
        const ls = backup.localStorage;
        for (const k of Object.keys(ls)) localStorage.setItem(k, ls[k]);
        // 2. Restore IndexedDB
        const idb = backup.indexedDB || {};
        await Promise.all([
          idb.actcache       ? _idbWriteAll(_actCacheDB,   'items',        idb.actcache)        : null,
          idb.heatmap_routes ? _idbWriteAll(_hmOpenDB,     'routes',       idb.heatmap_routes)  : null,
          idb.heatmap_meta   ? _idbWriteAll(_hmOpenDB,     'meta',         idb.heatmap_meta)    : null,
          idb.strava         ? _idbWriteAll(_stravaOpenDB, 'streams',      idb.strava, true)    : null,
          idb.routes         ? _idbWriteAll(_rbOpenDB,     'routes',       idb.routes)          : null,
        ]);
        showToast('Backup restored — reloading…', 'success');
        setTimeout(() => location.reload(), 1200);
      } catch (err) {
        console.error('Full backup import failed:', err);
        showToast('Backup import failed: ' + (err.message || 'parse error'), 'error');
      }
    };
    reader.readAsText(file);
  };
  input.click();
}

// Import backup directly from a file input (used by connect modal)
function importBackupFromConnect(inputEl) {
  const file = inputEl?.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = async ev => {
    try {
      showToast('Restoring backup…', 'info');
      const backup = JSON.parse(ev.target.result);
      if (!backup.version || !backup.localStorage) {
        showToast('Invalid backup file', 'error'); return;
      }
      const ls = backup.localStorage;
      for (const k of Object.keys(ls)) localStorage.setItem(k, ls[k]);
      const idb = backup.indexedDB || {};
      await Promise.all([
        idb.actcache       ? _idbWriteAll(_actCacheDB,   'items',        idb.actcache)        : null,
        idb.heatmap_routes ? _idbWriteAll(_hmOpenDB,     'routes',       idb.heatmap_routes)  : null,
        idb.heatmap_meta   ? _idbWriteAll(_hmOpenDB,     'meta',         idb.heatmap_meta)    : null,
        idb.strava         ? _idbWriteAll(_stravaOpenDB, 'streams',      idb.strava, true)    : null,
        idb.routes         ? _idbWriteAll(_rbOpenDB,     'routes',       idb.routes)          : null,
      ]);
      showToast('Backup restored — reloading…', 'success');
      setTimeout(() => location.reload(), 1200);
    } catch (err) {
      console.error('Backup import failed:', err);
      showToast('Import failed: ' + (err.message || 'parse error'), 'error');
    }
  };
  reader.readAsText(file);
  inputEl.value = '';
}
window.importBackupFromConnect = importBackupFromConnect;

/* ── Gear & Settings Export/Import (lightweight) ── */
function exportGearData() {
  const keys = [
    'icu_gear_components', 'icu_gear_batteries', 'icu_gear_services',
    'icu_gear_service_shops', 'icu_bike_photos', 'icu_fav_routes',
    'icu_units', 'icu_theme', 'icu_map_theme', 'icu_app_font',
    'icu_range_days', 'icu_week_start_day', 'icu_goals',
    'icu_dash_sections', 'icu_avatar', 'icu_hide_empty_cards',
  ];
  const data = { version: 2, type: 'gear_settings', exported: new Date().toISOString() };
  for (const k of keys) {
    const v = localStorage.getItem(k);
    if (v != null && v !== '') data[k] = v;
  }
  const json = JSON.stringify(data);
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `cycleiq-gear-${new Date().toISOString().slice(0, 10)}.json`;
  a.click();
  URL.revokeObjectURL(url);
  const sizeKB = (blob.size / 1024).toFixed(0);
  showToast(`Gear & settings exported (${sizeKB} KB)`, 'success');
}

function importGearData() {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = '.json';
  input.onchange = e => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
      try {
        const data = JSON.parse(ev.target.result);
        if (!data.type && !data.version) { showToast('Invalid file', 'error'); return; }
        let count = 0;
        for (const [k, v] of Object.entries(data)) {
          if (k.startsWith('icu_') && typeof v === 'string') {
            localStorage.setItem(k, v);
            count++;
          }
        }
        showToast(`Imported ${count} settings — reloading…`, 'success');
        setTimeout(() => location.reload(), 1200);
      } catch (err) {
        showToast('Import failed: ' + (err.message || 'invalid file'), 'error');
      }
    };
    reader.readAsText(file);
  };
  input.click();
}

/* ====================================================
   NAVIGATION
==================================================== */
// iOS Safari requires position:fixed on body to prevent background scroll
// behind the sidebar (overflow:hidden alone is ignored by Safari).
let _sidebarScrollY = 0;
function _lockBodyScroll(lock) {
  if (lock) {
    _sidebarScrollY = window.scrollY;
    Object.assign(document.body.style, {
      position: 'fixed', top: `-${_sidebarScrollY}px`,
      width: '100%', overflow: 'hidden'
    });
  } else {
    Object.assign(document.body.style, {
      position: '', top: '', width: '', overflow: ''
    });
    window.scrollTo(0, _sidebarScrollY);
  }
}

function toggleSidebar() {
  const sidebar  = document.getElementById('sidebar');
  const backdrop = document.getElementById('sidebarBackdrop');
  const fab      = document.getElementById('floatingMenuBtn');
  const open     = sidebar.classList.toggle('open');
  backdrop.classList.toggle('open', open);
  fab?.classList.toggle('is-open', open);
  _lockBodyScroll(open);
}

function closeSidebar() {
  const sb = document.getElementById('sidebar');
  sb?.classList.remove('open');
  document.getElementById('sidebarBackdrop')?.classList.remove('open');
  document.getElementById('floatingMenuBtn')?.classList.remove('is-open');
  _lockBodyScroll(false);
  // Reset scroll after close transition so it's ready for next open
  if (sb) { const nav = sb.querySelector('.sidebar-nav'); if (nav) setTimeout(() => { nav.scrollTop = 0; }, 350); }
}

// Prevent touchmove on the backdrop — stops iOS from starting a scroll
// context on the empty area that then "steals" scroll from the sidebar.
document.addEventListener('DOMContentLoaded', () => {
  // Lazy settings subpages — safe because subpages are self-contained
  requestAnimationFrame(() => {
    _initSubpageCache();
  });

  // ── iOS-style sticky title: show when large title scrolls out ──
  const _pgHeadline = document.querySelector('.page-headline-title');
  const _stickyBar = document.getElementById('stickyPageTitle');
  if (_pgHeadline && _stickyBar) {
    const _stickyObs = new IntersectionObserver(entries => {
      entries.forEach(e => {
        _stickyBar.classList.toggle('visible', !e.isIntersecting);
      });
    }, { threshold: 0, rootMargin: '-1px 0px 0px 0px' });
    _stickyObs.observe(_pgHeadline);
  }

  const bd = document.getElementById('sidebarBackdrop');
  if (bd) {
    bd.addEventListener('touchmove', e => e.preventDefault(), { passive: false });
  }
  // Pill nav bounce on button tap — Web Animations API runs on the compositor (no reflow)
  const pillNav = document.getElementById('dashPillNav');
  if (pillNav) {
    pillNav.addEventListener('click', function(e) {
      if (e.target.closest('.dash-pill-btn')) {
        pillNav.animate(
          [
            { transform: 'scale(1)' },
            { transform: 'scale(0.96)' },
            { transform: 'scale(1.02)' },
            { transform: 'scale(1)' },
          ],
          { duration: 320, easing: 'cubic-bezier(0.34, 1.56, 0.64, 1)', fill: 'none' }
        );
      }
    });
  }
});

/* ====================================================
   SWIPE TO OPEN / CLOSE SIDEBAR (Mobile)
==================================================== */
const _swipe = {
  startX: 0, startY: 0,
  prevX: 0, prevT: 0,     // velocity tracking
  tracking: false,         // true once we've committed to a horizontal swipe
  direction: '',           // 'open' or 'close'
  wasOpen: false,          // sidebar state when swipe started
  sidebarW: 260,
  edgeZone: 30,            // px from left edge to start an "open" swipe
  directionLocked: false,
  velocity: 0,             // px/ms — positive = rightward
  animating: false         // true while snap animation is in flight
};

function _isMobile() { return window.innerWidth <= 700; }

/* ── helpers ── */
function _swipeCleanup(sidebar, backdrop, shouldOpen) {
  // Only toggle body scroll lock when state actually changes
  const stateChanged = shouldOpen !== _swipe.wasOpen;
  // Set class FIRST (its transform matches the inline one), then clear inline
  if (shouldOpen) {
    sidebar.classList.add('open');
    backdrop?.classList.add('open');
    document.getElementById('burgerBtn')?.classList.add('is-open');
    if (stateChanged) _lockBodyScroll(true);
    const _nav = sidebar.querySelector('.sidebar-nav');
    if (_nav) _nav.scrollTop = 0;
  } else {
    sidebar.classList.remove('open');
    backdrop?.classList.remove('open');
    document.getElementById('burgerBtn')?.classList.remove('is-open');
    if (stateChanged) _lockBodyScroll(false);
  }
  // Clear inline styles — class rules now handle visual state
  sidebar.style.transform = '';
  sidebar.style.pointerEvents = '';
  sidebar.style.transition = '';
  if (backdrop) {
    backdrop.style.opacity = '';
    backdrop.style.visibility = '';
    backdrop.style.pointerEvents = '';
    backdrop.style.transition = '';
  }
  _swipe.animating = false;
}

function _swipeReset() {
  _swipe.tracking = false;
  _swipe.direction = '';
  _swipe.velocity = 0;
  _swipe.directionLocked = false;
}

/* ── touchstart ── */
document.addEventListener('touchstart', (e) => {
  if (!_isMobile() || e.touches.length !== 1 || _swipe.animating) return;
  const x = e.touches[0].clientX;
  const sidebar = document.getElementById('sidebar');
  _swipe.startX = x;
  _swipe.startY = e.touches[0].clientY;
  _swipe.prevX = x;
  _swipe.prevT = e.timeStamp;
  _swipe.tracking = false;
  _swipe.directionLocked = false;
  _swipe.direction = '';
  _swipe.velocity = 0;
  _swipe.sidebarW = (sidebar ? sidebar.offsetWidth : 260) || 260;

  const isOpen = sidebar && sidebar.classList.contains('open');
  _swipe.wasOpen = isOpen;
  if (!isOpen && x <= _swipe.edgeZone) {
    _swipe.direction = 'open';
  } else if (isOpen) {
    _swipe.direction = 'close';
  }
}, false);

/* ── touchmove ── */
document.addEventListener('touchmove', (e) => {
  if (!_swipe.direction || e.touches.length !== 1) return;
  const x = e.touches[0].clientX;
  const y = e.touches[0].clientY;
  const dx = x - _swipe.startX;
  const dy = Math.abs(y - _swipe.startY);

  // Lock direction after small movement — if vertical, abort
  if (!_swipe.directionLocked) {
    if (Math.abs(dx) < 8 && dy < 8) return; // deadzone
    if (dy > Math.abs(dx)) { _swipe.direction = ''; return; } // vertical scroll
    _swipe.directionLocked = true;
    _swipe.tracking = true;
    // Disable sidebar CSS transition while dragging for 1:1 feel
    const sidebar = document.getElementById('sidebar');
    if (sidebar) sidebar.style.transition = 'none';
    const backdrop = document.getElementById('sidebarBackdrop');
    if (backdrop) backdrop.style.transition = 'none';
  }

  if (!_swipe.tracking) return;
  e.preventDefault();

  // Track velocity (exponential moving average for smoothness)
  const dt = e.timeStamp - _swipe.prevT;
  if (dt > 0) {
    const instantV = (x - _swipe.prevX) / dt;
    _swipe.velocity = 0.4 * _swipe.velocity + 0.6 * instantV;
  }
  _swipe.prevX = x;
  _swipe.prevT = e.timeStamp;

  const sidebar = document.getElementById('sidebar');
  const backdrop = document.getElementById('sidebarBackdrop');
  if (!sidebar) return;

  const W = _swipe.sidebarW;
  let offset; // 0 = fully closed, 1 = fully open

  if (_swipe.direction === 'open') {
    offset = Math.max(0, Math.min(1, dx / W));
  } else {
    offset = Math.max(0, Math.min(1, 1 + dx / W));
  }

  sidebar.style.transform = `translateX(${-W + offset * W}px)`;
  sidebar.style.pointerEvents = 'auto';

  if (backdrop) {
    backdrop.style.opacity = offset * 0.55;
    backdrop.style.visibility = offset > 0 ? 'visible' : 'hidden';
    backdrop.style.pointerEvents = offset > 0.1 ? 'auto' : 'none';
  }
}, { passive: false });

/* ── touchend ── */
document.addEventListener('touchend', (e) => {
  if (!_swipe.tracking) { _swipe.direction = ''; return; }

  const sidebar = document.getElementById('sidebar');
  const backdrop = document.getElementById('sidebarBackdrop');
  if (!sidebar) { _swipeReset(); return; }

  const W = _swipe.sidebarW;
  const x = e.changedTouches[0].clientX;
  const dx = x - _swipe.startX;

  let offset;
  if (_swipe.direction === 'open') {
    offset = Math.max(0, Math.min(1, dx / W));
  } else {
    offset = Math.max(0, Math.min(1, 1 + dx / W));
  }

  // Decide snap direction — velocity wins for genuine quick flicks only
  const VELOCITY_THRESHOLD = 0.55; // px/ms — must be a fast flick
  const MIN_FLICK_DIST = 0.15;     // must have dragged at least 15% of sidebar width
  let shouldOpen;
  if (Math.abs(_swipe.velocity) > VELOCITY_THRESHOLD && offset > MIN_FLICK_DIST && offset < (1 - MIN_FLICK_DIST)) {
    shouldOpen = _swipe.velocity > 0; // right = open, left = close
  } else {
    shouldOpen = offset > 0.35;
  }

  const targetX = shouldOpen ? 0 : -W;

  // If already at target (tiny drag that didn't move), skip animation
  const currentX = -W + offset * W;
  if (Math.abs(currentX - targetX) < 2) {
    _swipeCleanup(sidebar, backdrop, shouldOpen);
    _swipeReset();
    return;
  }

  // Animate to final position — set transition, then set target transform
  _swipe.animating = true;
  sidebar.style.transition = 'transform 0.25s cubic-bezier(0.2, 0, 0, 1)';
  if (backdrop) backdrop.style.transition = 'opacity 0.25s ease, visibility 0.25s';

  sidebar.style.transform = `translateX(${targetX}px)`;
  sidebar.style.pointerEvents = shouldOpen ? 'auto' : '';
  if (backdrop) {
    backdrop.style.opacity = shouldOpen ? '0.55' : '0';
    backdrop.style.visibility = shouldOpen ? 'visible' : 'hidden';
    backdrop.style.pointerEvents = shouldOpen ? 'auto' : 'none';
  }

  // After transition completes, swap inline styles for CSS classes
  const onEnd = (ev) => {
    if (ev.propertyName !== 'transform') return;
    sidebar.removeEventListener('transitionend', onEnd);
    clearTimeout(fallback);
    _swipeCleanup(sidebar, backdrop, shouldOpen);
  };
  sidebar.addEventListener('transitionend', onEnd);
  const fallback = setTimeout(() => {
    sidebar.removeEventListener('transitionend', onEnd);
    _swipeCleanup(sidebar, backdrop, shouldOpen);
  }, 300);

  _swipeReset();
}, false);

/* ── touchcancel — clean up if touch is interrupted ── */
document.addEventListener('touchcancel', () => {
  if (!_swipe.tracking) { _swipe.direction = ''; return; }
  const sidebar = document.getElementById('sidebar');
  const backdrop = document.getElementById('sidebarBackdrop');
  if (sidebar) {
    sidebar.style.transition = '';
    sidebar.style.transform = '';
    sidebar.style.pointerEvents = '';
  }
  if (backdrop) {
    backdrop.style.transition = '';
    backdrop.style.opacity = '';
    backdrop.style.visibility = '';
    backdrop.style.pointerEvents = '';
  }
  _swipeReset();
}, false);

/* ── Disable pinch-to-zoom everywhere EXCEPT Leaflet maps ── */
function _isOnMap(e) {
  return e.target && e.target.closest && e.target.closest('.leaflet-container');
}

// 1) Block multi-touch — capture phase on window, fires before everything
window.addEventListener('touchstart', function(e) {
  if (e.touches.length > 1 && !_isOnMap(e)) e.preventDefault();
}, { passive: false, capture: true });

window.addEventListener('touchmove', function(e) {
  if (e.touches.length > 1 && !_isOnMap(e)) e.preventDefault();
}, { passive: false, capture: true });

// 2) Safari proprietary gesture events
['gesturestart', 'gesturechange', 'gestureend'].forEach(function(evt) {
  window.addEventListener(evt, function(e) {
    if (!_isOnMap(e)) e.preventDefault();
  }, { passive: false, capture: true });
});

// 3) Strip inline touch-action on canvas elements (Chart.js sets these)
(function() {
  const mo = new MutationObserver(function(mutations) {
    for (const m of mutations) {
      if (m.type !== 'attributes' || m.attributeName !== 'style') continue;
      const el = m.target;
      if (el.tagName !== 'CANVAS') continue;
      const ta = el.style.touchAction;
      if (ta && ta !== 'pan-x pan-y') el.style.touchAction = 'pan-x pan-y';
    }
  });
  mo.observe(document.getElementById('pageContent') || document.body, { attributes: true, attributeFilter: ['style'], subtree: true });
})();

// 4) Last resort: if iOS Safari still zooms, snap viewport scale back to 1
if (window.visualViewport) {
  window.visualViewport.addEventListener('resize', function() {
    if (window.visualViewport.scale > 1.01) {
      document.body.style.zoom = (1 / window.visualViewport.scale);
      requestAnimationFrame(function() {
        document.body.style.zoom = '';
      });
    }
  });
}

function navigate(page, opts) {
  // Redirect zones to power page with zones tab
  if (page === 'zones') { navigate('power'); setTimeout(() => _switchPwrTab('zones'), 50); return; }
  if (opts?.settingsSubpage) window._pendingSettingsSubpage = opts.settingsSubpage;
  // Route Builder: confirm before leaving if there's an unsaved route
  if (state.currentPage === 'routes' && page !== 'routes' && window._rb && window._rb.waypoints && window._rb.waypoints.length > 0) {
    _rbConfirmLeave(page);
    return;
  }

  // Exit fullscreen mode if leaving route builder
  document.body.classList.remove('rb-fullscreen');

  // Abort any in-flight API requests from the previous page
  _navAbort?.abort();
  _navAbort = new AbortController();

  // Detect returning to activities list from activity detail (to restore scroll)
  const _restoreActScroll = (page === 'activities' && state.currentPage === 'activity' && window._actListScrollRestore);

  // Reset scroll position (skip when returning to activities — restored below)
  if (!_restoreActScroll) window.scrollTo(0, 0);

  // Close any open dialogs when navigating away
  document.querySelectorAll('dialog[open]').forEach(d => closeModalAnimated(d));

  // Clean up charts from the page we're leaving to free memory
  try { if (state.currentPage) cleanupPageCharts(state.currentPage); } catch(e) { console.warn('Chart cleanup error:', e); }

  // Strip dynamic DOM from heavy pages to reduce node count
  try { _cleanupPageDOM(state.currentPage); } catch(e) { console.warn('DOM cleanup error:', e); }

  // Clear any pending debounce timers from the page we're leaving
  clearTimeout(_wxSearchTimer);
  clearTimeout(_actSearchDebounce);
  clearTimeout(_h2hDebounce);

  // Clear page gradient when leaving weather, dashboard, or goals
  if ((state.currentPage === 'weather' || state.currentPage === 'dashboard' || state.currentPage === 'goals') && page !== state.currentPage) {
    const _pc = document.getElementById('pageContent');
    if (_pc) _pc.style.background = '';
    document.body.classList.remove('goals-bg');
  }
  // Add dark gradient on goals page
  if (page === 'goals') document.body.classList.add('goals-bg');

  // Clear scroll restore if navigating anywhere other than activities→activity round-trip
  if (!_restoreActScroll) window._actListScrollRestore = null;

  state.previousPage = state.currentPage;
  state.currentPage  = page;
  try { sessionStorage.setItem('icu_route', JSON.stringify({ type: 'page', page })); } catch {}

  // Hide save-route FAB when leaving activity page
  document.body.classList.remove('show-save-fab');

  // Update pill nav active state + visibility (use visibility to keep backdrop-filter warm)
  const _pillNav = document.getElementById('dashPillNav');
  const _pillHidePages = new Set(['settings', 'routes', 'workout', 'activity', 'heatmap', 'suggestion', 'bikedetail', 'weather']);
  if (_pillNav) {
    const hide = _pillHidePages.has(page);
    _pillNav.style.visibility = hide ? 'hidden' : '';
    _pillNav.style.pointerEvents = hide ? 'none' : '';
  }

  // Show/hide global FABs based on current page (visibility to keep backdrop-filter warm)
  const _calFab = document.getElementById('calFab');
  const _actFab = document.getElementById('actSearchFab');
  const _dashFab = document.getElementById('dashRouteFab');
  const _saveRouteFab = document.getElementById('actSaveRouteFab');
  const _proFab = document.getElementById('actProFab');
  if (_calFab)  { _calFab.style.visibility  = page === 'calendar'   ? '' : 'hidden'; _calFab.style.pointerEvents  = page === 'calendar'   ? '' : 'none'; }
  if (_proFab) { const showPro = page === 'activity' && window.innerWidth >= 900; _proFab.style.visibility = showPro ? '' : 'hidden'; _proFab.style.pointerEvents = showPro ? '' : 'none'; }
  if (_actFab)  { _actFab.style.visibility  = page === 'activities' ? '' : 'hidden'; _actFab.style.pointerEvents  = page === 'activities' ? '' : 'none'; }
  if (_dashFab) { _dashFab.style.visibility = page === 'dashboard'  ? '' : 'hidden'; _dashFab.style.pointerEvents = page === 'dashboard'  ? '' : 'none'; }
  const _actBackFab = document.getElementById('actBackFab');
  if (_actBackFab) { _actBackFab.style.visibility = page === 'activity' ? '' : 'hidden'; _actBackFab.style.pointerEvents = page === 'activity' ? '' : 'none'; }
  const _sgnFab = document.getElementById('sgnBackFab');
  if (_sgnFab) { _sgnFab.style.visibility = page === 'suggestion' ? '' : 'hidden'; _sgnFab.style.pointerEvents = page === 'suggestion' ? '' : 'none'; }
  const _bikeFab = document.getElementById('bikeBackFab');
  if (_bikeFab) { _bikeFab.style.visibility = page === 'bikedetail' ? '' : 'hidden'; _bikeFab.style.pointerEvents = page === 'bikedetail' ? '' : 'none'; }
  if (page !== 'bikedetail') _bkdHidePill();
  const _settFab = document.getElementById('settingsBackFab');
  if (_settFab) { _settFab.style.visibility = page === 'settings' ? '' : 'hidden'; _settFab.style.pointerEvents = page === 'settings' ? '' : 'none'; }
  const _settSearch = document.getElementById('settingsSearchFab');
  if (_settSearch) { _settSearch.style.visibility = page === 'settings' ? '' : 'hidden'; _settSearch.style.pointerEvents = page === 'settings' ? '' : 'none'; }
  const _mrAddFab = document.getElementById('mrAddFab');
  if (_mrAddFab) { _mrAddFab.style.visibility = page === 'myroutes' ? '' : 'hidden'; _mrAddFab.style.pointerEvents = page === 'myroutes' ? '' : 'none'; }
  const _wxBackFab = document.getElementById('weatherBackFab');
  const _wxAddFab  = document.getElementById('weatherAddFab');
  if (_wxBackFab) { _wxBackFab.style.visibility = page === 'weather' ? '' : 'hidden'; _wxBackFab.style.pointerEvents = page === 'weather' ? '' : 'none'; }
  if (_wxAddFab)  { _wxAddFab.style.visibility  = page === 'weather' ? '' : 'hidden'; _wxAddFab.style.pointerEvents  = page === 'weather' ? '' : 'none'; }
  document.querySelectorAll('.dash-pill-btn').forEach(btn => {
    const lbl = btn.querySelector('span')?.textContent?.toLowerCase() || '';
    const match = lbl === page || (lbl === 'home' && page === 'dashboard');
    btn.classList.toggle('active', match);
  });

  // ── Prepare page-specific UI BEFORE the swap so nothing flashes ──
  const info = {
    dashboard:  ['Summary', ''],
    activities: ['Activities',     ''],
    calendar:   ['Calendar',       'Planned workouts & events'],
    fitness:    ['Fitness',        'Training load, history & guide'],
    power:      ['Power Curve',    'Best efforts across durations'],
    zones:      ['Training Zones', 'Time in zone breakdown'],
    compare:    ['Compare',        'Compare metrics across time periods'],
    heatmap:    ['Heat Map',       'All your rides on one map'],
    import:     ['Import',         'Upload .FIT files from Garmin, Wahoo & more'],
    goals:      ['Goals & Streaks', 'Training targets, streaks & lifetime stats'],
    weather:    ['Weather',        'Weekly forecast & riding conditions'],
    settings:   ['Settings',       'Account & connection'],
    workout:    ['Workout Builder', 'Build & export custom cycling workouts'],
    guide:      ['Training Guide', 'Understanding CTL · ATL · TSB & training load'],
    gear:       ['My Garage', 'Your bicycle fleet & maintenance'],
    routes:     ['Route Builder',  'Plan & build cycling routes'],
    myroutes:   ['Library',       'Routes, rides & workouts'],
    suggestion: ['Suggested Workout', ''],
    bikedetail: ['', ''],
  };
  const [title, sub] = info[page] || ['CycleIQ', ''];
  document.getElementById('pageTitle').textContent    = title;
  document.getElementById('pageSubtitle').textContent = sub;

  // Sync sticky page title (settings only)
  const _stickyTitle = document.getElementById('stickyPageTitleText');
  if (_stickyTitle) _stickyTitle.textContent = title;
  const _stickyBar = document.getElementById('stickyPageTitle');
  if (_stickyBar) {
    _stickyBar.classList.remove('visible');
    _stickyBar.classList.toggle('sticky-page-title--settings', page === 'settings');
  }

  // Headline — hidden for calendar & routes
  const headline = document.querySelector('.page-headline');
  if (headline) {
    if (page === 'calendar' || page === 'routes') headline.classList.add('page-headline--hidden');
    else headline.classList.remove('page-headline--hidden');
  }

  // Full-bleed pages — toggle padding-less mode
  const pc = document.getElementById('pageContent');
  if (pc) {
    pc.classList.toggle('page-content--calendar', page === 'calendar');
    pc.classList.toggle('page-content--heatmap', page === 'heatmap' || page === 'library');
    pc.classList.toggle('page-content--routes', page === 'routes');
    pc.classList.toggle('page-content--has-pill', page === 'dashboard' || page === 'power' || page === 'fitness');
  }

  // Floating top row (profile icon) — show on dashboard only (mobile)
  const floatingTopRow = document.getElementById('floatingTopRow');
  if (floatingTopRow) {
    floatingTopRow.style.display = (page === 'dashboard' || page === 'power' || page === 'fitness') ? 'flex' : 'none';
  }

  // Notification bell (dashboard only)
  const notifBell = document.getElementById('notifBell');
  if (notifBell) {
    notifBell.style.display = (page === 'dashboard') ? 'flex' : 'none';
    if (page === 'dashboard') _notifRefreshBell();
  }
  // P2P icon: show on dashboard if P2P is enabled
  const p2pBtn = document.getElementById('p2pStatusBtn');
  if (p2pBtn) {
    const p2pOn = localStorage.getItem('icu_p2p_enabled') === 'true';
    p2pBtn.style.display = (page === 'dashboard' && p2pOn) ? 'flex' : 'none';
  }

  // Dashboard top fade gradient — visible only on dashboard, fades in on scroll
  const dashFade = document.getElementById('dashTopFade');
  if (dashFade) {
    dashFade.style.display = (page === 'dashboard') ? '' : 'none';
    dashFade.style.opacity = '0';
  }

  // Floating range pill visibility — not on dashboard (bell replaces it)
  const pill = document.getElementById('dateRangePill');
  if (pill) {
    pill.style.display = 'none';
    if (page === 'dashboard') {
      const activeBtn = pill.querySelector('button.active');
      if (activeBtn) requestAnimationFrame(() => activeBtn.scrollIntoView({ inline: 'center', block: 'nearest', behavior: 'instant' }));
    }
  }
  const zonePill = document.getElementById('zoneRangePill');
  if (zonePill) {
    zonePill.style.display = (page === 'zones') ? 'flex' : 'none';
    if (page === 'zones') {
      const ab = zonePill.querySelector('button.active');
      if (ab) requestAnimationFrame(() => ab.scrollIntoView({ inline: 'center', block: 'nearest', behavior: 'instant' }));
    }
  }
  const pwrPill = document.getElementById('pwrRangePillTopbar');
  if (pwrPill) {
    pwrPill.style.display = (page === 'power') ? 'flex' : 'none';
    if (page === 'power') {
      const ab = pwrPill.querySelector('button.active');
      if (ab) requestAnimationFrame(() => ab.scrollIntoView({ inline: 'center', block: 'nearest', behavior: 'instant' }));
    }
  }
  const fitPill = document.getElementById('fitRangePillFloat');
  if (fitPill) {
    fitPill.style.display = (page === 'fitness') ? 'flex' : 'none';
    if (page === 'fitness') {
      const ab = fitPill.querySelector('button.active');
      if (ab) requestAnimationFrame(() => ab.scrollIntoView({ inline: 'center', block: 'nearest', behavior: 'instant' }));
    }
  }
  // Toggle scroll edge gradient for pages with floating pills (dashboard uses its own scroll-triggered fade)
  const _pillPages = ['power', 'fitness'];
  document.getElementById('pageContent')?.classList.toggle('has-scroll-edge', _pillPages.includes(page));

  // Swap active page — use View Transitions API for smooth cross-fade if available
  const _swapPage = () => {
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    document.getElementById('page-' + page)?.classList.add('active');
    document.querySelector(`[data-page="${page}"]`)?.classList.add('active');
  };
  const _skipTransition = page === 'calendar' || page === 'routes' || state.previousPage === 'calendar' || state.previousPage === 'routes';
  if (document.startViewTransition && state.previousPage && state.previousPage !== page && !_skipTransition) {
    document.startViewTransition(_swapPage);
  } else {
    _swapPage();
  }

  if (page === 'dashboard') { applyDashSectionVisibility(); }
  // Desktop settings scroll lock
  const _pc = document.getElementById('pageContent');
  if (_pc) _pc.classList.toggle('stt-desktop-lock', page === 'settings' && _isDesktopSettings());

  if (page === 'settings') {
    _initSubpageCache(); // lazy-strip all subpage DOM on first visit
    renderDashSectionToggles(); renderActSectionToggles();
    _updateStorageSizeLabel();
    _updateNotifSummary();
    _updateConnSummary();
    if (window._pendingSettingsSubpage) {
      const _psub = window._pendingSettingsSubpage;
      window._pendingSettingsSubpage = null;
      setTimeout(() => { _iosNavLocked = false; openSettingsSubpage(_psub); }, 350);
    }
  }

  if (page === 'dashboard' && state.synced) {
    const rail = document.getElementById('recentActScrollRail');
    if (rail) rail.scrollLeft = 0;
    renderDashboard();
    // Fire push notification for critical alerts (max 1 per session)
    setTimeout(_notifFirePush, 2000);
  }
  if (page === 'calendar') { renderCalendar(); refreshCalendarEvents(); }
  if (page === 'fitness')  { renderFitnessPage(); _renderGuideInline(); }
  if (page === 'power')    renderPowerPage();
  if (page === 'compare')  { ensureLifetimeLoaded(); renderComparePage(); }
  // Redirect old pages to library
  if (page === 'heatmap' || page === 'myroutes') { navigate('library'); return; }
  if (page === 'library')  { ensureLifetimeLoaded(); _renderLibraryPage(); }
  if (page === 'goals')    { renderStreaksPage(); renderGoalsPage(); }
  if (page === 'workout')  { _wrkRenderHome(); document.getElementById('pageContent')?.classList.add('wrk-snap'); }
  else document.getElementById('pageContent')?.classList.remove('wrk-snap');
  if (page === 'suggestion') renderSuggestionPage();
  if (page === 'bikedetail') renderBikeDetailPage();
  if (page === 'settings') {
    iosSettingsInit();
    initWeatherLocationUI();
    initMapThemePicker();
    icuRenderSyncUI();
    stravaRenderSyncUI();
    updateStorageBar();
    updateLifetimeCacheUI();
    offlineSyncInitUI();
    pollRestore();
    rlUpdateUI();
    _rlStartTick();
    if (window._lbInit) _lbInit();
  } else {
    _rlStopTick();
  }
  if (page === 'activities') {
    ensureLifetimeLoaded();
    if (state.synced) renderAllActivitiesList();
    requestAnimationFrame(_updateActStickyTop);
    const tb = document.querySelector('#page-activities .acts-toolbar');
    if (tb) tb.classList.remove('acts-toolbar--hidden');
    _actScroll.lastY = window.scrollY;
  }
  if (page === 'weather')  renderWeatherPage();
  if (page === 'gear')     renderGearPage();
  if (page === 'service')  renderServicePage();
  if (page === 'guide')    { navigate('fitness'); return; } // merged into fitness
  if (page === 'import')   { initImportPage(); }
  if (page === 'routes')   renderRouteBuilderPage();
  // Legacy: redirect old streaks/wellness routes to merged goals page
  if (page === 'wellness' || page === 'streaks') { navigate('goals'); return; }

  // Upgrade all native selects to custom dropdowns
  requestAnimationFrame(() => initCustomDropdowns());
  _rIC(() => { if (window.refreshGlow) refreshGlow(); if (window.refreshBadgeTilt) refreshBadgeTilt(); });

  // Restore scroll position when returning to activities from activity detail
  if (_restoreActScroll) {
    const _r = window._actListScrollRestore;
    window._actListScrollRestore = null;
    // Ensure enough rows are loaded to cover the previous scroll depth
    const _ls = window._actListState?.allActivityList;
    if (_ls && _ls.cursor < _r.cursor) {
      while (_ls.cursor < _r.cursor && _ls.cursor < _ls.filtered.length) {
        _actListLoadMore('allActivityList');
      }
    }
    requestAnimationFrame(() => {
      // Restore scroll, then ensure the clicked row is visible
      window.scrollTo(0, _r.scrollY);
      if (_r.actId) {
        const row = document.querySelector(`.activity-row[data-act-id="${_r.actId}"]`);
        if (row) {
          // If row drifted out of view, scroll it into center
          const rect = row.getBoundingClientRect();
          if (rect.top < 0 || rect.bottom > window.innerHeight) {
            row.scrollIntoView({ block: 'center' });
          }
          row.classList.add('act-row--highlight');
          setTimeout(() => row.classList.remove('act-row--highlight'), 2500);
        }
      }
    });
  } else {
    window.scrollTo(0, 0);
    requestAnimationFrame(() => window.scrollTo(0, 0));
  }
}

/* ====================================================
   UNITS  (metric / imperial)
==================================================== */
function loadUnits() {
  state.units = localStorage.getItem('icu_units') || 'metric';
}

/* ── Weather location (manual city setting) ─────────────────────────────── */
let _wxSearchTimer = null;
function _initWxAutocomplete() {
  const input = document.getElementById('wxCityInput');
  if (!input || input._wxAcInit) return;
  input._wxAcInit = true;
  input.addEventListener('input', () => {
    clearTimeout(_wxSearchTimer);
    const q = (input.value || '').trim();
    if (q.length < 2) { _hideWxSuggestions(); return; }
    _wxSearchTimer = setTimeout(() => _fetchWxSuggestions(q), 300);
  });
  input.addEventListener('keydown', e => {
    if (e.key === 'Escape') _hideWxSuggestions();
  });
  document.addEventListener('click', e => {
    if (!e.target.closest('.wx-search-wrap')) _hideWxSuggestions();
  });
}
async function _fetchWxSuggestions(query) {
  const box = document.getElementById('wxSuggestions');
  if (!box) return;
  try {
    const res = await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query)}&count=5&language=en&format=json`);
    if (!res.ok) return;
    const data = await res.json();
    if (!data.results?.length) { box.innerHTML = '<div class="wx-sug-empty">No results</div>'; box.classList.add('active'); return; }
    box.innerHTML = data.results.map(r => {
      const label = [r.name, r.admin1, r.country].filter(Boolean).join(', ');
      return `<button class="wx-sug-item" data-lat="${r.latitude}" data-lng="${r.longitude}" data-label="${label.replace(/"/g, '&quot;')}">${label}</button>`;
    }).join('');
    box.classList.add('active');
    box.querySelectorAll('.wx-sug-item').forEach(btn => {
      btn.addEventListener('click', () => _selectWxSuggestion(btn));
    });
  } catch (_) {}
}
function _selectWxSuggestion(btn) {
  const lat = parseFloat(btn.dataset.lat);
  const lng = parseFloat(btn.dataset.lng);
  const label = btn.dataset.label;
  addWxLocation(lat, lng, label);
  const statusEl = document.getElementById('wxCurrentLocation');
  if (statusEl) statusEl.textContent = `${getWxLocations().length} / ${WX_MAX_LOCATIONS} locations`;
  const input = document.getElementById('wxCityInput');
  if (input) input.value = '';
  _hideWxSuggestions();
}
function _hideWxSuggestions() {
  const box = document.getElementById('wxSuggestions');
  if (box) { box.classList.remove('active'); box.innerHTML = ''; }
}


async function useMyLocation() {
  const statusEl = document.getElementById('wxCurrentLocation');
  if (statusEl) statusEl.textContent = 'Locating…';

  let lat, lng;

  // Try browser geolocation first
  if (navigator.geolocation) {
    try {
      const pos = await new Promise((resolve, reject) =>
        navigator.geolocation.getCurrentPosition(resolve, reject, {
          enableHighAccuracy: false, timeout: 10000, maximumAge: 300000
        })
      );
      lat = pos.coords.latitude;
      lng = pos.coords.longitude;
    } catch (_) { /* fall through to IP fallback */ }
  }

  // Fallback: IP-based geolocation (try multiple services)
  if (lat == null) {
    const ipServices = [
      {
        url: 'https://get.geojs.io/v1/ip/geo.json',
        parse: d => ({ lat: parseFloat(d.latitude), lng: parseFloat(d.longitude), city: d.city, country: d.country })
      },
      {
        url: 'https://ipapi.co/json/',
        parse: d => ({ lat: d.latitude, lng: d.longitude, city: d.city, country: d.country_name })
      },
      {
        url: 'https://ip-api.com/json/?fields=lat,lon,city,country',
        parse: d => ({ lat: d.lat, lng: d.lon, city: d.city, country: d.country })
      },
    ];
    for (const svc of ipServices) {
      try {
        const res = await fetch(svc.url);
        if (!res.ok) continue;
        const raw = await res.json();
        const d = svc.parse(raw);
        if (d.lat && d.lng && !isNaN(d.lat)) {
          const cityName = [d.city, d.country].filter(Boolean).join(', ') || `${d.lat.toFixed(2)}, ${d.lng.toFixed(2)}`;
          _applyWeatherLocation(d.lat, d.lng, cityName, statusEl);
          return;
        }
      } catch (_) { continue; }
    }
  }

  if (lat == null) {
    if (statusEl) statusEl.textContent = 'Not set';
    showToast('Could not determine location — try entering a city manually', 'error');
    return;
  }

  // Reverse-geocode via Nominatim for browser geolocation result
  let cityName = `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  try {
    const res = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&zoom=10`);
    if (res.ok) {
      const data = await res.json();
      const addr = data.address || {};
      const city = addr.city || addr.town || addr.village || addr.municipality || '';
      const country = addr.country || '';
      if (city) cityName = [city, country].filter(Boolean).join(', ');
    }
  } catch (_) {}

  _applyWeatherLocation(lat, lng, cityName, statusEl);
}

/* ── Multi-location weather (max 5) ──────────────────────────────── */
const WX_MAX_LOCATIONS = 5;

function getWxLocations() {
  try {
    const raw = localStorage.getItem('icu_wx_locations');
    if (raw) { const arr = JSON.parse(raw); if (Array.isArray(arr)) return arr; }
  } catch (_) {}
  // Migrate legacy single location
  try {
    const legacy = localStorage.getItem('icu_wx_coords');
    if (legacy) {
      const c = JSON.parse(legacy);
      const loc = { id: Date.now(), lat: c.lat, lng: c.lng, city: c.city || 'Unknown', active: true };
      saveWxLocations([loc]);
      return [loc];
    }
  } catch (_) {}
  return [];
}

function saveWxLocations(locs) {
  try {
    localStorage.setItem('icu_wx_locations', JSON.stringify(locs));
    // Keep icu_wx_coords in sync with the active location (backward compat)
    const active = locs.find(l => l.active);
    if (active) {
      localStorage.setItem('icu_wx_coords', JSON.stringify({ lat: active.lat, lng: active.lng, city: active.city }));
    } else {
      localStorage.removeItem('icu_wx_coords');
    }
  } catch (e) { console.warn('localStorage.setItem failed (wx locations):', e); }
}

function getActiveWxLocation() {
  const locs = getWxLocations();
  return locs.find(l => l.active) || locs[0] || null;
}

function setActiveWxLocation(id) {
  const locs = getWxLocations();
  locs.forEach(l => l.active = (l.id === id));
  saveWxLocations(locs);
  // Clear forecast cache so it refetches for new location
  localStorage.removeItem('icu_wx_forecast');
  localStorage.removeItem('icu_wx_forecast_ts');
  localStorage.removeItem('icu_wx_page');
  localStorage.removeItem('icu_wx_page_ts');
  if (state.currentPage === 'weather') {
    renderWeatherPage(window.scrollY);
  }
  if (state.currentPage === 'dashboard') renderWeatherForecast();
  _refreshWxLocSettings();
}

function addWxLocation(lat, lng, city) {
  const locs = getWxLocations();
  // Prevent duplicates (same city name or very close coordinates)
  const dup = locs.find(l => l.city === city || (Math.abs(l.lat - lat) < 0.05 && Math.abs(l.lng - lng) < 0.05));
  if (dup) {
    // Just activate the existing one
    setActiveWxLocation(dup.id);
    showToast(`Switched to ${city}`, 'success');
    return;
  }
  if (locs.length >= WX_MAX_LOCATIONS) {
    showToast(`Maximum ${WX_MAX_LOCATIONS} locations — remove one first`, 'error');
    return;
  }
  locs.forEach(l => l.active = false);
  locs.push({ id: Date.now(), lat, lng, city, active: true });
  saveWxLocations(locs);
  localStorage.removeItem('icu_wx_forecast');
  localStorage.removeItem('icu_wx_forecast_ts');
  localStorage.removeItem('icu_wx_page');
  localStorage.removeItem('icu_wx_page_ts');
  showToast(`Added ${city}`, 'success');
  if (state.currentPage === 'weather') renderWeatherPage();
  if (state.currentPage === 'dashboard') renderWeatherForecast();
  _refreshWxLocSettings();
}

function removeWxLocation(id) {
  let locs = getWxLocations();
  const removing = locs.find(l => l.id === id);
  locs = locs.filter(l => l.id !== id);
  // If we removed the active one, activate the first remaining
  if (removing?.active && locs.length) locs[0].active = true;
  saveWxLocations(locs);
  localStorage.removeItem('icu_wx_forecast');
  localStorage.removeItem('icu_wx_forecast_ts');
  localStorage.removeItem('icu_wx_page');
  localStorage.removeItem('icu_wx_page_ts');
  showToast(`Removed ${removing?.city || 'location'}`, 'info');
  if (state.currentPage === 'weather') renderWeatherPage();
  if (state.currentPage === 'dashboard') renderWeatherForecast();
  _refreshWxLocSettings();
}

function _applyWeatherLocation(lat, lng, cityName, statusEl) {
  addWxLocation(lat, lng, cityName);
  if (statusEl) statusEl.textContent = cityName;
}

function clearWeatherLocation() {
  localStorage.removeItem('icu_wx_coords');
  localStorage.removeItem('icu_wx_locations');
  localStorage.removeItem('icu_wx_forecast');
  localStorage.removeItem('icu_wx_forecast_ts');
  localStorage.removeItem('icu_wx_page');
  localStorage.removeItem('icu_wx_page_ts');
  const statusEl = document.getElementById('wxCurrentLocation');
  if (statusEl) statusEl.textContent = 'Not set';
  const fSec = document.getElementById('forecastSection');
  if (fSec) fSec.style.display = 'none';
  const fCard = document.getElementById('forecastCard');
  if (fCard) fCard.style.display = 'none';
  _refreshWxLocSettings();
}

function _refreshWxLocSettings() {
  _initWxAutocomplete();
  const list = document.getElementById('wxLocationsList');
  if (!list) return;
  const locs = getWxLocations();
  if (!locs.length) {
    list.innerHTML = '<div class="ios-row"><span class="ios-row-label" style="color:var(--text-muted)">No locations added</span></div>';
    return;
  }
  list.innerHTML = locs.map(l => `
    <div class="ios-row" onclick="setActiveWxLocation(${l.id})" style="cursor:pointer">
      <span class="wx-loc-dot${l.active ? ' wx-loc-dot--on' : ''}"></span>
      <span class="ios-row-label">${l.city}</span>
      <button class="wx-loc-remove btn btn-ghost btn-sm" onclick="event.stopPropagation();removeWxLocation(${l.id})" title="Remove">
        <svg class="icon" width="14" height="14" style="stroke:var(--text-muted)"><use href="icons.svg#icon-x"/></svg>
      </button>
    </div>
  `).join('');
  // Update the status label
  const statusEl = document.getElementById('wxCurrentLocation');
  if (statusEl) statusEl.textContent = `${locs.length} / ${WX_MAX_LOCATIONS} locations`;
}

function renderWxLocationSwitcher() {
  const locs = getWxLocations();
  if (locs.length === 0) return '';
  let wxCodes = {};
  try { wxCodes = JSON.parse(localStorage.getItem('icu_wx_today_codes') || '{}'); } catch (_) {}
  return `
    <div class="wx-loc-switcher">
      ${locs.map(l => {
        const code = wxCodes[l.id];
        const icon = code != null
          ? `<span class="wx-pill-icon">${wmoIcon(code)}</span>`
          : `<svg class="icon" width="12" height="12"><use href="icons.svg#icon-map-pin"/></svg>`;
        return `<button class="wx-loc-pill${l.active ? ' wx-loc-pill--active' : ''}" onclick="setActiveWxLocation(${l.id})">
          ${icon}
          ${l.city}
        </button>`;
      }).join('')}
      <button class="wx-loc-pill wx-loc-pill--add" onclick="navigate('settings')" title="Add location">
        <svg class="icon" width="14" height="14"><use href="icons.svg#icon-plus"/></svg>
      </button>
    </div>`;
}

function initWeatherLocationUI() {
  const statusEl = document.getElementById('wxCurrentLocation');
  if (!statusEl) return;
  const active = getActiveWxLocation();
  if (active) {
    statusEl.textContent = active.city || `${active.lat?.toFixed(2)}, ${active.lng?.toFixed(2)}`;
  }
  _refreshWxLocSettings();
  // Restore saved model selection
  const sel = document.getElementById('wxModelSelect');
  if (sel) sel.value = localStorage.getItem('icu_wx_model') || 'best_match';

  // Restore hide-empty-cards toggle
  const hideToggle = document.getElementById('hideEmptyCardsToggle');
  if (hideToggle) hideToggle.checked = localStorage.getItem('icu_hide_empty_cards') === 'true';

  // Restore FTP alert toggle
  const ftpT = document.getElementById('ftpAlertToggle');
  if (ftpT) ftpT.checked = loadFtpAlert();
}

function setWeatherModel(model) {
  try { localStorage.setItem('icu_wx_model', model); } catch (e) { console.warn('localStorage.setItem failed:', e); }
  // Clear cached forecasts so next load uses the new model
  localStorage.removeItem('icu_wx_forecast');
  localStorage.removeItem('icu_wx_forecast_ts');
  localStorage.removeItem('icu_wx_page');
  localStorage.removeItem('icu_wx_page_ts');
  showToast(`Weather model set to: ${model}`, 'success');
}

function setUnits(units) {
  state.units = units;
  try { localStorage.setItem('icu_units', units); } catch (e) { console.warn('localStorage.setItem failed:', e); }
  document.querySelectorAll('[data-units]').forEach(btn =>
    btn.classList.toggle('active', btn.dataset.units === units)
  );
  // Slide toggle pill
  const unitsPill = document.getElementById('unitsPills');
  if (unitsPill) unitsPill.dataset.active = units === 'imperial' ? 'light' : 'dark';
  const elevEl = document.getElementById('settingsElevUnit');
  if (elevEl) elevEl.textContent = units === 'imperial' ? 'feet' : 'metres';
  if (state.synced) {
    if (state.currentPage === 'dashboard') renderDashboard();
    if (state.currentPage === 'activities') renderAllActivitiesList();
    if (state.currentPage === 'fitness') renderFitnessPage();
    if (state.currentPage === 'power') renderPowerPage();
  }
}

function set3DQuality(val) {
  localStorage.setItem('icu_3d_quality', val);
  // Reset the resolved quality cache in the badges module if it's already loaded
  if (_badges3dModule?.setQualitySetting) _badges3dModule.setQualitySetting(val);
  const sel = document.getElementById('quality3dSelect');
  if (sel) sel.value = val;
}

// Distance: input in metres, returns { val, unit }
function fmtDist(metres) {
  if (state.units === 'imperial') {
    return { val: (metres / 1609.344).toFixed(1), unit: 'mi' };
  }
  return { val: (metres / 1000).toFixed(1), unit: 'km' };
}

// Speed: input in m/s, returns { val, unit }
function fmtSpeed(ms) {
  if (state.units === 'imperial') {
    return { val: (ms * 2.23694).toFixed(1), unit: 'mph' };
  }
  return { val: (ms * 3.6).toFixed(1), unit: 'km/h' };
}

// Elevation: input in metres, returns { val, unit }
function fmtElev(metres) {
  if (state.units === 'imperial') {
    return { val: Math.round(metres * 3.28084).toLocaleString(), unit: 'ft' };
  }
  return { val: Math.round(metres).toLocaleString(), unit: 'm' };
}

/* ====================================================
   DATE RANGE & WEEK START
==================================================== */
function setWeekStartDay(day) {
  // day: 0=Sunday, 1=Monday
  state.weekStartDay = day;
  try { localStorage.setItem('icu_week_start_day', day); } catch (e) { console.warn('localStorage.setItem failed:', e); }
  // Sync toggle buttons in settings
  document.querySelectorAll('[data-weekstart]').forEach(btn => {
    btn.classList.toggle('active', parseInt(btn.dataset.weekstart) === day);
  });
  // Slide toggle pill
  const weekPill = document.getElementById('weekStartPills');
  if (weekPill) weekPill.dataset.active = day === 0 ? 'light' : 'dark';
  // Re-render all week-dependent views
  if (state.synced) {
    renderWeekProgress();
    renderFitnessStreak();
  }
  if (state.currentPage === 'calendar') { renderCalendar(); refreshCalendarEvents(); }
}

function rangeLabel(days) {
  return days === 365 ? 'Last year' : `Last ${days} days`;
}

// Per-card independent range state
const _cardRanges = {};
function _getCardRange(cardKey) {
  return _cardRanges[cardKey] || state.rangeDays || 30;
}

function _inlineRangePill(cardKey) {
  const days = _getCardRange(cardKey);
  return [14, 30, 90].map(d =>
    `<button class="dash-range-btn${d === days ? ' active' : ''}" onclick="event.stopPropagation();setCardRange('${cardKey}',${d})">${d}d</button>`
  ).join('');
}

function setCardRange(cardKey, days) {
  _cardRanges[cardKey] = days;
  // Re-render just this card's pills
  const pillEl = document.getElementById('dashRangePill_' + cardKey);
  if (pillEl) pillEl.innerHTML = _inlineRangePill(cardKey);
  // Re-render the specific card
  const acts = state.activities || [];
  const cutoff = daysAgo(days);
  const recent = acts.filter(a => new Date(a.start_date_local || a.start_date) >= cutoff && !isEmptyActivity(a));
  const ftp = state.athlete?.ftp || state.athlete?.icu_ftp || 200;
  const weight = state.athlete?.weight || 70;
  try {
    if (cardKey === 'training') { noChartAnim(() => renderFitnessHistoryChart(days)); }
    if (cardKey === 'zones') { renderZoneDist(recent); }
    if (cardKey === 'power') { const origRange = state.rangeDays; state.rangeDays = days; state.powerCurveRange = null; noChartAnim(() => renderPowerCurve()); state.rangeDays = origRange; }
    if (cardKey === 'trends') { noChartAnim(() => renderCyclingTrends(recent, days)); }
    if (cardKey === 'tss') { noChartAnim(() => renderWeeklyChart(recent)); }
    if (cardKey === 'scatter') { noChartAnim(() => renderPwrHrScatter(recent)); }
  } catch(e) { console.warn('setCardRange error:', cardKey, e); }
}

function _refreshDashRangePills() {
  const cards = ['training', 'zones', 'power', 'trends', 'tss', 'scatter', 'avgpower'];
  cards.forEach(key => {
    const el = document.getElementById('dashRangePill_' + key);
    if (el) el.innerHTML = _inlineRangePill(key);
  });
}

function setRange(days) {
  state.rangeDays = days;
  try { localStorage.setItem('icu_range_days', days); } catch (e) { console.warn('localStorage.setItem failed:', e); }
  // Sync all inline range pills
  document.querySelectorAll('.dash-range-btn').forEach(b => {
    b.classList.toggle('active', b.textContent === days + 'd');
  });
  // Sync topbar pill (legacy)
  document.querySelectorAll('#dateRangePill button').forEach(b => b.classList.remove('active'));
  const _rangeBtn = document.getElementById('range' + days);
  if (_rangeBtn) {
    _rangeBtn.classList.add('active');
    _rangeBtn.scrollIntoView({ inline: 'center', block: 'nearest', behavior: 'smooth' });
  }
  // Sync settings default-range checkmarks
  document.querySelectorAll('.ios-row--check[data-defrange]').forEach(r =>
    r.classList.toggle('active', parseInt(r.dataset.defrange) === days)
  );
  // Update main settings row value label
  const defLabel = document.getElementById('iosDefRangeVal');
  if (defLabel) defLabel.textContent = days + ' days';
  // Update inline range pills on dashboard cards
  _refreshDashRangePills();
  if (state.synced && state.currentPage === 'dashboard') noChartAnim(() => renderDashboard());
}

/* ====================================================
   MERGED ACTIVITY POOL  (recent + lifetime, deduped)
   Used by the Activities page so it lists everything.
==================================================== */
function getAllActivities() {
  const recent   = state.activities   || [];
  const lifetime = state.lifetimeActivities || [];
  const map = new Map();
  if (lifetime.length) {
    lifetime.forEach(a => { const id = a.id || a.icu_id; if (id) map.set(id, a); });
  }
  recent.forEach(a => { const id = a.id || a.icu_id; if (id) map.set(id, a); }); // overwrites lifetime
  // Merge locally imported FIT activities
  try {
    const fitImports = JSON.parse(localStorage.getItem('icu_fit_activities') || '[]');
    fitImports.forEach(a => { if (a.id && !map.has(a.id)) map.set(a.id, a); });
  } catch (_) {}
  // Merge Strava imported activities
  try {
    const stravaImports = JSON.parse(localStorage.getItem('icu_strava_activities') || '[]');
    stravaImports.forEach(a => { if (a.id && !map.has(a.id)) map.set(a.id, a); });
  } catch (_) {}
  return Array.from(map.values());
}

/** Load lifetime data from cache (if not already in memory) so the
 *  Activities page can show the full history immediately. */
function ensureLifetimeLoaded() {
  if (state.lifetimeActivities) return; // already in memory
  const cached = loadLifetimeCache();
  if (cached) {
    state.lifetimeActivities = cached.activities;
    state.lifetimeLastSync   = cached.lastSync;
    // Re-render now that we have more activities
    renderAllActivitiesList();
  }
}

/* ====================================================
   ACTIVITIES SORT
==================================================== */
const SORT_FIELDS = {
  date:      a => new Date(a.start_date_local || a.start_date).getTime(),
  distance:  a => actVal(a, 'distance', 'icu_distance'),
  time:      a => actVal(a, 'moving_time', 'elapsed_time', 'icu_moving_time', 'icu_elapsed_time'),
  elevation: a => actVal(a, 'total_elevation_gain', 'icu_total_elevation_gain'),
  power:     a => actVal(a, 'icu_weighted_avg_watts', 'average_watts', 'icu_average_watts'),
  bpm:       a => actVal(a, 'average_heartrate', 'icu_average_heartrate'),
};

function sortedAllActivities() {
  let pool = getAllActivities().filter(a => !isEmptyActivity(a));
  if (state.activitiesYear !== null) {
    pool = pool.filter(a => {
      const d = new Date(a.start_date_local || a.start_date);
      return d.getFullYear() === state.activitiesYear;
    });
  }
  if (state.activitiesSportFilter && state.activitiesSportFilter !== 'all') {
    const env = state.activitiesSportFilter; // 'indoor' or 'outdoor'
    pool = pool.filter(a => calActivityEnvironment(a) === env);
  }
  if (state.activitiesSearch && state.activitiesSearch.trim()) {
    const q = state.activitiesSearch.trim().toLowerCase();
    pool = pool.filter(a => {
      const name = (a.name || a.icu_name || '').toLowerCase();
      return name.includes(q);
    });
  }
  const fn  = SORT_FIELDS[state.activitiesSort] || SORT_FIELDS.date;
  const dir = state.activitiesSortDir === 'asc' ? 1 : -1;
  return [...pool].sort((a, b) => dir * (fn(a) - fn(b)));
}

function setActivitiesYear(year) {
  state.activitiesYear = year === 'all' ? null : parseInt(year);
  renderAllActivitiesList();
}

function setActivitiesSport(sport) {
  state.activitiesSportFilter = sport;
  renderAllActivitiesList();
  _updateSportButtons();
}

function setActivitiesSearch(q) {
  state.activitiesSearch = q;
  renderAllActivitiesList();
}

/* ── Apple-style Activity Search Modal ── */
let _actSearchDebounce = null;



function closeActivitySearch() {
  const modal = document.getElementById('actSearchModal');
  document.body.style.overflow = '';
  if (modal) closeModalAnimated(modal);
}

function clearActivitySearch() {
  const input = document.getElementById('actSearchInput');
  if (input) { input.value = ''; input.focus(); }
  document.getElementById('actSearchClear')?.classList.remove('visible');
  document.getElementById('actSearchResults').innerHTML =
    '<div class="act-search-empty">Type to search all activities</div>';
}

function _onActivitySearchInput(e) {
  const q = e.target.value.trim();
  const clearBtn = document.getElementById('actSearchClear');
  if (clearBtn) clearBtn.classList.toggle('visible', q.length > 0);

  clearTimeout(_actSearchDebounce);
  if (!q) {
    document.getElementById('actSearchResults').innerHTML =
      '<div class="act-search-empty">Type to search all activities</div>';
    return;
  }
  _actSearchDebounce = setTimeout(() => _runActivitySearch(q), 150);
}

function _runActivitySearch(q) {
  const lower = q.toLowerCase();
  const all = getAllActivities().filter(a => !isEmptyActivity(a));
  const matches = all.filter(a => {
    const name = (a.name || a.icu_name || '').toLowerCase();
    const type = (a.sport_type || a.type || a.icu_sport_type || '').toLowerCase();
    return name.includes(lower) || type.includes(lower);
  }).sort((a, b) => {
    const da = new Date(a.start_date_local || a.start_date).getTime();
    const db = new Date(b.start_date_local || b.start_date).getTime();
    return db - da;
  });

  const container = document.getElementById('actSearchResults');
  if (!matches.length) {
    container.innerHTML = '<div class="act-search-empty">No activities found</div>';
    return;
  }

  const MONTH_NAMES = MONTH_SHORT;
  let html = `<div class="act-search-count">${matches.length} result${matches.length !== 1 ? 's' : ''}</div>`;
  const limit = Math.min(matches.length, 50);
  for (let i = 0; i < limit; i++) {
    const a = matches[i];
    const rawName = (a.name && a.name.trim()) ? a.name.trim() : activityFallbackName(a);
    const { title: name } = cleanActivityName(rawName);
    const d = new Date(a.start_date_local || a.start_date);
    const dateStr = `${d.getDate()} ${MONTH_NAMES[d.getMonth()]} ${d.getFullYear()}`;
    const type = a.sport_type || a.type || '';
    const dist = actVal(a, 'distance', 'icu_distance') / 1000;
    const secs = actVal(a, 'moving_time', 'elapsed_time', 'icu_moving_time', 'icu_elapsed_time', 'total_elapsed_time');
    const sub = [dateStr, type, dist > 0.05 ? dist.toFixed(1) + ' km' : '', secs > 0 ? fmtDur(secs) : ''].filter(Boolean).join(' · ');
    const tc = activityTypeClass(a);
    const icon = activityTypeIcon(a);
    // Store in lookup for navigation
    const key = '_search_' + i;
    window._actLookup[key] = a;
    html += `<div class="act-search-row" onclick="navigateToActivity('${key}');closeActivitySearch()">
      <div class="act-search-row-icon ${tc}">${icon}</div>
      <div class="act-search-row-info">
        <div class="act-search-row-name">${name}</div>
        <div class="act-search-row-sub">${sub}</div>
      </div>
      <div class="act-search-row-chevron"><svg class="icon"><use href="icons.svg#icon-chevron-right"/></svg></div>
    </div>`;
  }
  if (matches.length > 50) {
    html += `<div class="act-search-empty" style="padding:16px 0;font-size:13px">Showing first 50 of ${matches.length} results</div>`;
  }
  container.innerHTML = html;
}

// Wire up the search input listener
document.addEventListener('DOMContentLoaded', () => {
  const inp = document.getElementById('actSearchInput');
  if (inp) inp.addEventListener('input', _onActivitySearchInput);
});

function setActivitiesSort(field) {
  if (state.activitiesSort === field) {
    state.activitiesSortDir = state.activitiesSortDir === 'desc' ? 'asc' : 'desc';
  } else {
    state.activitiesSort    = field;
    state.activitiesSortDir = 'desc';
  }
  renderAllActivitiesList();
  updateSortButtons();
}

function _updateSportButtons() {
  const sportOrder = ['all', 'outdoor', 'indoor'];
  const idx = sportOrder.indexOf(state.activitiesSportFilter || 'all');
  document.querySelectorAll('[data-sport]').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.sport === state.activitiesSportFilter);
  });
  const seg = document.getElementById('actsTypeSegmented');
  if (seg) seg.dataset.active = String(Math.max(0, idx));
}

function updateSortButtons() {
  document.querySelectorAll('[data-sort]').forEach(btn => {
    const f = btn.dataset.sort;
    const active = f === state.activitiesSort;
    btn.classList.toggle('active', active);
    const arrow = btn.querySelector('.sort-arrow');
    if (arrow) arrow.textContent = active ? (state.activitiesSortDir === 'desc' ? ' ↓' : ' ↑') : '';
  });
}

function _cleanupCardGrid(containerId) {
  const gs = window._actCardGridState[containerId];
  if (!gs) return;
  if (gs.observer) gs.observer.disconnect();
  if (gs.mapObserver) gs.mapObserver.disconnect();
  gs.mapQueue = [];
  gs.mapActive = 0;
  (gs.maps || []).forEach(m => { try { m.remove(); } catch (_) {} });
  gs.maps = [];
  window._actCardGridState[containerId] = null;
}

const CARD_MAP_CONC = 2; // max simultaneous map renders

function _ensureCardMapObserver(containerId) {
  const ls = window._actCardGridState[containerId];
  if (!ls || ls.mapObserver) return;

  ls.mapObserver = new IntersectionObserver((entries) => {
    for (const entry of entries) {
      if (!entry.isIntersecting) continue;
      const mapEl = entry.target;
      ls.mapObserver.unobserve(mapEl);
      // Queue it for rendering
      ls.mapQueue.push(mapEl);
    }
    _drainCardMapQueue(containerId);
  }, { rootMargin: '200px 0px' }); // start loading 200px before visible
}

function _drainCardMapQueue(containerId) {
  const ls = window._actCardGridState[containerId];
  if (!ls) return;
  while (ls.mapQueue.length > 0 && ls.mapActive < CARD_MAP_CONC) {
    const mapEl = ls.mapQueue.shift();
    const a = mapEl._activity;
    const idx = parseInt(mapEl.dataset.actIdx, 10);
    if (!a) continue;
    ls.mapActive++;
    renderRecentActCardMap(a, idx, 'actGridCard', ls.maps)
      .catch(() => {})
      .finally(() => {
        if (!window._actCardGridState[containerId]) return;
        ls.mapActive--;
        _drainCardMapQueue(containerId);
      });
  }
}

function setActivitiesView(mode) {
  state.activitiesView = mode;
  document.querySelectorAll('[data-view]').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.view === mode);
  });
  const listEl  = document.getElementById('allActivityList');
  const gridEl  = document.getElementById('allActivityCardGrid');
  const zonesEl = document.getElementById('allActivityZonesGrid');
  if (listEl)  listEl.style.display  = mode === 'list'  ? '' : 'none';
  if (gridEl)  gridEl.style.display  = mode === 'card'  ? '' : 'none';
  if (zonesEl) zonesEl.style.display = mode === 'zones' ? '' : 'none';

  // Clean up card grid maps when switching away to free WebGL contexts
  if (mode !== 'card') _cleanupCardGrid('allActivityCardGrid');

  renderAllActivitiesList();
}

function renderAllActivitiesList() {
  // Sync segmented control indicator
  _updateSportButtons();
  const sorted = sortedAllActivities();
  // Count placeholder activities (planned workouts never completed — all metrics zero).
  let allPool = getAllActivities().filter(a => !!(a.start_date_local || a.start_date));
  if (state.activitiesYear !== null) {
    allPool = allPool.filter(a => {
      const d = new Date(a.start_date_local || a.start_date);
      return d.getFullYear() === state.activitiesYear;
    });
  }
  const emptyCount = allPool.filter(a => isEmptyActivity(a)).length;

  const pageSub = document.getElementById('pageSubtitle');
  if (pageSub && state.currentPage === 'activities') {
    let text = `${sorted.length} ${sorted.length === 1 ? 'activity' : 'activities'}`;
    if (emptyCount > 0) text += ` · ${emptyCount} without data`;
    pageSub.textContent = text;
  }

  if (state.activitiesView === 'card') {
    renderActivityCardGrid('allActivityCardGrid', sorted);
  } else if (state.activitiesView === 'zones') {
    renderActivityZonesView('allActivityZonesGrid', sorted);
  } else {
    renderActivityList('allActivityList', sorted);
  }

  _refreshYearDropdown();
  _updateActStickyTop();
  _initActToolbarScroll();
}

/* ── Activity card grid (reuses recent-act card design) ── */
window._actCardGridState = {};
const ACT_CARD_GRID_BATCH = 12;
// In-memory + persistent cache of card map snapshots keyed by `${actId}_${theme}`
const _cardMapImgCache = new Map();
const _CARD_MAP_CACHE_NAME = 'icu-card-map-snaps-v2';
const _CARD_MAP_MAX = 120; // max snapshots to keep on disk

async function _cardMapCacheSave(key, dataUrl) {
  _cardMapImgCache.set(key, dataUrl);
  // Evict oldest in-memory entries if over limit
  if (_cardMapImgCache.size > _CARD_MAP_MAX) {
    const it = _cardMapImgCache.keys();
    for (let i = _cardMapImgCache.size - _CARD_MAP_MAX; i > 0; i--) _cardMapImgCache.delete(it.next().value);
  }
  try {
    const c = await caches.open(_CARD_MAP_CACHE_NAME);
    await c.put(`/_snap/${key}`, new Response(dataUrl));
    // Prune if over limit
    const keys = await c.keys();
    if (keys.length > _CARD_MAP_MAX) {
      for (let i = 0; i < keys.length - _CARD_MAP_MAX; i++) c.delete(keys[i]);
    }
  } catch (_) {}
}

async function _cardMapCacheLoad(key) {
  // Check in-memory first
  if (_cardMapImgCache.has(key)) return _cardMapImgCache.get(key);
  // Check persistent cache
  try {
    const c = await caches.open(_CARD_MAP_CACHE_NAME);
    const resp = await c.match(`/_snap/${key}`);
    if (resp) {
      const dataUrl = await resp.text();
      _cardMapImgCache.set(key, dataUrl); // promote to memory
      return dataUrl;
    }
  } catch (_) {}
  return null;
}

function renderActivityCardGrid(containerId, activities) {
  const el = document.getElementById(containerId);
  const filtered = (activities || []).filter(a => !isEmptyActivity(a));

  // Clean up previous maps + observer
  const prev = window._actCardGridState[containerId];
  if (prev) {
    if (prev.observer) prev.observer.disconnect();
    (prev.maps || []).forEach(m => { try { m.remove(); } catch (_) {} });
  }

  if (!filtered.length) {
    el.innerHTML = `<div class="empty-state"><svg class="icon"><use href="icons.svg#icon-activity"/></svg><p>No activities in this period.</p></div>`;
    window._actCardGridState[containerId] = null;
    return;
  }

  window._actCardGridState[containerId] = {
    el, filtered, cursor: 0, observer: null, lastMonth: null, maps: [],
    idCounter: 0, mapObserver: null, mapQueue: [], mapActive: 0,
  };

  el.innerHTML = '';
  _actCardGridLoadMore(containerId);
}

function _actCardGridLoadMore(containerId) {
  const ls = window._actCardGridState[containerId];
  if (!ls || ls.cursor >= ls.filtered.length) return;

  const MONTH_NAMES = MONTH_LONG;

  const end = Math.min(ls.cursor + ACT_CARD_GRID_BATCH, ls.filtered.length);
  let html = '';
  const batchStart = ls.idCounter;

  for (let i = ls.cursor; i < end; i++) {
    const a = ls.filtered[i];
    const d = new Date(a.start_date_local || a.start_date);
    const monthKey = d.getFullYear() + '-' + d.getMonth();
    if (monthKey !== ls.lastMonth) {
      ls.lastMonth = monthKey;
      const label = MONTH_NAMES[d.getMonth()] + ' ' + d.getFullYear();
      html += `<div class="act-month-divider"><span class="act-month-label">${label}</span></div>`;
    }
    html += buildRecentActCardHTML(a, ls.idCounter, 'actGridCard');
    ls.idCounter++;
  }

  // Remove old sentinel
  const oldSentinel = ls.el.querySelector('.act-list-sentinel');
  if (oldSentinel) oldSentinel.remove();

  ls.el.insertAdjacentHTML('beforeend', html);

  // Wire click handlers + lazy map observer for this batch
  let mapIdx = batchStart;
  for (let i = ls.cursor; i < end; i++) {
    const a = ls.filtered[i];
    const card = document.getElementById(`actGridCard_${mapIdx}`);
    if (card) card.onclick = () => navigateToActivity(a);

    // Register map container for lazy loading
    const mapEl = document.getElementById(`actGridCardMap_${mapIdx}`);
    if (mapEl) {
      mapEl.dataset.actIdx = mapIdx;
      mapEl.dataset.actId = a.id || a.icu_activity_id;
      mapEl._activity = a;  // keep reference for lazy loader
      _ensureCardMapObserver(containerId);
      ls.mapObserver.observe(mapEl);
    }
    mapIdx++;
  }
  ls.cursor = end;

  // Sentinel for infinite scroll
  if (ls.cursor < ls.filtered.length) {
    const sentinel = document.createElement('div');
    sentinel.className = 'act-list-sentinel';
    ls.el.appendChild(sentinel);

    if (ls.observer) ls.observer.disconnect();
    ls.observer = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) {
        ls.observer.disconnect();
        _actCardGridLoadMore(containerId);
      }
    }, { rootMargin: '300px' });
    ls.observer.observe(sentinel);
  }
}

/* ── Activity zones view (intervals bar graph cards) ── */
window._actZonesState = {};
const ACT_ZONES_BATCH = 12;

function buildZonesCardHTML(a, idx) {
  const rawName = (a.name && a.name.trim()) ? a.name.trim() : (a.icu_name || 'Activity');
  const { title: name, platformTag } = cleanActivityName(rawName);
  const dateStr = a.start_date_local || a.start_date || '';
  const dateObj = dateStr ? new Date(dateStr) : null;
  const dateFmt = dateObj
    ? dateObj.toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' })
    : '—';
  const timeFmt = dateObj
    ? dateObj.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' })
    : '';

  const dist  = actVal(a, 'distance', 'icu_distance');
  const secs  = actVal(a, 'moving_time', 'elapsed_time', 'icu_moving_time', 'icu_elapsed_time');
  const tss   = actVal(a, 'icu_training_load', 'tss');
  const watts = actVal(a, 'icu_weighted_avg_watts', 'average_watts', 'icu_average_watts');
  const hr    = actVal(a, 'average_heartrate', 'icu_average_heartrate');

  const dFmt = dist > 0 ? fmtDist(dist) : null;

  const tssClass = tss >= 250 ? 'ra-tss--extreme' : tss >= 150 ? 'ra-tss--hard' : tss >= 100 ? 'ra-tss--moderate' : tss >= 50 ? 'ra-tss--easy' : '';
  const tssBadge = tss > 0
    ? `<span class="ra-tss-badge ${tssClass}">${Math.round(tss)} TSS</span>`
    : '';

  const statItems = [
    watts > 0 && { val: Math.round(watts) + '<span class="ra-stat-unit">w</span>', lbl: 'Power' },
    hr    > 0 && { val: Math.round(hr),          lbl: 'Avg HR' },
    secs  > 0 && { val: _fmtDurHTML(secs),            lbl: 'Time' },
    dFmt      && { val: dFmt.val + '<span class="ra-stat-unit"> ' + dFmt.unit + '</span>', lbl: 'Distance' },
  ].filter(Boolean);

  const statsHTML = statItems.map(s =>
    `<div class="ra-stat">
      <div class="ra-stat-val">${s.val}</div>
      <div class="ra-stat-lbl">${s.lbl}</div>
    </div>`
  ).join('');

  const badgesHTML = (tssBadge || platformTag)
    ? `<div class="zones-card-badges">${tssBadge}${platformTag ? `<span class="act-platform-tag">${platformTag}</span>` : ''}</div>`
    : '';

  const achBadge = _heroAchBadge(a);
  const _zac = _achColor(a);
  const _zacStyle = _zac ? ` style="border:1px solid ${_zac}40;background:linear-gradient(135deg, ${_zac}28 0%, ${_zac}10 50%, transparent 100%), var(--bg-card)"` : '';

  return `<div class="card card--clickable zones-card" id="zonesCard_${idx}"${_zacStyle}>
    <div class="zones-card-header">
      <div class="zones-card-date">${dateFmt}${timeFmt ? ' · ' + timeFmt : ''}</div>
      <div class="zones-card-name-row">
        <div class="zones-card-name">${name}</div>
        ${achBadge}
      </div>
      ${badgesHTML}
    </div>
    <div class="zones-card-graph" id="zonesCardGraph_${idx}"></div>
    <div class="zones-card-stats">${statsHTML}</div>
  </div>`;
}

async function renderZonesCardIntervals(a, idx) {
  const actId = a.id || a.icu_activity_id;
  const graphEl = document.getElementById(`zonesCardGraph_${idx}`);
  if (!graphEl || !actId) return;

  try {
    let raw = await actCacheGet(actId, 'intervals');
    if (raw && raw.__noIntervals) {
      graphEl.innerHTML = '<div class="zc-empty">No interval data</div>';
      return;
    }
    if (!raw) {
      raw = await icuFetch(`/activity/${actId}/intervals`);
      actCachePut(actId, 'intervals', raw || { __noIntervals: true });
    }

    const intervals = raw?.icu_intervals;
    state._actIntervals = intervals || []; // store for info subpage
    if (!Array.isArray(intervals) || intervals.length < 1) {
      if (!raw?.__noIntervals) actCachePut(actId, 'intervals', { __noIntervals: true });
      graphEl.innerHTML = '<div class="zc-empty">No interval data</div>';
      return;
    }

    const totalDur = intervals.reduce((s, iv) => s + (iv.moving_time || iv.elapsed_time || 0), 0);
    const maxWatts = Math.max(...intervals.map(iv => iv.average_watts || 0), 1);
    const ftp = state.athlete?.ftp || 200;
    if (totalDur <= 0) { graphEl.innerHTML = '<div class="zc-empty">No interval data</div>'; return; }

    let html = '';
    intervals.forEach(iv => {
      const dur = iv.moving_time || iv.elapsed_time || 0;
      if (dur <= 0) return;

      const watts = iv.average_watts || 0;
      const widthPct = (dur / totalDur * 100).toFixed(2);
      const heightPct = watts > 0 ? Math.max(20, (watts / maxWatts * 100)) : 20;

      let zoneIdx = (iv.zone || 0) - 1;
      if (zoneIdx < 0 && watts > 0 && ftp > 0) {
        const ratio = watts / ftp;
        if (ratio < 0.55) zoneIdx = 0;
        else if (ratio < 0.75) zoneIdx = 1;
        else if (ratio < 0.90) zoneIdx = 2;
        else if (ratio < 1.05) zoneIdx = 3;
        else if (ratio < 1.20) zoneIdx = 4;
        else zoneIdx = 5;
      }
      zoneIdx = Math.max(0, Math.min(5, zoneIdx));
      const color = ZONE_HEX[zoneIdx] || ZONE_HEX[0];

      const type = (iv.type || '').toUpperCase();
      const isRest = /REST|RECOVER/.test(type);

      html += `<div class="zc-seg${isRest ? ' zc-seg--rest' : ''}" style="width:${widthPct}%;height:${heightPct}%;background:${color}"></div>`;
    });

    graphEl.innerHTML = html;
    graphEl.classList.add('has-data');
  } catch (e) {
    graphEl.innerHTML = '<div class="zc-empty">No interval data</div>';
  }
}

function renderActivityZonesView(containerId, activities) {
  const el = document.getElementById(containerId);
  const filtered = (activities || []).filter(a => !isEmptyActivity(a));

  const prev = window._actZonesState[containerId];
  if (prev && prev.observer) prev.observer.disconnect();

  if (!filtered.length) {
    el.innerHTML = `<div class="empty-state"><svg class="icon"><use href="icons.svg#icon-activity"/></svg><p>No activities in this period.</p></div>`;
    window._actZonesState[containerId] = null;
    return;
  }

  window._actZonesState[containerId] = {
    el, filtered, cursor: 0, observer: null, lastMonth: null, idCounter: 0
  };

  el.innerHTML = '';
  _actZonesLoadMore(containerId);
}

function _actZonesLoadMore(containerId) {
  const ls = window._actZonesState[containerId];
  if (!ls || ls.cursor >= ls.filtered.length) return;

  const MONTH_NAMES = MONTH_LONG;

  const end = Math.min(ls.cursor + ACT_ZONES_BATCH, ls.filtered.length);
  let html = '';
  const batchStart = ls.idCounter;

  for (let i = ls.cursor; i < end; i++) {
    const a = ls.filtered[i];
    const d = new Date(a.start_date_local || a.start_date);
    const monthKey = d.getFullYear() + '-' + d.getMonth();
    if (monthKey !== ls.lastMonth) {
      ls.lastMonth = monthKey;
      const label = MONTH_NAMES[d.getMonth()] + ' ' + d.getFullYear();
      html += `<div class="act-month-divider"><span class="act-month-label">${label}</span></div>`;
    }
    html += buildZonesCardHTML(a, ls.idCounter);
    ls.idCounter++;
  }

  const oldSentinel = ls.el.querySelector('.act-list-sentinel');
  if (oldSentinel) oldSentinel.remove();

  ls.el.insertAdjacentHTML('beforeend', html);

  // Wire click handlers + fetch intervals
  const jobs = [];
  let jobIdx = batchStart;
  for (let i = ls.cursor; i < end; i++) {
    const a = ls.filtered[i];
    const card = document.getElementById(`zonesCard_${jobIdx}`);
    if (card) card.onclick = () => navigateToActivity(a);
    jobs.push({ a, idx: jobIdx });
    jobIdx++;
  }
  ls.cursor = end;

  // Fetch intervals with limited concurrency
  (async () => {
    const CONC = 3;
    for (let i = 0; i < jobs.length; i += CONC) {
      await Promise.all(jobs.slice(i, i + CONC).map(
        j => renderZonesCardIntervals(j.a, j.idx)
      ));
    }
  })();

  // Sentinel for infinite scroll
  if (ls.cursor < ls.filtered.length) {
    const sentinel = document.createElement('div');
    sentinel.className = 'act-list-sentinel';
    ls.el.appendChild(sentinel);

    if (ls.observer) ls.observer.disconnect();
    ls.observer = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) {
        ls.observer.disconnect();
        _actZonesLoadMore(containerId);
      }
    }, { rootMargin: '300px' });
    ls.observer.observe(sentinel);
  }
}

function _updateActStickyTop() {
  const toolbar = document.querySelector('#page-activities .acts-toolbar');
  if (!toolbar) return;
  const update = () => {
    const val = Math.max(0, toolbar.getBoundingClientRect().bottom) + 'px';
    const list  = document.getElementById('allActivityList');
    const grid  = document.getElementById('allActivityCardGrid');
    const zones = document.getElementById('allActivityZonesGrid');
    if (list)  list.style.setProperty('--act-sticky-top', val);
    if (grid)  grid.style.setProperty('--act-sticky-top', val);
    if (zones) zones.style.setProperty('--act-sticky-top', val);
  };
  requestAnimationFrame(update);
}

/* ── Sync month-divider sticky top with toolbar position during animation ── */
function _setActStickyTop(val) {
  const list  = document.getElementById('allActivityList');
  const grid  = document.getElementById('allActivityCardGrid');
  const zones = document.getElementById('allActivityZonesGrid');
  if (list)  list.style.setProperty('--act-sticky-top', val);
  if (grid)  grid.style.setProperty('--act-sticky-top', val);
  if (zones) zones.style.setProperty('--act-sticky-top', val);
}
function _animateActStickyTop(toolbar, isHidden) {
  if (isHidden) { _setActStickyTop('env(safe-area-inset-top, 0px)'); return; }
  // Toolbar revealing — track its bottom edge each frame until transition ends
  let running = true;
  function track() {
    if (!running) return;
    const bottom = Math.max(0, toolbar.getBoundingClientRect().bottom);
    _setActStickyTop(bottom + 'px');
    requestAnimationFrame(track);
  }
  toolbar.addEventListener('transitionend', function handler() {
    running = false;
    toolbar.removeEventListener('transitionend', handler);
    _setActStickyTop(Math.max(0, toolbar.getBoundingClientRect().bottom) + 'px');
  }, { once: true });
  requestAnimationFrame(track);
}

/* ── Hide toolbar on scroll-down, reveal on scroll-up ── */
const _actScroll = { lastY: 0, ticking: false, bound: false };
function _initActToolbarScroll() {
  if (_actScroll.bound) return;
  _actScroll.bound = true;
  _actScroll.lastY = window.scrollY;

  window.addEventListener('scroll', () => {
    if (_actScroll.ticking) return;
    _actScroll.ticking = true;
    requestAnimationFrame(() => {
      _actScroll.ticking = false;
      if (state.currentPage !== 'activities') return;
      const toolbar = document.querySelector('#page-activities .acts-toolbar');
      if (!toolbar) return;

      const y = window.scrollY;
      const delta = y - _actScroll.lastY;
      // Only toggle after a 8px threshold to avoid jitter
      const wasHidden = toolbar.classList.contains('acts-toolbar--hidden');
      if (delta > 8) {
        toolbar.classList.add('acts-toolbar--hidden');
      } else if (delta < -8) {
        toolbar.classList.remove('acts-toolbar--hidden');
      }
      const isHidden = toolbar.classList.contains('acts-toolbar--hidden');
      if (wasHidden !== isHidden) _animateActStickyTop(toolbar, isHidden);
      _actScroll.lastY = y;
    });
  }, { passive: true });
}

function _refreshYearDropdown() {
  const sel = document.getElementById('activitiesYearSelect');
  if (!sel) return;

  // Collect distinct years from ALL (unfiltered) activities
  const currentYear = new Date().getFullYear();
  const years = new Set();
  getAllActivities().forEach(a => {
    if (!isEmptyActivity(a)) {
      const y = new Date(a.start_date_local || a.start_date).getFullYear();
      if (!isNaN(y)) years.add(y);
    }
  });

  // Ensure the last 4 years are always present in the list
  for (let y = currentYear; y > currentYear - 4; y--) years.add(y);

  const sorted = [...years].sort((a, b) => b - a); // newest first

  // Re-build options only if they changed (avoids flicker)
  const desired = ['all', ...sorted.map(String)];
  const current = [...sel.options].map(o => o.value);
  if (JSON.stringify(desired) === JSON.stringify(current)) return;

  sel.innerHTML = '';
  // "All" option
  const allOpt = document.createElement('option');
  allOpt.value = 'all';
  allOpt.textContent = 'All years';
  sel.appendChild(allOpt);

  sorted.forEach(y => {
    const opt = document.createElement('option');
    opt.value = y;
    opt.textContent = y === currentYear ? `${y} (current)` : String(y);
    sel.appendChild(opt);
  });

  // Restore selected value
  sel.value = state.activitiesYear !== null ? String(state.activitiesYear) : 'all';
}

