function openGearModal(editId) {
  _ensureGearModal();
  const modal = document.getElementById('gearModal');
  const titleEl = document.getElementById('gearModalTitle');
  if (!modal) return;

  // Reset form
  document.getElementById('gearEditId').value         = editId || '';
  document.getElementById('gearFormName').value       = '';
  document.getElementById('gearFormBrand').value      = '';
  document.getElementById('gearFormModel').value      = '';
  document.getElementById('gearFormDate').value       = '';
  document.getElementById('gearFormPrice').value      = '';
  document.getElementById('gearFormKmAtInstall').value= '';
  document.getElementById('gearFormReminderKm').value = '';
  if (document.getElementById('gearFormImage')) document.getElementById('gearFormImage').value = '';
  if (document.getElementById('gearFormOEM')) document.getElementById('gearFormOEM').checked = false;
  document.getElementById('gearFormBike').value       = _gearSelectedBike || '';
  document.getElementById('gearFormCategory').value   = 'Drivetrain';

  if (editId) {
    const comp = loadGearComponents().find(c => c.id === editId);
    if (comp) {
      titleEl.textContent = 'Edit Component';
      document.getElementById('gearFormName').value        = comp.name        || '';
      document.getElementById('gearFormBrand').value       = comp.brand       || '';
      _gearUpdateModels(); // populate model options for this brand
      document.getElementById('gearFormModel').value       = comp.model       || '';
      document.getElementById('gearFormDate').value        = comp.purchaseDate|| '';
      document.getElementById('gearFormPrice').value       = comp.price       || '';
      document.getElementById('gearFormKmAtInstall').value = comp.kmAtInstall || '';
      document.getElementById('gearFormReminderKm').value  = comp.reminderKm  || '';
      document.getElementById('gearFormBike').value        = comp.bikeId      || '';
      document.getElementById('gearFormCategory').value    = comp.category    || 'Drivetrain';
      if (document.getElementById('gearFormImage')) document.getElementById('gearFormImage').value = comp.image || '';
      if (document.getElementById('gearFormOEM')) document.getElementById('gearFormOEM').checked = !!comp.oem;
      const preview = document.getElementById('gearFormImagePreview');
      if (preview && comp.image) {
        preview.innerHTML = `<img src="${comp.image}" alt="preview">`;
        preview.style.background = 'transparent';
      }
    }
  } else {
    titleEl.textContent = 'Add Component';
    const preview = document.getElementById('gearFormImagePreview');
    if (preview) { preview.innerHTML = ''; preview.style.background = 'var(--bg-elevated)'; }
  }

  _openOverlaySheet('gearModal');
  _initGearScrubbers();
  _syncGearScrubbers();
  initCustomDropdowns(modal);
  document.getElementById('gearFormBike')?._cddRefresh?.();
  document.getElementById('gearFormCategory')?._cddRefresh?.();
  document.getElementById('gearFormBrand')?._cddRefresh?.();
  document.getElementById('gearFormModel')?._cddRefresh?.();
  // Override dropdown triggers to use picker sheets
  _gearHookPickerSheets(modal);
  _gearHookDatePickers(modal);

  // Brand → Model suggestions
  const brandSel = document.getElementById('gearFormBrand');
  if (brandSel) {
    brandSel.removeEventListener('change', _gearUpdateModels);
    brandSel.addEventListener('change', _gearUpdateModels);
    _gearUpdateModels();
  }
}

// Component photo upload — reuses the same hidden file input
let _gearCompPhotoTarget = null;
function gearCompPhotoUpload(compId) {
  _gearCompPhotoTarget = compId;
  // Create a temporary file input
  const inp = document.createElement('input');
  inp.type = 'file';
  inp.accept = 'image/*';
  inp.onchange = () => {
    const file = inp.files?.[0];
    if (!file || !_gearCompPhotoTarget) return;
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX = 200;
        let w = img.width, h = img.height;
        if (w > MAX) { h *= MAX / w; w = MAX; }
        if (h > MAX) { w *= MAX / h; h = MAX; }
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        // If modal is open, update preview + hidden field
        const preview = document.getElementById('gearFormImagePreview');
        const hiddenInput = document.getElementById('gearFormImage');
        if (preview && document.getElementById('gearModal')?.style.display !== 'none') {
          preview.innerHTML = `<img src="${dataUrl}" alt="preview">`;
          preview.style.background = 'transparent';
          if (hiddenInput) hiddenInput.value = dataUrl;
        } else {
          // Direct save to component
          let all = loadGearComponents();
          all = all.map(c => c.id === _gearCompPhotoTarget ? { ...c, image: dataUrl } : c);
          saveGearComponents(all);
          renderGearComponents();
        }
        _gearCompPhotoTarget = null;
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  };
  inp.click();
}

