/* ── FIT file parsing & caching ── */

// IndexedDB cache for parsed FIT data — avoids re-downloading on repeat views
const FIT_CACHE_DB = 'cycleiq_fit_cache';
const FIT_CACHE_VER = 1;
const FIT_PARSER_VER = 14; // v14: fix HRV not stored in result
function _fitCacheDB() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(FIT_CACHE_DB, FIT_CACHE_VER);
    req.onupgradeneeded = e => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains('parsed')) {
        db.createObjectStore('parsed', { keyPath: 'actId' });
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror   = () => reject(req.error);
  });
}

async function _fitCacheGet(actId) {
  try {
    const db = await _fitCacheDB();
    return await new Promise(res => {
      const tx = db.transaction('parsed', 'readonly');
      const req = tx.objectStore('parsed').get(actId);
      req.onsuccess = () => res(req.result || null);
      req.onerror   = () => res(null);
    });
  } catch { return null; }
}

async function _fitCachePut(actId, data) {
  try {
    const db = await _fitCacheDB();
    const tx = db.transaction('parsed', 'readwrite');
    tx.objectStore('parsed').put({ actId, ...data, cachedAt: Date.now(), parserVer: FIT_PARSER_VER });
  } catch {}
}

// Minimal FIT parser: extracts device_info battery_voltage fields
// FIT spec: device_info (mesg 23), field 10 = battery_voltage (uint16, scale 256)
// field 11 = battery_status (enum: 1=new, 2=good, 3=ok, 4=low, 5=critical, 6=charging, 7=unknown)
// Fetch, parse, and cache FIT data for an activity
// Returns { devices: [...], dynamics: {...} | null } or null
// Dedup inflight FIT requests — prevents 3 parallel downloads for the same activity
const _fitInflight = new Map();
async function _fetchParsedFIT(actId) {
  // 0. Check inflight request
  if (_fitInflight.has(actId)) return _fitInflight.get(actId);
  const promise = _fetchParsedFITInner(actId);
  _fitInflight.set(actId, promise);
  try { return await promise; } finally { _fitInflight.delete(actId); }
}
async function _fetchParsedFITInner(actId) {
  // 1. Check in-memory cache
  if (window._lastFITParse && window._lastFITParse.actId === actId) {
    return window._lastFITParse.data;
  }
  // 2. Check IndexedDB cache (invalidate if parser version changed)
  const cached = await _fitCacheGet(actId);
  if (cached && cached.parserVer === FIT_PARSER_VER) {
    const data = {
      devices: cached.devices || [],
      dynamics: cached.dynamics || null,
      temperature: cached.temperature || null,
      gpsAccuracy: cached.gpsAccuracy || null,
      respiration: cached.respiration || null,
      gearChanges: cached.gearChanges || null,
      hrv: cached.hrv || null,
    };
    window._lastFITParse = { actId, data };
    return data;
  }
  // 3. Download and parse
  const urls = [
    ICU_BASE + `/activity/${actId}/file`,
    ICU_BASE + `/activity/${actId}/original`,
    ICU_BASE + `/athlete/${state.athleteId}/activities/${actId}/original`,
    ICU_BASE + `/activity/${actId}.fit`,
    ICU_BASE + `/athlete/${state.athleteId}/activities/${actId}.fit`,
  ];
  for (const url of urls) {
    try {
      const resp = await fetch(url, { headers: authHeader() });
      if (!resp.ok) continue;
      rlTrackRequest();
      const buf = await resp.arrayBuffer();
      if (buf.byteLength < 14) continue;
      const dv = new DataView(buf);
      const sig = String.fromCharCode(dv.getUint8(8), dv.getUint8(9), dv.getUint8(10), dv.getUint8(11));
      if (sig !== '.FIT') continue;
      // Hybrid approach: library for device_info/events, legacy for record data (PCO, dynamics)
      let data;
      const legacyData = _parseFIT(dv);
      try {
        await _loadFitDecoder();
        const libData = _parseFITWithLib(buf);
        if (libData) {
          // Library is better at: devices (handles all manufacturers), events (gear changes)
          // Legacy is better at: record fields (PCO, dynamics — library misses some fields)
          data = {
            devices: libData.devices.length > legacyData.devices.length ? libData.devices : legacyData.devices,
            dynamics: legacyData.dynamics, // always use legacy for dynamics/PCO
            temperature: legacyData.temperature?.length > (libData.temperature?.length || 0) ? legacyData.temperature : libData.temperature,
            gpsAccuracy: legacyData.gpsAccuracy?.length > (libData.gpsAccuracy?.length || 0) ? legacyData.gpsAccuracy : libData.gpsAccuracy,
            respiration: legacyData.respiration?.length > (libData.respiration?.length || 0) ? legacyData.respiration : libData.respiration,
            gearChanges: (libData.gearChanges?.length || 0) > (legacyData.gearChanges?.length || 0) ? libData.gearChanges : legacyData.gearChanges,
            hrv: libData.hrv || legacyData.hrv, // library is better at HRV extraction
          };
        }
      } catch (e) {
        console.warn('[FIT] Library unavailable:', e.message);
      }
      if (!data) data = legacyData;
      if (data.devices.length || data.dynamics) {
        window._lastFITParse = { actId, data };
        // Cache in IndexedDB (background, non-blocking)
        _fitCachePut(actId, {
          devices: data.devices, dynamics: data.dynamics,
          temperature: data.temperature, gpsAccuracy: data.gpsAccuracy,
          respiration: data.respiration, gearChanges: data.gearChanges, hrv: data.hrv,
        }).catch(() => {});
        return data;
      }
    } catch (e) {
      console.warn('FIT parse failed for', url, e.message);
    }
  }
  return null;
}

// Legacy wrapper: extract only battery devices
async function _extractBatteryFromFIT(actId) {
  const data = await _fetchParsedFIT(actId);
  return data ? data.devices : null;
}

// ── fit-decoder library (lazy-loaded from CDN) ──
let _fitDecoderLoaded = false;
let _fitDecoderLoading = null;
async function _loadFitDecoder() {
  if (_fitDecoderLoaded && window.fitDecoder) return window.fitDecoder;
  if (_fitDecoderLoading) return _fitDecoderLoading;
  _fitDecoderLoading = new Promise((resolve, reject) => {
    const script = document.createElement('script');
    script.src = 'https://cdn.jsdelivr.net/npm/fit-decoder@1.0.5/dist/index.js';
    script.onload = () => { _fitDecoderLoaded = true; resolve(window.fitDecoder); };
    script.onerror = () => { _fitDecoderLoading = null; reject(new Error('fit-decoder CDN load failed')); };
    document.head.appendChild(script);
  });
  return _fitDecoderLoading;
}

// Parse FIT using fit-decoder library, map to our data structure
function _parseFITWithLib(buffer) {
  const fd = window.fitDecoder;
  if (!fd) return null;

  const jsonRaw = fd.fit2json(buffer);
  const json = fd.parseRecords(jsonRaw);

  const result = { devices: [], dynamics: null, temperature: null, gpsAccuracy: null, respiration: null, gearChanges: null };
  const dyn = { lrBal: [], lte: [], rte: [], lps: [], rps: [], cps: [], lPco: [], rPco: [] };
  const temp = [], gpsAcc = [], respRate = [], gearChanges = [];

  // Library returns all messages in json.records[] — filter by type
  const allRecords = json.records || [];

  // Process device_info messages
  const deviceInfos = allRecords.filter(r => r.type === 'device_info').map(r => r.data);
  for (const d of deviceInfos) {
    // Library may use named fields or numeric field IDs depending on SDK profile coverage
    const dev = {
      voltage: d.battery_voltage ?? (d[10] != null && d[10] !== 0xFFFF ? d[10] / 256 : null),
      batStatus: d.battery_status != null
        ? (typeof d.battery_status === 'string'
          ? ({ new: 1, good: 2, ok: 3, low: 4, critical: 5, charging: 6 }[d.battery_status.toLowerCase()] ?? null)
          : d.battery_status)
        : (d[11] != null && d[11] !== 0xFF ? d[11] : null),
      manufacturer: d.manufacturer ?? d.manufacturer_id ?? d[2] ?? null,
      product: d.product ?? d.garmin_product ?? d[3] ?? null,
      deviceType: d.device_type ?? d.ant_device_type ?? d[25] ?? null,
      serialNumber: d.serial_number ?? d[4] ?? null,
      softwareVersion: d.software_version ?? d[5] ?? null,
      sourceType: d.source_type ?? d[22] ?? null,
    };
    // Map string manufacturer to numeric ID for compatibility
    if (typeof dev.manufacturer === 'string') {
      const mfrLower = dev.manufacturer.toLowerCase();
      let found = false;
      for (const [id, name] of Object.entries(_FIT_MFR)) {
        if (name.toLowerCase() === mfrLower) { dev.manufacturer = parseInt(id); found = true; break; }
      }
      if (!found) {
        // Store string as-is if no mapping found
      }
    }
    if (dev.manufacturer !== null || dev.deviceType !== null) {
      result.devices.push(dev);
    }
  }

  // Process record messages (cycling dynamics, temp, GPS, respiration)
  const records = allRecords.filter(r => r.type === 'record').map(r => r.data);
  // Extract HRV data (beat-to-beat R-R intervals)
  const hrvRR = [];
  try {
    const hrvRecords = allRecords.filter(r => r.type === 'hrv').map(r => r.data);
    for (const h of hrvRecords) {
      const t = h.time ?? h[0];
      if (typeof t === 'number' && t > 0 && t < 5000) hrvRR.push(t);
      else if (Array.isArray(t)) { for (const v of t) { if (typeof v === 'number' && v > 0 && v < 5000) hrvRR.push(v); } }
    }
  } catch (e) { console.warn('[FIT-LIB] HRV extraction error:', e.message); }

  for (const r of records) {
    // Temperature (named or field 13)
    const t = r.temperature ?? r[13] ?? null;
    if (t != null && t !== 0x7F) temp.push(t);
    // GPS accuracy (only use named field — numeric fallback unreliable)
    const ga = r.gps_accuracy ?? r.enhanced_gps_accuracy ?? null;
    if (ga != null && ga < 255 && ga > 0) gpsAcc.push(ga);
    // Respiration — field 63 (RespirationRate sint8) or field 128 (EnhancedRespirationRate uint16/100)
    let resp = r.respiration_rate ?? r[63] ?? null;
    if (resp == null) {
      const eResp = r.enhanced_respiration_rate ?? r[128] ?? null;
      if (eResp != null && eResp !== 0xFFFF && eResp > 0) resp = eResp / 100;
    }
    if (resp != null && resp > 0 && resp < 80) respRate.push(resp);
    // Cycling dynamics
    if (r.left_right_balance != null) dyn.lrBal.push(r.left_right_balance & 0x7F);
    if (r.left_torque_effectiveness != null) dyn.lte.push(r.left_torque_effectiveness);
    if (r.right_torque_effectiveness != null) dyn.rte.push(r.right_torque_effectiveness);
    if (r.left_pedal_smoothness != null) dyn.lps.push(r.left_pedal_smoothness);
    if (r.right_pedal_smoothness != null) dyn.rps.push(r.right_pedal_smoothness);
    if (r.combined_pedal_smoothness != null) dyn.cps.push(r.combined_pedal_smoothness);
    const lPcoVal = r.left_platform_center_offset ?? r.left_pco ?? r[54] ?? null;
    const rPcoVal = r.right_platform_center_offset ?? r.right_pco ?? r[55] ?? null;
    if (lPcoVal != null) dyn.lPco.push(lPcoVal);
    if (rPcoVal != null) dyn.rPco.push(rPcoVal);
  }

  // Process event messages (gear changes)
  const events = allRecords.filter(r => r.type === 'event').map(r => r.data);
  for (const e of events) {
    const evtName = typeof e.event === 'string' ? e.event.toLowerCase() : e.event;
    if (evtName === 'gear_change' || evtName === 'rear_gear_change' || evtName === 'front_gear_change'
        || evtName === 42 || evtName === 43) {
      // Library may parse gear fields directly, or we decode from packed data
      let front = e.front_gear ?? e.front_gear_num_teeth ?? 0;
      let rear = e.rear_gear ?? e.rear_gear_num_teeth ?? 0;
      let frontNum = e.front_gear_num ?? 0;
      let rearNum = e.rear_gear_num ?? 0;
      // If named fields not available, decode from packed uint32 data field
      if (!front && !rear && e.data != null && typeof e.data === 'number' && e.data > 255) {
        rearNum = e.data & 0xFF;
        rear = (e.data >> 8) & 0xFF;
        frontNum = (e.data >> 16) & 0xFF;
        front = (e.data >> 24) & 0xFF;
      }
      // Also check gear_change_data field (field 11)
      if (!front && !rear && e.gear_change_data != null) {
        const gd = e.gear_change_data;
        rearNum = gd & 0xFF;
        rear = (gd >> 8) & 0xFF;
        frontNum = (gd >> 16) & 0xFF;
        front = (gd >> 24) & 0xFF;
      }
      const timestamp = e.timestamp ? Math.round(new Date(e.timestamp).getTime() / 1000) : (e[253] ?? null);
      if (front || rear) {
        gearChanges.push({ timestamp, front, rear, frontNum, rearNum });
      }
    }
  }

  // Assemble results
  const hasDyn = dyn.lrBal.length > 0 || dyn.lPco.length > 0;
  if (hasDyn) {
    const avg = a => a.length ? a.reduce((s, v) => s + v, 0) / a.length : null;
    result.dynamics = {
      avgLRBal: avg(dyn.lrBal),
      avgLTE: avg(dyn.lte), avgRTE: avg(dyn.rte),
      avgLPS: avg(dyn.lps), avgRPS: avg(dyn.rps), avgCPS: avg(dyn.cps),
      avgLPco: avg(dyn.lPco), avgRPco: avg(dyn.rPco),
      lPcoHist: dyn.lPco, rPcoHist: dyn.rPco,
    };
  }
  if (temp.length > 10) result.temperature = temp;
  if (gpsAcc.length > 10) result.gpsAccuracy = gpsAcc;
  if (respRate.length > 10) result.respiration = respRate;
  if (gearChanges.length) result.gearChanges = gearChanges;
  if (hrvRR.length > 10) result.hrv = hrvRR;

  return result;
}

// Legacy general-purpose FIT parser (fallback if library fails to load)
function _parseFIT(dv) {
  const result = { devices: [], dynamics: null, temperature: null, gpsAccuracy: null, respiration: null, gearChanges: null };
  // Cycling dynamics accumulators
  const dyn = { lrBal: [], lte: [], rte: [], lps: [], rps: [], cps: [], lPco: [], rPco: [] };
  // Additional streams
  const temp = [];       // temperature per record (°C)
  const gpsAcc = [];     // GPS accuracy per record (m)
  const respRate = [];   // respiration rate per record (breaths/min)
  const gearChanges = []; // gear change events
  let hasDyn = false;

  try {
    const headerSize = dv.getUint8(0);
    if (headerSize < 12) return result;
    const sig = String.fromCharCode(dv.getUint8(8), dv.getUint8(9), dv.getUint8(10), dv.getUint8(11));
    if (sig !== '.FIT') return result;

    let offset = headerSize;
    const defnMap = {};
    const end = dv.byteLength - 2;

    while (offset < end) {
      const recHeader = dv.getUint8(offset++);
      const isCompressed = (recHeader & 0x80) !== 0;

      if (isCompressed) {
        const tsLocal = (recHeader >> 5) & 0x03;
        const defn = defnMap[tsLocal];
        if (!defn) break;
        if (defn.globalMesg === 20) {
          _parseFITRecord(dv, offset, defn, dyn, temp, gpsAcc, respRate);
          hasDyn = true;
        }
        offset += defn.size;
        continue;
      }

      const isDefn = (recHeader & 0x40) !== 0;
      const localMesg = recHeader & 0x0F;

      if (isDefn) {
        offset++; // reserved
        const arch = dv.getUint8(offset++);
        const le = arch === 0;
        const globalMesg = le ? dv.getUint16(offset, true) : dv.getUint16(offset, false);
        offset += 2;
        const numFields = dv.getUint8(offset++);
        const fields = [];
        let dataSize = 0;
        for (let i = 0; i < numFields; i++) {
          const fNum = dv.getUint8(offset++);
          const fSize = dv.getUint8(offset++);
          const fType = dv.getUint8(offset++);
          fields.push({ num: fNum, size: fSize, type: fType });
          dataSize += fSize;
        }
        if ((recHeader & 0x20) !== 0) {
          const nDev = dv.getUint8(offset++);
          for (let i = 0; i < nDev; i++) { offset += 3; dataSize += dv.getUint8(offset - 2); }
        }
        defnMap[localMesg] = { globalMesg, fields, size: dataSize, le };
      } else {
        const defn = defnMap[localMesg];
        if (!defn) break;

        if (defn.globalMesg === 23) { // device_info
          let voltage = null, batStatus = null, manufacturer = null, product = null, deviceType = null;
          let serialNumber = null, softwareVersion = null, sourceType = null;
          let fOff = offset;
          for (const f of defn.fields) {
            if (f.num === 10 && f.size === 2) {
              const raw = defn.le ? dv.getUint16(fOff, true) : dv.getUint16(fOff, false);
              if (raw !== 0xFFFF) voltage = raw / 256;
            } else if (f.num === 11 && f.size === 1) {
              const raw = dv.getUint8(fOff);
              if (raw !== 0xFF) batStatus = raw;
            } else if (f.num === 2 && f.size === 2) {
              const raw = defn.le ? dv.getUint16(fOff, true) : dv.getUint16(fOff, false);
              if (raw !== 0xFFFF) manufacturer = raw;
            } else if (f.num === 3 && f.size === 2) {
              const raw = defn.le ? dv.getUint16(fOff, true) : dv.getUint16(fOff, false);
              if (raw !== 0xFFFF) product = raw;
            } else if (f.num === 4 && f.size === 4) {
              const raw = defn.le ? dv.getUint32(fOff, true) : dv.getUint32(fOff, false);
              if (raw !== 0xFFFFFFFF) serialNumber = raw;
            } else if (f.num === 5 && f.size === 2) {
              const raw = defn.le ? dv.getUint16(fOff, true) : dv.getUint16(fOff, false);
              if (raw !== 0xFFFF) softwareVersion = raw / 100;
            } else if (f.num === 25 && f.size === 1) {
              const raw = dv.getUint8(fOff);
              if (raw !== 0xFF) deviceType = raw;
            } else if (f.num === 22 && f.size === 1) {
              const raw = dv.getUint8(fOff);
              if (raw !== 0xFF) sourceType = raw;
            }
            fOff += f.size;
          }
          // Capture ALL device_info records (with or without battery) for full device inventory
          if (manufacturer !== null || deviceType !== null) {
            result.devices.push({ voltage, batStatus, manufacturer, product, deviceType, serialNumber, softwareVersion, sourceType });
          }
        } else if (defn.globalMesg === 20) { // record
          _parseFITRecord(dv, offset, defn, dyn, temp, gpsAcc, respRate);
          hasDyn = true;
        } else if (defn.globalMesg === 21) { // event — gear_change is event 42/43
          _parseFITEvent(dv, offset, defn, gearChanges);
        }
        offset += defn.size;
      }
    }
  } catch (e) {
    console.warn('FIT parse error:', e.message);
  }

  if (hasDyn && (dyn.lte.length || dyn.lps.length || dyn.lPco.length || dyn.lrBal.length)) {
    result.dynamics = dyn;
  }
  if (temp.length > 10)    result.temperature  = temp;
  if (gpsAcc.length > 10)  result.gpsAccuracy  = gpsAcc;
  if (respRate.length > 10) result.respiration  = respRate;
  if (gearChanges.length)  result.gearChanges  = gearChanges;
  return result;
}

// Parse a single FIT record message for dynamics + streams
// Record field numbers: 13=temperature, 31=gps_accuracy, 108=respiration_rate
function _parseFITRecord(dv, offset, defn, dyn, temp, gpsAcc, respRate) {
  let lrBal = null, lte = null, rte = null, lps = null, rps = null, cps = null, lPco = null, rPco = null;
  let t = null, gps = null, resp = null;
  let fOff = offset;
  for (const f of defn.fields) {
    const v8 = () => { const r = dv.getUint8(fOff); return r === 0xFF ? null : r; };
    const v8s = () => { const r = dv.getInt8(fOff); return r === 0x7F ? null : r; };
    const v16 = () => { const r = defn.le ? dv.getUint16(fOff, true) : dv.getUint16(fOff, false); return r === 0xFFFF ? null : r; };
    const v16s = () => { const r = defn.le ? dv.getInt16(fOff, true) : dv.getInt16(fOff, false); return r === 0x7FFF ? null : r; };
    switch (f.num) {
      // Cycling dynamics
      case 30: lrBal = v8(); break;
      case 43: lte = v8(); if (lte !== null) lte /= 2; break;
      case 44: rte = v8(); if (rte !== null) rte /= 2; break;
      case 45: lps = v8(); if (lps !== null) lps /= 2; break;
      case 46: rps = v8(); if (rps !== null) rps /= 2; break;
      case 47: cps = v8(); if (cps !== null) cps /= 2; break;
      case 54: lPco = v8s(); break; // LeftPco (sint8, mm)
      case 55: rPco = v8s(); break; // RightPco (sint8, mm)
      case 67: if (lPco === null) lPco = v8s(); break; // legacy fallback
      case 68: if (rPco === null) rPco = v8s(); break; // legacy fallback
      // Temperature (field 13, sint8, °C)
      case 13: if (f.size === 1) t = v8s(); break;
      // GPS accuracy (field 31, uint8, meters)
      case 31: if (f.size === 1) gps = v8(); break;
      // Respiration rate — field 63 (sint8) or field 128 (uint16, enhanced)
      case 63: if (f.size === 1) { const rv = v8s(); if (rv !== null && rv > 0 && rv < 80) resp = rv; } break;
      case 128: if (f.size === 2 && resp === null) { const rv = defn.le ? dv.getUint16(fOff, true) : dv.getUint16(fOff, false); if (rv !== 0xFFFF && rv > 0) resp = rv / 100; } break;
    }
    fOff += f.size;
  }
  if (lrBal !== null) dyn.lrBal.push(lrBal & 0x7F);
  if (lte !== null) dyn.lte.push(lte);
  if (rte !== null) dyn.rte.push(rte);
  if (lps !== null) dyn.lps.push(lps);
  if (rps !== null) dyn.rps.push(rps);
  if (cps !== null) dyn.cps.push(cps);
  if (lPco !== null) dyn.lPco.push(lPco);
  if (rPco !== null) dyn.rPco.push(rPco);
  // Streams
  if (t !== null) temp.push(t);
  if (gps !== null) gpsAcc.push(gps);
  if (resp !== null && resp > 0 && resp < 60) respRate.push(resp);
}

// Parse FIT event message for gear changes
// Event mesg (21): field 0 = event (enum), field 1 = event_type, field 3 = data (uint32)
// Gear change event: event = 42, data encodes front/rear gear teeth
function _parseFITEvent(dv, offset, defn, gearChanges) {
  let event = null, eventType = null, data = null, gearData = null, timestamp = null;
  let fOff = offset;
  for (const f of defn.fields) {
    if (f.num === 0 && f.size === 1) { // event
      const r = dv.getUint8(fOff);
      if (r !== 0xFF) event = r;
    } else if (f.num === 1 && f.size === 1) { // event_type
      const r = dv.getUint8(fOff);
      if (r !== 0xFF) eventType = r;
    } else if (f.num === 3 && f.size === 4) { // data (uint32)
      const r = defn.le ? dv.getUint32(fOff, true) : dv.getUint32(fOff, false);
      if (r !== 0xFFFFFFFF) data = r;
    } else if (f.num === 11 && f.size === 4) { // gear_change_data (uint32) — preferred field for gear changes
      const r = defn.le ? dv.getUint32(fOff, true) : dv.getUint32(fOff, false);
      if (r !== 0xFFFFFFFF) gearData = r;
    } else if (f.num === 253 && f.size === 4) { // timestamp
      const r = defn.le ? dv.getUint32(fOff, true) : dv.getUint32(fOff, false);
      if (r !== 0xFFFFFFFF) timestamp = r;
    }
    fOff += f.size;
  }
  // event 42 or 43 = gear_change (Garmin uses 43, FIT SDK says 42; legacy: 11 = rear, 12 = front)
  if (event === 42 || event === 43 || event === 11 || event === 12) {
    // Prefer field 11 (gear_change_data) over field 3 (generic data)
    const d = gearData ?? data;
    if (d !== null) {
      // gear_change_data encoding: bits 0-7 = rear_gear_num, 8-15 = rear_gear, 16-23 = front_gear_num, 24-31 = front_gear
      const rearTeeth  = (d >> 8) & 0xFF;
      const frontTeeth = (d >> 24) & 0xFF;
      const rearNum    = d & 0xFF;
      const frontNum   = (d >> 16) & 0xFF;
      if (rearTeeth || frontTeeth) {
        gearChanges.push({ timestamp, front: frontTeeth, rear: rearTeeth, frontNum, rearNum });
      }
    }
  }
}

// Legacy wrapper for battery-only extraction
function _parseFITBattery(dv) {
  return _parseFIT(dv).devices;
}

// Convert voltage to percentage based on common battery chemistries
// Auto-detect: voltage ≤ 3.3V is likely coin cell (CR2032/CR1632), > 3.3V is Li-ion
function _voltageToPercent(voltage) {
  if (!voltage || voltage <= 0) return null;
  // Coin cell (CR2032, CR1632): 2.0V dead → 3.0V full
  if (voltage <= 3.3) {
    if (voltage >= 3.0) return 100;
    if (voltage <= 2.0) return 0;
    return Math.round(((voltage - 2.0) / 1.0) * 100);
  }
  // Li-ion/Li-po (rechargeable): 3.0V dead → 4.2V full
  if (voltage >= 4.2) return 100;
  if (voltage <= 3.3) return 0;
  return Math.round(((voltage - 3.3) / 0.9) * 100);
}

// Battery status enum → text
function _batStatusText(s) {
  return { 1: 'New', 2: 'Good', 3: 'OK', 4: 'Low', 5: 'Critical', 6: 'Charging', 7: 'Unknown' }[s] || null;
}

// FIT manufacturer IDs → names (from Garmin FIT SDK Profile.xlsx)
const _FIT_MFR = {
  1: 'Garmin', 2: 'Garmin', 7: 'SRAM', 15: 'Timex', 23: 'SRM', 29: 'Quarq',
  32: 'Wahoo', 36: 'Bryton', 38: 'Cateye', 40: 'Mio', 48: 'Favero',
  63: 'Magene', 69: 'Lezyne', 70: 'Giant', 71: 'Shimano', 76: 'Stages',
  85: 'Wahoo', 86: 'Sigma', 89: 'Shimano', 95: 'Tacx', 96: 'Polar',
  104: 'Suunto', 110: 'Zwift', 119: 'iGPSPORT', 255: 'Development',
  258: 'Rotor', 259: 'Elite', 263: 'SRAM AXS', 267: '4iiii', 268: 'Power2Max', 269: 'InfoCrank',
  278: 'Campagnolo', 284: 'Wahoo', 286: 'Xplova', 294: 'Hammerhead',
  296: 'Kinetic', 297: 'Bkool', 312: 'CycleOps', 345: 'Xoss',
};

// ANT+ device type IDs → human names
const _FIT_DEVICE_TYPE = {
  0: 'Antfs',
  1: 'ANT+ Sensor',
  11: 'Bike Power',
  12: 'Environment',
  15: 'Multi-Sport Speed & Distance',
  17: 'Fitness Equipment',
  119: 'Heart Rate',
  120: 'Bike Speed & Cadence',
  121: 'Bike Cadence',
  122: 'Bike Speed',
  123: 'Stride Speed & Distance',
  124: 'Light',
  35: 'Gear Shifter',
  36: 'Light Hub',
  38: 'Radar',
  40: 'Dropper Seatpost',
};

// SRAM AXS product IDs → component names
const _SRAM_PRODUCTS = {
  1: 'Rear Derailleur',
  2: 'Front Derailleur',
  3: 'Left Shifter',
  4: 'Right Shifter',
  5: 'Left Blip',
  6: 'Right Blip',
  7: 'Dropper Post',
  8: 'Rocker Paddle',
  9: 'AXS Controller',
};

// Shimano Di2 product IDs → component names
const _SHIMANO_PRODUCTS = {
  1: 'Rear Derailleur',
  2: 'Front Derailleur',
  3: 'Left Shifter',
  4: 'Right Shifter',
  5: 'System Unit',
  6: 'Battery (Di2)',
  7: 'Junction Box',
};

// Get a friendly device name from FIT data
function _fitDeviceName(mfrId, productId, deviceType) {
  const mfrName = _FIT_MFR[mfrId] || '';
  // SRAM-specific product names
  if ((mfrId === 7 || mfrId === 263) && _SRAM_PRODUCTS[productId]) {
    return `SRAM ${_SRAM_PRODUCTS[productId]}`;
  }
  // SRAM AXS with no product ID — aggregated system battery
  if (mfrId === 263 && !productId) {
    return 'SRAM AXS System';
  }
  // Shimano-specific product names
  if ((mfrId === 71 || mfrId === 89) && _SHIMANO_PRODUCTS[productId]) {
    return `Shimano ${_SHIMANO_PRODUCTS[productId]}`;
  }
  // Garmin head units
  if ((mfrId === 1 || mfrId === 2) && deviceType == null) {
    return 'Garmin Head Unit';
  }
  // ANT+ device type fallback
  if (deviceType != null && _FIT_DEVICE_TYPE[deviceType]) {
    return mfrName ? `${mfrName} ${_FIT_DEVICE_TYPE[deviceType]}` : _FIT_DEVICE_TYPE[deviceType];
  }
  // If we have a manufacturer name, use it
  if (mfrName) return mfrName;
  // Unknown manufacturer — show ID for identification
  return mfrId ? `Unknown Sensor (${mfrId})` : 'Internal Sensor';
}

// After activity sync: extract battery data from the most recent ride's FIT file
async function _syncBatteryFromLastRide() {
  const bats = loadGearBatteries();
  if (!bats.length) return; // no batteries tracked — skip

  const acts = state.activities || [];
  if (!acts.length) return;

  // Find cycling activities
  const rides = acts.filter(a => {
    const t = (a.type || '').toLowerCase();
    return t.includes('ride') || t.includes('cycling');
  });
  if (!rides.length) return;

  // Check if we already synced the most recent ride
  const lastExtracted = localStorage.getItem('icu_bat_last_fit_id');
  if (lastExtracted === rides[0].id) return;

  // Process up to 10 uncached rides per sync (gradual backfill)
  let toProcess = [];
  for (const ride of rides) {
    const cached = await _fitCacheGet(ride.id);
    if (!cached) toProcess.push(ride);
    if (toProcess.length >= 10) break;
  }
  // Always include the most recent ride even if cached (for fresh battery data)
  if (!toProcess.find(r => r.id === rides[0].id)) toProcess.unshift(rides[0]);

  const allReadings = [];
  // Process sequentially with small delay to avoid rate limiting
  for (const ride of toProcess) {
    try {
      const fitData = await _fetchParsedFIT(ride.id); // uses cache if available
      if (!fitData || !fitData.devices) continue;
      const readings = fitData.devices
        .filter(d => d.voltage || d.batStatus)
        .map(d => ({
          voltage: d.voltage,
          status: _batStatusText(d.batStatus),
          percent: _voltageToPercent(d.voltage),
          manufacturer: _FIT_MFR[d.manufacturer] || d.manufacturer,
          product: d.product,
          deviceType: d.deviceType,
          activityId: ride.id,
          date: (ride.start_date_local || ride.start_date || '').slice(0, 10),
        }));
      allReadings.push(...readings);
      // Small delay between downloads to avoid rate limiting
      await new Promise(r => setTimeout(r, 500));
    } catch (e) {
      console.warn('Battery sync failed for', ride.id, e.message);
    }
  }

  if (allReadings.length) {
    // Deduplicate: keep most recent reading per manufacturer+product combo
    const best = new Map();
    for (const r of allReadings) {
      const key = `${r.manufacturer}_${r.product}_${r.deviceType}`;
      const existing = best.get(key);
      if (!existing || r.date > existing.date) best.set(key, r);
    }
    const merged = [...best.values()];
    try {
      localStorage.setItem('icu_bat_fit_readings', JSON.stringify(merged));
      console.log('Battery readings from FIT:', merged);
    } catch (e) {}

    // Auto-update linked batteries with sensor data
    _syncFITReadingsToBatteries(merged);
  }

  localStorage.setItem('icu_bat_last_fit_id', rides[0].id);
}

// Sync FIT sensor readings to linked tracked batteries
function _syncFITReadingsToBatteries(readings) {
  const bats = loadGearBatteries();
  let changed = false;
  for (const bat of bats) {
    if (!bat.fitDeviceKey) continue;
    // Match by full key or partial key (for backward compat with old keys)
    const reading = readings.find(r => {
      const fullKey = `${r.manufacturer}_${r.product}_${r.deviceType ?? ''}_${r.serialNumber ?? ''}`;
      const shortKey = `${r.manufacturer}_${r.product}`;
      return fullKey === bat.fitDeviceKey || shortKey === bat.fitDeviceKey;
    });
    if (!reading) continue;
    // Store the sensor reading directly on the battery
    bat.fitSensorPercent = reading.percent;
    bat.fitSensorVoltage = reading.voltage;
    bat.fitSensorStatus = reading.status;
    bat.fitSensorDate = reading.date;
    changed = true;
  }
  if (changed) {
    saveGearBatteries(bats);
    // Re-render if on dashboard or gear page
    if (typeof _renderDashBatteries === 'function') _renderDashBatteries();
    if (typeof renderGearBatteries === 'function') renderGearBatteries();
  }
}

/* ── Charge calculation ── */

function calcBatteryPercent(bat) {
  // Prefer real sensor data from FIT file when linked and recent (< 7 days)
  if (bat.fitDeviceKey && bat.fitSensorPercent != null && bat.fitSensorDate) {
    const daysSinceSensor = (Date.now() - new Date(bat.fitSensorDate).getTime()) / 86400000;
    if (daysSinceSensor < 7) {
      return {
        percent: bat.fitSensorPercent,
        source: 'sensor',
        voltage: bat.fitSensorVoltage,
        status: bat.fitSensorStatus,
        sensorDate: bat.fitSensorDate,
      };
    }
  }

  if (bat.batteryType === 'coin_cell') return calcCoinCellPercent(bat);

  const sinceDate = new Date(bat.lastChargeDate);
  if (isNaN(sinceDate.getTime())) return null;

  // Gather all activities: cached + lifetime
  const allActs = [...(state.activities || []), ...(state.lifetimeActivities || [])];
  // Deduplicate by id
  const seen = new Set();
  const acts = allActs.filter(a => {
    if (!a || !a.id || seen.has(a.id)) return false;
    seen.add(a.id);
    const aDate = new Date(a.start_date_local || a.start_date);
    if (isNaN(aDate.getTime()) || aDate <= sinceDate) return false;
    // Filter by bike if set
    if (bat.bikeId && a.gear_id && a.gear_id !== bat.bikeId) return false;
    // Only cycling activities
    const t = (a.type || '').toLowerCase();
    if (!t.includes('ride') && !t.includes('cycling') && !t.includes('ebikeride')) return false;
    return true;
  });

  if (bat.ratedLifeHours) {
    let totalH = 0;
    acts.forEach(a => {
      const s = a.moving_time || a.elapsed_time || a.icu_moving_time || 0;
      totalH += s / 3600;
    });
    const usedPct = Math.min(100, Math.round((totalH / bat.ratedLifeHours) * 100));
    return { percent: Math.max(0, 100 - usedPct), usedHours: totalH, ratedHours: bat.ratedLifeHours, count: acts.length };
  }

  if (bat.ratedLifeKm) {
    let totalKm = 0;
    acts.forEach(a => {
      const d = a.distance || a.icu_distance || 0;
      totalKm += d > 1000 ? d / 1000 : d; // handle both m and km
    });
    const usedPct = Math.min(100, Math.round((totalKm / bat.ratedLifeKm) * 100));
    return { percent: Math.max(0, 100 - usedPct), usedKm: totalKm, ratedKm: bat.ratedLifeKm, count: acts.length };
  }

  return null;
}

function calcCoinCellPercent(bat) {
  const spec = BATTERY_SYSTEMS[bat.system]?.components[bat.componentType];
  const lifeYears = spec?.lifeYears || 2;
  const lifeDays = lifeYears * 365;
  const since = new Date(bat.lastChargeDate || bat.installDate);
  if (isNaN(since.getTime())) return null;
  const elapsed = (Date.now() - since.getTime()) / (1000 * 60 * 60 * 24);
  const usedPct = Math.min(100, Math.round((elapsed / lifeDays) * 100));
  return { percent: Math.max(0, 100 - usedPct), elapsedDays: Math.round(elapsed), lifeDays, isCoinCell: true };
}

function batteryColor(pct) {
  if (pct > 50)  return 'var(--accent)';
  if (pct > 25)  return C_YELLOW;
  if (pct > 10)  return C_ORANGE;
  return 'var(--red)';
}
function batteryColorClass(pct) {
  if (pct > 50)  return 'battery--green';
  if (pct > 25)  return 'battery--yellow';
  if (pct > 10)  return 'battery--orange';
  return 'battery--red';
}

/* ── Rendering ── */

function renderGearBatteries() {
  const grid = document.getElementById('gearBatteriesGrid');
  if (!grid) return;

  const all = loadGearBatteries();
  const showObsolete = document.getElementById('batteryShowObsolete')?.checked;
  const toggleEl = document.getElementById('batteryObsoleteToggle');
  if (toggleEl) toggleEl.style.display = all.some(b => b.obsolete) ? '' : 'none';

  let filtered = showObsolete ? all : all.filter(b => !b.obsolete);
  if (_gearSelectedBike) filtered = filtered.filter(b => b.bikeId === _gearSelectedBike);

  if (!filtered.length) {
    grid.innerHTML = `<div class="gar-empty">No batteries tracked yet</div>`;
    return;
  }
  grid.innerHTML = filtered.map(b => batteryCard(b)).join('');
}

function batteryCard(bat) {
  const calc = calcBatteryPercent(bat);
  const pct = calc ? calc.percent : 100;
  const isObsolete = bat.obsolete;
  const fillCls = pct > 60 ? 'gar-bat-fill--green' : pct > 30 ? 'gar-bat-fill--yellow' : pct > 15 ? 'gar-bat-fill--orange' : 'gar-bat-fill--red';
  const pctColor = pct > 60 ? 'var(--accent)' : pct > 30 ? '#ffcc00' : pct > 15 ? '#ff9500' : 'var(--red)';

  let sub = '';
  if (calc) {
    if (calc.isCoinCell) {
      const mo = Math.max(0, Math.round((calc.lifeDays - calc.elapsedDays) / 30));
      sub = `~${mo} months left`;
    } else if (calc.usedHours !== undefined) {
      sub = `${calc.usedHours.toFixed(1)}h / ${calc.ratedHours}h`;
    } else if (calc.usedKm !== undefined) {
      sub = `${Math.round(calc.usedKm)} / ${calc.ratedKm} km`;
    }
  }
  if (bat.lastChargeDate) {
    const days = Math.round((Date.now() - new Date(bat.lastChargeDate).getTime()) / 86400000);
    sub += sub ? ` · ${days}d ago` : `Charged ${days}d ago`;
  }

  const sysLabel = BATTERY_SYSTEMS[bat.system]?.label || '';
  const bike = _gearBikeCache.find(b => b.id === bat.bikeId);

  // Component image for SRAM AXS shifters/derailleurs
  const isSramShifter = bat.system === 'sram_axs' && (bat.componentType === 'shifter_left' || bat.componentType === 'shifter_right');
  const isSramDerailleur = bat.system === 'sram_axs' && (bat.componentType === 'rear_derailleur' || bat.componentType === 'front_derailleur' || bat.componentType === 'rear_derailleur_eagle');
  let imgHtml;
  if (isSramShifter) {
    const src = bat.componentType === 'shifter_left' ? 'img/components/sram/rival-ed-left-front.webp' : 'img/components/sram/rival-ed-right-front.webp';
    imgHtml = `<img src="${src}" alt="${bat.name}" style="width:100%;height:100%;object-fit:contain">`;
  } else if (isSramDerailleur) {
    const dSrc = bat.componentType === 'front_derailleur' ? 'img/components/sram/front-derailleur.webp' : 'img/components/sram/rear-derailleur.webp';
    imgHtml = `<img src="${dSrc}" alt="${bat.name}" style="width:100%;height:100%;object-fit:contain">`;
  } else {
    imgHtml = `<div class="gar-bat-visual">
      <div class="gar-bat-terminal"></div>
      <div class="gar-bat-body"><div class="gar-bat-fill ${fillCls}" style="height:${Math.max(8, pct)}%"></div></div>
    </div>`;
  }

  const hasComponentImg = isSramShifter || isSramDerailleur;

  // Battery drain sparkline (last 5 charge events approximated)
  const sparkW = 80, sparkH = 28;
  let sparkSvg = '';
  if (bat.chargeHistory?.length > 1) {
    const pts = bat.chargeHistory.slice(-6).map((c, i, a) => {
      const x = (i / (a.length - 1)) * sparkW;
      const y = sparkH - (c.pct / 100) * sparkH;
      return `${x},${y}`;
    }).join(' ');
    sparkSvg = `<svg width="${sparkW}" height="${sparkH}" viewBox="0 0 ${sparkW} ${sparkH}" class="gar-bat-spark">
      <polyline points="${pts}" fill="none" stroke="${pctColor}" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
    </svg>`;
  }

  const hasUndo = !!bat._prevChargeDate;
  return `<div class="gar-bat-card card card--clickable${isObsolete ? ' gar-bat-row--obsolete' : ''}" onclick="openBatDetailSheet('${bat.id}')">
    ${!isObsolete ? (hasUndo
      ? `<button class="gar-bat-charge-fab gar-bat-charge-fab--undo" title="Undo charge" onclick="event.stopPropagation();undoChargeBattery('${bat.id}')">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" width="14" height="14"><path d="M3 10h10a5 5 0 0 1 0 10H12"/><polyline points="7 6 3 10 7 14"/></svg>
        </button>`
      : `<button class="gar-bat-charge-fab" title="Charge" onclick="event.stopPropagation();chargeBattery('${bat.id}')">
          <svg class="icon" width="14" height="14"><use href="icons.svg#icon-bolt"/></svg>
        </button>`) : ''}
    <div class="gar-bat-card-top">
      <div class="gar-bat-img${hasComponentImg ? '' : ' gar-bat-img--icon'}">${imgHtml}</div>
      <div class="gar-bat-card-info">
        <div class="gar-bat-name">${bat.name || 'Battery'}</div>
        ${bike?.name ? `<span class="gar-bat-bike-pill">${bike.name}</span>` : ''}
        <div class="gar-bat-sub">${sub}</div>
      </div>
      <div class="gar-bat-card-pct" style="color:${pctColor}">${pct}%</div>
    </div>
    <div class="gar-bat-card-bar">
      <div class="gar-bat-card-fill ${fillCls}" style="width:${Math.max(2, pct)}%"></div>
    </div>
    ${sparkSvg ? `<div class="gar-bat-card-bottom">${sparkSvg}</div>` : ''}
  </div>`;
}

/* ── Battery Modal ── */

function _ensureBatteryModal() {
  if (document.getElementById('batteryModal')) return;
  const d = document.createElement('div');
  d.className = 'wxd-overlay'; d.id = 'batteryModal'; d.style.display = 'none';
  d.innerHTML = `<div class="wxd-backdrop" onclick="closeBatteryModal()"></div>
    <div class="wxd-sheet" style="max-width:520px">
      <div class="wxd-floating-close"><button class="modal-close" onclick="closeBatteryModal()" aria-label="Close"><svg class="icon"><use href="icons.svg#icon-x"/></svg></button></div>
      <div class="modal-drag-indicator"></div>
      <div class="modal-header">
        <div class="modal-header-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" width="22" height="22"><rect x="6" y="4" width="12" height="18" rx="2"/><line x1="10" y1="1" x2="14" y2="1" stroke-width="3" stroke-linecap="round"/><rect x="8" y="12" width="8" height="8" rx="1" fill="currentColor" opacity="0.3"/></svg></div>
        <div class="modal-title" id="batteryModalTitle">Add Battery</div>
        <div class="modal-desc">Track an electronic shifting battery or power pack.</div>
      </div>
      <div class="modal-body">
        <input type="hidden" id="batteryEditId">
        <div class="gear-form-grid">
          <div class="field"><label for="batteryFormBike">BIKE</label><select id="batteryFormBike" class="app-select"><option value="">Select bike</option></select></div>
          <div class="field"><label for="batteryFormSystem">SYSTEM</label><select id="batteryFormSystem" class="app-select" onchange="onBatterySystemChange()"><option value="">— Select system —</option></select></div>
          <div class="field"><label for="batteryFormComponent">COMPONENT</label><select id="batteryFormComponent" class="app-select" onchange="onBatteryComponentChange()"><option value="">— Select component —</option></select></div>
          <div class="field"><label for="batteryFormName">DISPLAY NAME</label><input type="text" id="batteryFormName" placeholder="e.g. Rear Derailleur Battery" aria-label="Battery name"></div>
          <div class="field"><label for="batteryFormChargeDate">LAST CHARGED / REPLACED</label><input type="date" id="batteryFormChargeDate"></div>
          <div class="field"><label for="batteryFormInstallDate">INSTALL DATE</label><input type="date" id="batteryFormInstallDate"></div>
          <div class="field" id="batteryRatedHoursField"><label for="batteryFormRatedHours">RATED LIFE (HOURS)</label><input type="number" id="batteryFormRatedHours" placeholder="60" min="1" step="1"><div class="field-hint">Manufacturer-rated riding hours per charge</div></div>
          <div class="field" id="batteryRatedKmField" style="display:none"><label for="batteryFormRatedKm">RATED LIFE (KM)</label><input type="number" id="batteryFormRatedKm" placeholder="1000" min="1" step="100"><div class="field-hint">Manufacturer-rated km per charge</div></div>
          <div class="field" style="grid-column:1/-1"><label for="batteryFormNotes">NOTES</label><input type="text" id="batteryFormNotes" placeholder="Optional notes..." aria-label="Battery notes"></div>
        </div>
        <div style="display:flex;gap:10px;margin-top:8px"><button class="btn btn-primary" style="flex:1" onclick="submitBatteryForm()">Save Battery</button><button class="btn btn-ghost" onclick="closeBatteryModal()">Cancel</button></div>
      </div>
    </div>`;
  document.body.appendChild(d);
}

function openBatteryModal(editId) {
  _ensureBatteryModal();
  const modal = document.getElementById('batteryModal');
  const titleEl = document.getElementById('batteryModalTitle');
  document.getElementById('batteryEditId').value = editId || '';

  // Populate system dropdown
  const sysSel = document.getElementById('batteryFormSystem');
  sysSel.innerHTML = '<option value="">Select system</option>' +
    Object.entries(BATTERY_SYSTEMS).map(([k, v]) => `<option value="${k}">${v.label}</option>`).join('');

  // Populate bike dropdown from cache
  const bikeSel = document.getElementById('batteryFormBike');
  bikeSel.innerHTML = '<option value="">Select bike</option>' +
    _gearBikeCache.map(b => `<option value="${b.id}">${b.name}</option>`).join('');

  // Reset component dropdown
  document.getElementById('batteryFormComponent').innerHTML = '<option value="">Select component</option>';

  if (editId) {
    titleEl.textContent = 'Edit Battery';
    const bat = loadGearBatteries().find(b => b.id === editId);
    if (bat) {
      bikeSel.value = bat.bikeId || '';
      sysSel.value = bat.system || '';
      onBatterySystemChange(); // populate components
      document.getElementById('batteryFormComponent').value = bat.componentType || '';
      document.getElementById('batteryFormName').value = bat.name || '';
      document.getElementById('batteryFormChargeDate').value = bat.lastChargeDate || '';
      document.getElementById('batteryFormInstallDate').value = bat.installDate || '';
      document.getElementById('batteryFormRatedHours').value = bat.ratedLifeHours || '';
      document.getElementById('batteryFormRatedKm').value = bat.ratedLifeKm || '';
      document.getElementById('batteryFormNotes').value = bat.notes || '';
      // Show correct rated field
      const spec = BATTERY_SYSTEMS[bat.system]?.components[bat.componentType];
      const useKm = spec ? (spec.ratedKm && !spec.ratedHours) : !!bat.ratedLifeKm;
      document.getElementById('batteryRatedHoursField').style.display = useKm ? 'none' : '';
      document.getElementById('batteryRatedKmField').style.display = useKm ? '' : 'none';
    }
  } else {
    titleEl.textContent = 'Add Battery';
    document.getElementById('batteryFormName').value = '';
    document.getElementById('batteryFormChargeDate').value = new Date().toISOString().split('T')[0];
    document.getElementById('batteryFormInstallDate').value = new Date().toISOString().split('T')[0];
    document.getElementById('batteryFormRatedHours').value = '';
    document.getElementById('batteryFormRatedKm').value = '';
    document.getElementById('batteryFormNotes').value = '';
    document.getElementById('batteryRatedHoursField').style.display = '';
    document.getElementById('batteryRatedKmField').style.display = 'none';
    // Pre-select bike if filtered
    if (_gearSelectedBike) bikeSel.value = _gearSelectedBike;
  }

  _openOverlaySheet('batteryModal');
  refreshCustomDropdowns(modal);
  _gearHookPickerSheets(modal);
  _gearHookDatePickers(modal);
}

function closeBatteryModal() {
  _closeOverlaySheet('batteryModal');
}

function onBatterySystemChange() {
  const sysKey = document.getElementById('batteryFormSystem').value;
  const compSel = document.getElementById('batteryFormComponent');
  const sys = BATTERY_SYSTEMS[sysKey];

  if (!sys) {
    compSel.innerHTML = '<option value="">Select component</option>';
    return;
  }

  compSel.innerHTML = '<option value="">Select component</option>' +
    Object.entries(sys.components).map(([k, v]) => `<option value="${k}">${v.label}</option>`).join('');
}

function onBatteryComponentChange() {
  const sysKey = document.getElementById('batteryFormSystem').value;
  const compKey = document.getElementById('batteryFormComponent').value;
  const spec = BATTERY_SYSTEMS[sysKey]?.components[compKey];
  if (!spec) return;

  // Auto-fill name
  const nameEl = document.getElementById('batteryFormName');
  if (!nameEl.value) nameEl.value = spec.label;

  // Show correct rated life field and auto-fill
  const useKm = spec.ratedKm && !spec.ratedHours;
  document.getElementById('batteryRatedHoursField').style.display = useKm ? 'none' : '';
  document.getElementById('batteryRatedKmField').style.display = useKm ? '' : 'none';

  if (spec.ratedHours) document.getElementById('batteryFormRatedHours').value = spec.ratedHours;
  if (spec.ratedKm) document.getElementById('batteryFormRatedKm').value = spec.ratedKm;
}

function submitBatteryForm() {
  const name = document.getElementById('batteryFormName').value.trim();
  const system = document.getElementById('batteryFormSystem').value;
  if (!name) { showToast('Please enter a display name', 'error'); return; }
  if (!system) { showToast('Please select a system', 'error'); return; }

  const editId = document.getElementById('batteryEditId').value;
  const spec = BATTERY_SYSTEMS[system]?.components[document.getElementById('batteryFormComponent').value];

  const bat = {
    id:             editId || ('bat_' + Date.now() + '_' + Math.random().toString(36).slice(2, 7)),
    bikeId:         document.getElementById('batteryFormBike').value,
    system:         system,
    componentType:  document.getElementById('batteryFormComponent').value,
    name:           name,
    lastChargeDate: document.getElementById('batteryFormChargeDate').value,
    installDate:    document.getElementById('batteryFormInstallDate').value,
    ratedLifeHours: parseFloat(document.getElementById('batteryFormRatedHours').value) || null,
    ratedLifeKm:    parseFloat(document.getElementById('batteryFormRatedKm').value) || null,
    batteryType:    spec?.type || 'rechargeable',
    notes:          document.getElementById('batteryFormNotes').value.trim(),
    obsolete:       false,
    obsoleteDate:   null,
  };

  // Link to FIT device if adding from activity page
  if (window._pendingFitDeviceKey) {
    bat.fitDeviceKey = window._pendingFitDeviceKey;
    window._pendingFitDeviceKey = null;
  }

  const all = loadGearBatteries();
  const idx = all.findIndex(b => b.id === editId);
  if (idx >= 0) {
    bat.obsolete = all[idx].obsolete;
    bat.obsoleteDate = all[idx].obsoleteDate;
    if (all[idx].fitDeviceKey && !bat.fitDeviceKey) bat.fitDeviceKey = all[idx].fitDeviceKey;
    all[idx] = bat;
  } else {
    all.push(bat);
  }

  saveGearBatteries(all);
  closeBatteryModal();
  renderGearBatteries();
  showToast(editId ? 'Battery updated' : 'Battery added', 'success');
}

/* ── Battery actions ── */

function chargeBattery(id) {
  const all = loadGearBatteries();
  const bat = all.find(b => b.id === id);
  if (!bat) return;
  const calc = calcBatteryPercent(bat);
  const pct = calc ? calc.percent : 50;
  const isCoin = bat.batteryType === 'coin_cell';
  const fillCls = pct > 60 ? 'green' : pct > 30 ? 'yellow' : pct > 15 ? 'orange' : 'red';
  const fillColors = { green: 'var(--accent)', yellow: '#ffcc00', orange: '#ff9500', red: 'var(--red)' };

  // Create overlay
  let ov = document.getElementById('_batChargeOverlay');
  if (ov) ov.remove();
  ov = document.createElement('div');
  ov.id = '_batChargeOverlay';
  ov.className = 'bat-charge-overlay';
  ov.innerHTML = `
    <div class="bat-charge-backdrop"></div>
    <div class="bat-charge-popup">
      <div class="bat-charge-name">${bat.name}</div>
      <div class="bat-charge-battery">
        <div class="bat-charge-terminal"></div>
        <div class="bat-charge-body">
          <div class="bat-charge-fill" style="height:${Math.max(8, pct)}%;background:${fillColors[fillCls]}"></div>
        </div>
        <div class="bat-charge-pct">${pct}%</div>
      </div>
      <div class="bat-charge-bolt">
        <svg class="icon" width="20" height="20"><use href="icons.svg#icon-bolt"/></svg>
      </div>
      <button class="bat-charge-btn" id="_batChargeBtn">${isCoin ? 'Replace Battery' : 'Charge Now'}</button>
      <button class="bat-charge-cancel" onclick="document.getElementById('_batChargeOverlay')?.remove()">Cancel</button>
    </div>`;
  document.body.appendChild(ov);
  requestAnimationFrame(() => ov.classList.add('bat-charge-open'));

  document.getElementById('_batChargeBtn').onclick = () => {
    const fill = ov.querySelector('.bat-charge-fill');
    const pctEl = ov.querySelector('.bat-charge-pct');
    const body = ov.querySelector('.bat-charge-body');
    const btn = document.getElementById('_batChargeBtn');
    btn.disabled = true;
    btn.textContent = 'Charging...';

    // Animate fill to 100%
    fill.style.transition = 'height 1.2s cubic-bezier(0.34, 1.56, 0.64, 1), background 0.5s';
    fill.style.height = '100%';
    fill.style.background = 'var(--accent)';

    // Animate percentage count-up
    let cur = pct;
    const step = Math.max(1, Math.round((100 - pct) / 24));
    const countUp = setInterval(() => {
      cur = Math.min(100, cur + step);
      pctEl.textContent = cur + '%';
      if (cur >= 100) {
        clearInterval(countUp);
        pctEl.textContent = '100%';
      }
    }, 50);

    // After fill completes — glow effect
    setTimeout(() => {
      body.classList.add('bat-charge-glow');
      pctEl.style.color = 'var(--accent)';
      btn.textContent = isCoin ? 'Replaced!' : 'Charged!';

      // Save and close — store previous charge date for undo
      setTimeout(() => {
        bat._prevChargeDate = bat.lastChargeDate || null;
        bat.lastChargeDate = new Date().toISOString().split('T')[0];
        saveGearBatteries(all);
        ov.classList.remove('bat-charge-open');
        setTimeout(() => {
          ov.remove();
          renderGearBatteries();
          if (typeof _renderDashBatteries === 'function') _renderDashBatteries();
        }, 300);
      }, 800);
    }, 1300);
  };
}
window.chargeBattery = chargeBattery;


function openBatDetailSheet(id) {
  const all = loadGearBatteries();
  const bat = all.find(b => b.id === id);
  if (!bat) return;

  const calc = (typeof calcBatteryPercent === 'function') ? calcBatteryPercent(bat) : null;
  const pct = calc ? Math.round(typeof calc === 'object' ? calc.percent : calc) : null;
  const pctColor = pct === null ? 'var(--text-muted)' : pct > 60 ? 'var(--accent)' : pct > 30 ? '#ffcc00' : pct > 15 ? '#ff9500' : 'var(--red)';
  const fillCls = pct > 60 ? 'gar-bat-fill--green' : pct > 30 ? 'gar-bat-fill--yellow' : pct > 15 ? 'gar-bat-fill--orange' : 'gar-bat-fill--red';

  // Image
  const isSramShifter = bat.system === 'sram_axs' && (bat.componentType === 'shifter_left' || bat.componentType === 'shifter_right');
  const isSramDerailleur = bat.system === 'sram_axs' && (bat.componentType === 'rear_derailleur' || bat.componentType === 'front_derailleur' || bat.componentType === 'rear_derailleur_eagle');
  let imgSrc = '';
  if (isSramShifter) imgSrc = bat.componentType === 'shifter_left' ? 'img/components/sram/rival-ed-left-front.webp' : 'img/components/sram/rival-ed-right-front.webp';
  else if (isSramDerailleur) imgSrc = bat.componentType === 'front_derailleur' ? 'img/components/sram/front-derailleur.webp' : 'img/components/sram/rear-derailleur.webp';
  else imgSrc = _gearGetCategoryImage(bat.name, bat.componentType) || '';

  const imgHtml = imgSrc
    ? `<div class="comp-detail-img"><img src="${imgSrc}" alt="${bat.name}" style="object-fit:contain"></div>`
    : `<div class="comp-detail-img" style="background:rgba(0,229,160,0.1);display:flex;align-items:center;justify-content:center">
        <svg class="icon" width="40" height="40" style="stroke:var(--accent)"><use href="icons.svg#icon-battery"/></svg>
      </div>`;

  // Info
  const gear = state.gearBikes || [];
  const bike = gear.find(g => g.id === bat.bikeId);
  const system = bat.system === 'sram_axs' ? 'SRAM AXS' : bat.system === 'shimano_di2' ? 'Shimano Di2' : bat.system || '';
  const batType = bat.batteryType === 'coin_cell' ? 'Coin Cell (CR2032)' : bat.batteryType === 'rechargeable' ? 'Rechargeable' : bat.batteryType || '';

  // Rows
  const rows = [];
  if (system) rows.push(['System', system]);
  if (bike) rows.push(['Bike', bike.name]);
  if (batType) rows.push(['Type', batType]);
  if (bat.lastChargeDate) {
    const d = new Date(bat.lastChargeDate);
    rows.push(['Last Charged', d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })]);
  }
  if (bat.installDate) {
    const d = new Date(bat.installDate);
    rows.push(['Installed', d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })]);
  }
  if (bat.ratedLifeHours) rows.push(['Rated Life', bat.ratedLifeHours + ' hours']);
  if (bat.notes) rows.push(['Notes', bat.notes]);

  const batBodyHtml = `
    ${imgHtml}
    <div class="comp-detail-name">${bat.name || 'Battery'}</div>
    ${system ? `<div class="comp-detail-brand">${system}</div>` : ''}

    <div class="cd-bat-gauge">
      <div class="cd-bat-gauge-body">
        ${[1,2,3,4,5].map(i => {
          const segThreshold = i * 20;
          const active = (pct || 0) >= segThreshold - 10;
          return `<div class="cd-bat-gauge-seg${active ? ' cd-bat-gauge-seg--active' : ''}" style="${active ? 'background:' + pctColor : ''}"></div>`;
        }).join('')}
      </div>
      <div class="cd-bat-gauge-tip"></div>
      <div class="cd-bat-gauge-pct" style="color:${pctColor}">${pct !== null ? pct + '%' : '—'}</div>
    </div>

    ${rows.length ? `<div class="cd-section-title">Details</div>
    <div class="comp-detail-rows">
      ${rows.map(([l, v]) => `<div class="comp-detail-row"><span class="comp-detail-label">${l}</span><span class="comp-detail-val">${v}</span></div>`).join('')}
    </div>` : ''}

    <div class="comp-detail-actions">
      <button class="btn btn-ghost" style="flex:1" onclick="closeBatDetailSheet();chargeBattery('${bat.id}')">
        <svg class="icon" width="16" height="16"><use href="icons.svg#icon-bolt"/></svg>
        Charge
      </button>
      <button class="btn btn-ghost" style="flex:1" onclick="closeBatDetailSheet();openBatteryModal('${bat.id}')">
        <svg class="icon" width="16" height="16"><use href="icons.svg#icon-edit"/></svg>
        Edit
      </button>
      <button class="btn btn-ghost" style="flex:1;color:var(--red)" onclick="closeBatDetailSheet();deleteBattery('${bat.id}')">
        <svg class="icon" width="16" height="16"><use href="icons.svg#icon-trash"/></svg>
        Delete
      </button>
    </div>`;

  _openUniSheet({
    title: bat.name || 'Battery',
    body: batBodyHtml,
    maxWidth: 480,
    partial: true,
    hideHeader: true
  });
}

function closeBatDetailSheet() {
  _closeUniSheet();
}
function deleteBattery(id) {
  const all = loadGearBatteries();
  const idx = all.findIndex(b => b.id === id);
  if (idx < 0) return;
  all.splice(idx, 1);
  saveGearBatteries(all);
  renderGearBatteries();
  _renderDashBatteries();
  showToast('Battery deleted', 'success');
}

window.openBatDetailSheet = openBatDetailSheet;
window.closeBatDetailSheet = closeBatDetailSheet;
window.deleteBattery = deleteBattery;

// ── 3D Badge Viewer ──
let _badges3dModule = null;
let _badgeViewerList = []; // earned badges for navigation
let _badgeViewerIdx = 0;

async function openBadgeViewer(badgeId, name, desc) {
  // Build earned badges list if not set
  if (!_badgeViewerList.length) {
    document.querySelectorAll('.stk-badge--earned').forEach(el => {
      const onclick = el.getAttribute('onclick') || '';
      const m = onclick.match(/openBadgeViewer\('([^']+)','([^']+)','([^']+)'\)/);
      if (m) _badgeViewerList.push({ id: m[1], name: m[2], desc: m[3] });
    });
  }
  _badgeViewerIdx = _badgeViewerList.findIndex(b => b.id === badgeId);
  if (_badgeViewerIdx < 0) _badgeViewerIdx = 0;

  const count = _badgeViewerList.length;
  const bodyHtml = `
    <div style="position:relative">
      <canvas id="badge3dCanvas" style="width:100%;height:480px;touch-action:none;cursor:grab;border-radius:16px"></canvas>
      ${count > 1 ? `
        <button class="badge-nav-btn badge-nav-prev badge-nav-btn--desktop" onclick="_badgeNavPrev()" aria-label="Previous">
          <svg class="icon" width="20" height="20"><use href="icons.svg#icon-chevron-left"/></svg>
        </button>
        <button class="badge-nav-btn badge-nav-next badge-nav-btn--desktop" onclick="_badgeNavNext()" aria-label="Next">
          <svg class="icon" width="20" height="20"><use href="icons.svg#icon-chevron-right"/></svg>
        </button>
        <div class="badge-nav-row">
          <button class="badge-nav-btn badge-nav-btn--mobile" onclick="_badgeNavPrev()" aria-label="Previous">
            <svg class="icon" width="20" height="20"><use href="icons.svg#icon-chevron-left"/></svg>
          </button>
          <div class="badge-nav-dots" id="badgeNavDots">
            ${_badgeViewerList.map((_, i) => `<span class="badge-nav-dot${i === _badgeViewerIdx ? ' active' : ''}"></span>`).join('')}
          </div>
          <button class="badge-nav-btn badge-nav-btn--mobile" onclick="_badgeNavNext()" aria-label="Next">
            <svg class="icon" width="20" height="20"><use href="icons.svg#icon-chevron-right"/></svg>
          </button>
        </div>
      ` : ''}
      <div class="badge-viewer-info" id="badgeViewerInfo">
        <div class="badge-viewer-name" id="badgeViewerName">${_escHtml(name)}</div>
        <div class="badge-viewer-desc" id="badgeViewerDesc">${_escHtml(desc)}</div>
        <button class="badge-share-btn" onclick="_shareBadge()">
          <svg class="icon" width="16" height="16"><use href="icons.svg#icon-share"/></svg>
          Share
        </button>
      </div>
    </div>`;
  const isDesktop = window.innerWidth > 700;
  if (isDesktop) {
    // Floating centered dialog on desktop
    let overlay = document.getElementById('badgeDialogOverlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'badgeDialogOverlay';
      overlay.className = 'badge-dialog-overlay';
      overlay.innerHTML = `<div class="badge-dialog" id="badgeDialog"></div>`;
      overlay.addEventListener('click', e => { if (e.target === overlay) closeBadgeViewer(); });
      document.body.appendChild(overlay);
    }
    const dialog = document.getElementById('badgeDialog');
    dialog.innerHTML = bodyHtml;
    overlay.style.display = 'flex';
    requestAnimationFrame(() => overlay.classList.add('badge-dialog--open'));
  } else {
    _openUniSheet({ id: 'badgeViewer', body: bodyHtml, partial: true, maxWidth: 400, hideHeader: true,
      onClose: () => { const p = document.getElementById('_uniSheetPanel'); p.style.background = ''; p.style.overflow = ''; }
    });
    const _bp = document.getElementById('_uniSheetPanel');
    _bp.style.background = 'linear-gradient(to bottom,#1a1a1a,#0a0a0a)';
    _bp.style.overflow = 'hidden';
  }

  await _loadBadgeCard(badgeId, name, desc);
}

async function _loadBadgeCard(badgeId, name, desc) {
  if (!_badges3dModule) _badges3dModule = await import('./js/badges3d.js');
  try { if (_badges3dModule.destroyBadgeCard3D) _badges3dModule.destroyBadgeCard3D(); } catch(_){}

  // Replace canvas to get a fresh WebGL context
  const old = document.getElementById('badge3dCanvas');
  if (!old) return;
  const fresh = document.createElement('canvas');
  fresh.id = 'badge3dCanvas';
  fresh.style.cssText = old.style.cssText;
  old.replaceWith(fresh);

  // Update dots + info text
  const dots = document.getElementById('badgeNavDots');
  if (dots) dots.querySelectorAll('.badge-nav-dot').forEach((d, i) => d.classList.toggle('active', i === _badgeViewerIdx));
  const nameEl = document.getElementById('badgeViewerName');
  const descEl = document.getElementById('badgeViewerDesc');
  if (nameEl) nameEl.textContent = name;
  if (descEl) descEl.textContent = desc;

  await new Promise(r => setTimeout(r, 50));

  try {
    await _badges3dModule.initBadgeCard3D(fresh, badgeId, name, desc);
  } catch (e) {
    console.error('3D badge failed:', e);
    fresh.style.background = 'var(--surface-1)';
  }

}

function _badgeNavPrev() {
  if (!_badgeViewerList.length) return;
  _badgeViewerIdx = (_badgeViewerIdx - 1 + _badgeViewerList.length) % _badgeViewerList.length;
  const b = _badgeViewerList[_badgeViewerIdx];
  _loadBadgeCard(b.id, b.name, b.desc);
}

function _badgeNavNext() {
  if (!_badgeViewerList.length) return;
  _badgeViewerIdx = (_badgeViewerIdx + 1) % _badgeViewerList.length;
  const b = _badgeViewerList[_badgeViewerIdx];
  _loadBadgeCard(b.id, b.name, b.desc);
}

function closeBadgeViewer() {
  try { if (_badges3dModule?.destroyBadgeCard3D) _badges3dModule.destroyBadgeCard3D(); } catch(_){}
  try { if (_badges3dModule?.destroyBadge3D) _badges3dModule.destroyBadge3D(); } catch(_){}
  _badgeViewerList = [];
  // Close desktop dialog or mobile sheet
  const overlay = document.getElementById('badgeDialogOverlay');
  if (overlay) {
    overlay.classList.remove('badge-dialog--open');
    setTimeout(() => { overlay.style.display = 'none'; }, 300);
  }
  _closeUniSheet();
}
async function _shareBadge() {
  const b = _badgeViewerList[_badgeViewerIdx];
  if (!b) return;
  const text = `I earned the "${b.name}" badge on CycleIQ! 🏆 ${b.desc}`;
  if (navigator.share) {
    try { await navigator.share({ title: b.name, text }); } catch(_) {}
  } else {
    try { await navigator.clipboard.writeText(text); showToast('Copied to clipboard', 'success'); } catch(_) { showToast('Could not share', 'error'); }
  }
}
async function _openAchievementsPage() {
  const BADGES = window._allBadges || [];
  const earned = BADGES.filter(b => b.earned);
  const locked = BADGES.filter(b => !b.earned);

  const body = `
    <div style="padding:8px 0">
      <div style="font-size:13px;color:var(--text-muted);margin-bottom:16px">${earned.length} of ${BADGES.length} unlocked</div>
      ${earned.length ? `<div class="page-headline" style="margin-bottom:8px;font-size:15px">Earned</div>
      <div class="stk-badges-grid" id="achEarnedGrid">
        ${earned.map(b => `<div class="stk-badge stk-badge--earned" onclick="openBadgeViewer('${b.id}','${_escHtml(b.name)}','${_escHtml(b.desc)}')">
          <img class="stk-badge-preview" data-badge="${b.id}" alt="${_escHtml(b.name)}">
        </div>`).join('')}
      </div>` : ''}
      ${locked.length ? `<div class="page-headline" style="margin:20px 0 8px;font-size:15px">Locked</div>
      <div class="stk-badges-grid" id="achLockedGrid">
        ${locked.map(b => `<div class="stk-badge">
          <img class="stk-badge-preview" data-badge="${b.id}" alt="${_escHtml(b.name)}">
        </div>`).join('')}
      </div>` : ''}
    </div>`;

  _openUniSheet({ id: 'achievements', title: 'Achievements', body, partial: false });

  // Render previews + attach tilt
  let mod = null;
  try { mod = await import('./js/badges3d.js'); } catch(_) {}
  if (mod) {
    BADGES.forEach(b => {
      const img = document.querySelector(`#_uniSheetBody .stk-badge-preview[data-badge="${b.id}"]`);
      if (img) img.src = mod.renderBadgePreview(b.id, b.name, b.desc, !b.earned);
    });
  }
  const sheetBody = document.getElementById('_uniSheetBody');
  if (window.refreshBadgeTilt) refreshBadgeTilt(sheetBody);
  if (window.refreshGlow) refreshGlow(sheetBody);
}

window._openAchievementsPage = _openAchievementsPage;
window.openBadgeViewer = openBadgeViewer;
window._badgeNavPrev = _badgeNavPrev;
window._badgeNavNext = _badgeNavNext;
window._shareBadge = _shareBadge;
window.closeBadgeViewer = closeBadgeViewer;

function undoChargeBattery(id) {
  const all = loadGearBatteries();
  const bat = all.find(b => b.id === id);
  if (!bat || !bat._prevChargeDate) return;
  bat.lastChargeDate = bat._prevChargeDate;
  delete bat._prevChargeDate;
  saveGearBatteries(all);
  renderGearBatteries();
  if (typeof _renderDashBatteries === 'function') _renderDashBatteries();
  showToast('Charge undone', 'success');
}
window.undoChargeBattery = undoChargeBattery;

// ─────────────────────────────────────────────────────────────────────────────
// GEAR — BIKE SERVICE TRACKING
// ─────────────────────────────────────────────────────────────────────────────

const SERVICE_STORE_KEY = 'icu_gear_services';
const SERVICE_SHOP_STORE_KEY = 'icu_gear_service_shops';

function loadGearServices()   { try { return JSON.parse(localStorage.getItem(SERVICE_STORE_KEY)) || []; } catch { return []; } }
function saveGearServices(arr) { try { localStorage.setItem(SERVICE_STORE_KEY, JSON.stringify(arr)); } catch { showToast('Storage limit reached', 'error'); } }
function loadServiceShops()   { try { return JSON.parse(localStorage.getItem(SERVICE_SHOP_STORE_KEY)) || []; } catch { return []; } }
function saveServiceShops(arr) { try { localStorage.setItem(SERVICE_SHOP_STORE_KEY, JSON.stringify(arr)); } catch { showToast('Storage limit reached', 'error'); } }

// ── Resolve shop name & phone for a service record ──────────────────────────
function _resolveShop(svc) {
  if (svc.shopId) {
    const shop = loadServiceShops().find(s => s.id === svc.shopId);
    if (shop) return { name: shop.name, phone: shop.phone, address: shop.address };
  }
  return { name: svc.shopNameOverride || '', phone: svc.phoneOverride || '', address: '' };
}

// ── Calculate next-service progress ─────────────────────────────────────────
function calcServiceProgress(svc) {
  if (!svc.nextServiceMode) return null;
  let pct = 0, label = '', used = 0, target = 0, unit = '';
  if (svc.nextServiceMode === 'km') {
    const bike = _gearBikeCache.find(b => b.id === svc.bikeId);
    const currentKm = bike ? bike.km : 0;
    used = Math.max(0, currentKm - (svc.bikeKmAtService || 0));
    target = svc.nextServiceKm || 0;
    unit = 'km';
  } else if (svc.nextServiceMode === 'months') {
    const sDate = new Date(svc.serviceDate);
    const now = new Date();
    used = (now.getFullYear() - sDate.getFullYear()) * 12 + (now.getMonth() - sDate.getMonth());
    target = svc.nextServiceMonths || 0;
    unit = 'mo';
  }
  if (target <= 0) return null;
  pct = Math.min(100, Math.round(used / target * 100));
  const warn = pct >= 75;
  const overdue = pct >= 100;
  if (overdue) label = 'Service Due';
  else if (warn) label = 'Soon';
  else label = pct + '%';
  return { pct, label, warn, overdue, used: Math.round(used), target, unit };
}

// ── Service card HTML ───────────────────────────────────────────────────────
function serviceCard(bikeId, services) {
  const bike = _gearBikeCache.find(b => b.id === bikeId);
  const bikeName = bike ? bike.name : 'Unknown Bike';
  // Sort newest first
  const sorted = [...services].sort((a, b) => (b.serviceDate || '').localeCompare(a.serviceDate || ''));
  const latest = sorted[0];
  if (!latest) return '';

  const shop = _resolveShop(latest);
  const dateStr = latest.serviceDate ? new Date(latest.serviceDate + 'T12:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' }) : '—';
  const phoneHref = shop.phone ? shop.phone.replace(/[\s\-()]/g, '') : '';
  const prog = calcServiceProgress(latest);

  let cardClass = 'service-card';
  if (prog?.overdue) cardClass += ' service-card--overdue';
  else if (prog?.warn) cardClass += ' service-card--warn';

  const editSvg = `<svg class="icon" width="13" height="13"><use href="icons.svg#icon-edit"/></svg>`;
  const histSvg = `<svg class="icon" width="13" height="13"><use href="icons.svg#icon-activity"/></svg>`;
  const plusSvg = `<svg class="icon" width="13" height="13"><use href="icons.svg#icon-plus"/></svg>`;

  let barHtml = '';
  if (prog) {
    const color = prog.overdue ? 'var(--red)' : prog.warn ? '#f97316' : 'var(--accent)';
    const lblClass = prog.overdue ? ' gear-comp-bar-label--red' : prog.warn ? ' gear-comp-bar-label--warn' : '';
    barHtml = `
      <div class="service-card-km">${prog.used.toLocaleString()} ${prog.unit} since last service / ${prog.target.toLocaleString()} ${prog.unit}</div>
      <div class="gear-comp-bar-wrap">
        <div class="gear-comp-bar-track">
          <div class="gear-comp-bar-fill" style="width:${prog.pct}%;background:${color}"></div>
        </div>
        <span class="gear-comp-bar-label${lblClass}">${prog.overdue ? '&#9888; ' : prog.warn ? '&#9888; ' : ''}${prog.label}</span>
      </div>`;
  }

  return `
    <div class="${cardClass}">
      <div class="service-card-top">
        <div class="service-card-name">${bikeName}</div>
        <div class="gear-comp-actions">
          <button class="gear-icon-btn" title="Add service" onclick="openServiceModal(null,'${bikeId}')">${plusSvg}</button>
          <button class="gear-icon-btn" title="Edit last service" onclick="openServiceModal('${latest.id}')">${editSvg}</button>
          <button class="gear-icon-btn" title="Service history" onclick="openServiceHistory('${bikeId}')">${histSvg}</button>
        </div>
      </div>
      <div class="service-card-meta">
        <span>${dateStr}</span>
        ${shop.name ? `<span class="gear-comp-dot">&middot;</span><span>${shop.name}</span>` : ''}
        ${shop.phone ? `<span class="gear-comp-dot">&middot;</span><a href="tel:${phoneHref}" class="service-phone-link">${shop.phone}</a>` : ''}
      </div>
      <div class="service-card-work">${latest.workDone || ''}</div>
      ${latest.cost ? `<div class="service-card-cost">&euro;${Number(latest.cost).toFixed(2)}</div>` : ''}
      ${latest.notes ? `<div class="service-card-notes">${latest.notes}</div>` : ''}
      ${barHtml}
      ${sorted.length > 1 ? `<div style="font-size:var(--text-xs);color:var(--text-muted);margin-top:4px">${sorted.length - 1} previous service${sorted.length > 2 ? 's' : ''}</div>` : ''}
    </div>`;
}

